#![deny(unsafe_code)]

use std::fmt;

use rayon::prelude::*;
use wide::{f32x8, f64x4};

const BATCH_NORM_MIN_PAR_ROWS: usize = 8;

#[allow(unsafe_code)]
mod gemm {
    use rayon::prelude::*;

    // Above this many fused multiply-adds, split the GEMM across output row
    // blocks and run them on the rayon pool. `matrixmultiply` is single-threaded,
    // so a large solo matmul (the torch→ATen/MKL gap is multi-threaded BLAS) left
    // all but one core idle. Each block is an independent matrixmultiply call over
    // a contiguous row range of A and C: for a given output element the
    // k-accumulation order is fixed by the micro-kernel and does NOT depend on the
    // row count, so the parallel result is bit-for-bit identical to the single
    // call (proved by `gemm_row_split_matches_single_bit_exact`).
    // Row-block parallelism pays once a block carries enough work to dwarf the
    // rayon dispatch cost. The previous 1<<29 (~537M FMA) gate left medium GEMMs
    // single-threaded on multi-core hosts — notably the conv2d im2col matmul
    // (M=4096,K=576,N=64 ≈ 151M FMA) and a 512×512 matmul (134M) — so all but
    // one core sat idle. 1<<27 (~134M) brings both under the parallel path while
    // keeping genuinely small matmuls (≤256×256 ≈ 16.7M) serial. The split is
    // bit-for-bit identical to the single call regardless of block count
    // (proved by `gemm_row_split_matches_single_bit_exact`).
    const PAR_MIN_FLOPS: u128 = 1 << 27;
    // A TALL GEMM (many rows, modest total flops) can sit below PAR_MIN_FLOPS yet
    // still split into plenty of well-sized row blocks — e.g. an attention/linear
    // projection `[batch*S, embed] @ [embed, embed]` at large S (M = batch*S).
    // Parallelize it too: enough rows to fill the pool AND enough total work to
    // dwarf the dispatch. Thread-count-independent (so it isn't fragile at the
    // pool-size boundary) and OR'd with the flop gate, so it only ADDS parallelism
    // — no previously-parallel or previously-serial-small matmul changes.
    const TALL_MIN_ROWS: usize = 1024;
    const TALL_MIN_FLOPS: u128 = 1 << 25; // ~33.6M FMA total
    const MIN_BLOCK_ROWS: usize = 8;
    // f32 is half the bytes/flop of f64, so it turns compute-bound at a smaller K:
    // the 2-D tile's bandwidth saving then no longer offsets its smaller per-call
    // micro-kernel tiles, and large-K square sgemm regresses (measured: m2048 k2048
    // n2048 sgemm 0.81x). Above this K, keep the 1-D row split. K <= 1024 covers the
    // measured wins (sgemm 1.10-1.45x, sgemm_bt 1.02-1.25x). frankentorch-kgs4.48.
    const F32_2D_MAX_K: usize = 1024;

    fn should_parallelize(m: usize, k: usize, n: usize) -> bool {
        let flops = (m as u128) * (k as u128) * (n as u128);
        rayon::current_num_threads() > 1
            && m > MIN_BLOCK_ROWS
            && (flops >= PAR_MIN_FLOPS || (m >= TALL_MIN_ROWS && flops >= TALL_MIN_FLOPS))
    }

    fn block_rows(m: usize) -> usize {
        let threads = rayon::current_num_threads().max(1);
        m.div_ceil(threads).max(MIN_BLOCK_ROWS)
    }

    pub fn dgemm(m: usize, k: usize, n: usize, a: &[f64], b: &[f64], c: &mut [f64]) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..m * k];
        let b = &b[..k * n];
        let c = &mut c[..m * n];
        // Column path takes precedence for WIDE matmuls (n >> m): row-splitting
        // a small-M GEMM yields only ~m/MIN_BLOCK_ROWS blocks, while the column
        // path scales with N. (should_parallelize_cols already requires n > 4*m,
        // so non-wide matmuls are unaffected and keep the row split.)
        if should_parallelize_cols(m, k, n) {
            dgemm_col_parallel(m, k, n, a, b, c);
        } else if should_parallelize(m, k, n) {
            if n >= 2 * MIN_BLOCK_COLS {
                // Square/wide-enough: 2-D tiling avoids the row-split's full-B
                // re-streaming per thread (memory-bandwidth bound).
                dgemm_2d_parallel(m, k, n, a, b, c);
            } else {
                // Tall-skinny (small n): keep the 1-D row split — too few columns
                // to tile, and B is already small.
                let br = block_rows(m);
                c.par_chunks_mut(br * n)
                    .zip(a.par_chunks(br * k))
                    .for_each(|(c_blk, a_blk)| {
                        dgemm_block(c_blk.len() / n, k, n, a_blk, b, c_blk);
                    });
            }
        } else {
            dgemm_block(m, k, n, a, b, c);
        }
    }

    pub fn dgemm_scaled(
        m: usize,
        k: usize,
        n: usize,
        alpha: f64,
        a: &[f64],
        b: &[f64],
        c: &mut [f64],
    ) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..m * k];
        let b = &b[..k * n];
        let c = &mut c[..m * n];
        if should_parallelize_cols(m, k, n) {
            dgemm_col_parallel_scaled(m, k, n, alpha, a, b, c);
        } else if should_parallelize(m, k, n) {
            if n >= 2 * MIN_BLOCK_COLS {
                dgemm_2d_parallel_scaled(m, k, n, alpha, a, b, c);
            } else {
                let br = block_rows(m);
                c.par_chunks_mut(br * n)
                    .zip(a.par_chunks(br * k))
                    .for_each(|(c_blk, a_blk)| {
                        dgemm_block_scaled(c_blk.len() / n, k, n, alpha, a_blk, b, c_blk);
                    });
            }
        } else {
            dgemm_block_scaled(m, k, n, alpha, a, b, c);
        }
    }

    // Column (N) parallelism for SMALL-m, LARGE-n matmuls that the row-split
    // misses — e.g. a linear layer `[batch, in] @ [in, out]^T` with batch << out:
    // there M is too small to row-split, so the whole GEMM ran serial. Each
    // n-block's K-accumulation is identical to the single call (matrixmultiply's
    // micro-kernel order is independent of the N tiling), so the result is
    // BIT-FOR-BIT identical to dgemm_block.
    const PAR_MIN_FLOPS_COLS: u128 = 1 << 24; // ~16.8M FMA
    const MIN_BLOCK_COLS: usize = 128;

    fn should_parallelize_cols(m: usize, k: usize, n: usize) -> bool {
        rayon::current_num_threads() > 1
            && n >= 4 * MIN_BLOCK_COLS
            && n > 4 * m
            && (m as u128) * (k as u128) * (n as u128) >= PAR_MIN_FLOPS_COLS
    }

    fn block_cols(n: usize) -> usize {
        let threads = rayon::current_num_threads().max(1);
        n.div_ceil(threads).max(MIN_BLOCK_COLS)
    }

    /// `C[m,n] = A[m,k] @ B^T` where `B` is row-major `[n, k]` (e.g. a Linear
    /// layer's weight `[out, in]`). Reads B through matrixmultiply's strides
    /// (`rsb=1, csb=k`) so the transpose is NEVER materialised — eliminating the
    /// cache-unfriendly 8MB transposed copy that `x @ weight.t()` otherwise pays.
    /// Bit-for-bit identical to materialise-transpose-then-dgemm (same dims => same
    /// K-accumulation; B's values are read identically, only via strides). Uses
    /// the same column/row/serial split as `dgemm`.
    pub fn dgemm_bt(m: usize, k: usize, n: usize, a: &[f64], b: &[f64], c: &mut [f64]) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..m * k];
        let b = &b[..n * k];
        let c = &mut c[..m * n];
        if should_parallelize_cols(m, k, n) {
            // Split N (= B's rows), direct-write. Block [n0,n0+bw) reads the
            // contiguous B rows b[n0*k ..] (B^T via rsb=1,csb=k) and writes the
            // disjoint output column window straight into C via cp.0.add(n0)
            // (rsc=n,csc=1) — no owned buffer, no serial scatter. K not split →
            // bit-for-bit equal to dgemm_bt_block. frankentorch-kgs4.49.
            let nb = block_cols(n);
            let cp = TilePtr(c.as_mut_ptr());
            (0..n.div_ceil(nb)).into_par_iter().for_each(|blk| {
                let cp = &cp;
                let n0 = blk * nb;
                let bw = (n0 + nb).min(n) - n0;
                // SAFETY: a is m*k; b[n0*k..] holds bw rows of k; output window
                // [n0,n0+bw) is disjoint across blocks (last elem (m-1)*n+n0+bw-1 <= m*n-1).
                unsafe {
                    dgemm_mm(
                        m,
                        k,
                        bw,
                        1.0,
                        a.as_ptr(),
                        k as isize,
                        1,
                        b.as_ptr().add(n0 * k),
                        1,
                        k as isize,
                        0.0,
                        cp.0.add(n0),
                        n as isize,
                        1,
                    );
                }
            });
        } else if should_parallelize(m, k, n) {
            if n >= 2 * MIN_BLOCK_COLS {
                dgemm_bt_2d_parallel(m, k, n, a, b, c);
            } else {
                let br = block_rows(m);
                c.par_chunks_mut(br * n)
                    .zip(a.par_chunks(br * k))
                    .for_each(|(c_blk, a_blk)| {
                        dgemm_bt_block(c_blk.len() / n, k, n, a_blk, b, c_blk);
                    });
            }
        } else {
            dgemm_bt_block(m, k, n, a, b, c);
        }
    }

    /// `C[m,n] = A^T @ B` where `A` is row-major `[k, m]` and `B` is row-major
    /// `[k, n]`. This is the transposed-left analogue of [`dgemm_bt`]: it reads
    /// A through strides (`rsa=1, csa=m`) instead of materialising the `[m,k]`
    /// transpose first. For each output element the K traversal matches the
    /// materialise-transpose-then-`dgemm` path.
    pub fn dgemm_tb(m: usize, k: usize, n: usize, a: &[f64], b: &[f64], c: &mut [f64]) {
        dgemm_tb_scaled(m, k, n, 1.0, a, b, c);
    }

    pub fn dgemm_tb_scaled(
        m: usize,
        k: usize,
        n: usize,
        alpha: f64,
        a: &[f64],
        b: &[f64],
        c: &mut [f64],
    ) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..k * m];
        let b = &b[..k * n];
        let c = &mut c[..m * n];
        // SAFETY: A is [k,m] and read as A^T via strides; B and C are contiguous
        // row-major matrices with the exact dimensions passed to matrixmultiply.
        unsafe {
            dgemm_mm(
                m,
                k,
                n,
                alpha,
                a.as_ptr(),
                1,
                m as isize,
                b.as_ptr(),
                n as isize,
                1,
                0.0,
                c.as_mut_ptr(),
                n as isize,
                1,
            );
        }
    }

    /// Fused trailing-update: `C_sub -= A · B^T`, accumulating straight into a
    /// STRIDED submatrix of `c` (start `c_off`, row stride `ldc`) via matrixmultiply
    /// with alpha=-1, beta=1 — no temp product buffer and no scalar subtract pass.
    /// Parallelised over disjoint N column-blocks. Computes the FULL m×n rectangle
    /// (the caller zeroes any unused triangle afterwards). Used by blocked Cholesky.
    /// frankentorch-kgs4.61.
    #[allow(clippy::too_many_arguments)]
    pub fn dgemm_bt_sub_into(
        m: usize,
        k: usize,
        n: usize,
        a: &[f64],
        b: &[f64],
        c: &mut [f64],
        c_off: usize,
        ldc: usize,
    ) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..m * k];
        let b = &b[..n * k];
        let nb = block_cols(n);
        let cp = TilePtr(c.as_mut_ptr());
        (0..n.div_ceil(nb)).into_par_iter().for_each(|blk| {
            let cp = &cp;
            let n0 = blk * nb;
            let bw = (n0 + nb).min(n) - n0;
            // SAFETY: a is m*k; b[n0*k..] holds bw rows of k (B^T via rsb=1,csb=k).
            // Output window row i col (n0+j) -> c_off + i*ldc + n0 + j; column
            // windows are disjoint across blocks so writes never race. beta=1
            // accumulates into the existing C; alpha=-1 subtracts the product.
            unsafe {
                dgemm_mm(
                    m,
                    k,
                    bw,
                    -1.0,
                    a.as_ptr(),
                    k as isize,
                    1,
                    b.as_ptr().add(n0 * k),
                    1,
                    k as isize,
                    1.0,
                    cp.0.add(c_off + n0),
                    ldc as isize,
                    1,
                );
            }
        });
    }

    /// Fused trailing-update: `C_sub -= A · B` (B NOT transposed, contiguous
    /// [k×n]), accumulating straight into a STRIDED submatrix of `c` (start
    /// `c_off`, row stride `ldc`) via matrixmultiply with alpha=-1, beta=1 — no temp
    /// product buffer and no scalar subtract pass. Parallelised over disjoint N
    /// column-blocks. Used by the blocked LU trailing update (A22 -= L21·U12).
    /// frankentorch-kgs4.62.
    #[allow(clippy::too_many_arguments)]
    pub fn dgemm_sub_into(
        m: usize,
        k: usize,
        n: usize,
        a: &[f64],
        b: &[f64],
        c: &mut [f64],
        c_off: usize,
        ldc: usize,
    ) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..m * k];
        let b = &b[..k * n];
        let nb = block_cols(n);
        let cp = TilePtr(c.as_mut_ptr());
        (0..n.div_ceil(nb)).into_par_iter().for_each(|blk| {
            let cp = &cp;
            let n0 = blk * nb;
            let bw = (n0 + nb).min(n) - n0;
            // SAFETY: a is m*k; B is the contiguous [k×n] matrix, so its column
            // window [n0,n0+bw) is b.add(n0) read with rsb=n,csb=1. Output window
            // row i col (n0+j) -> c_off + i*ldc + n0 + j; column windows are disjoint
            // across blocks so writes never race. beta=1 accumulates, alpha=-1.
            unsafe {
                dgemm_mm(
                    m,
                    k,
                    bw,
                    -1.0,
                    a.as_ptr(),
                    k as isize,
                    1,
                    b.as_ptr().add(n0),
                    n as isize,
                    1,
                    1.0,
                    cp.0.add(c_off + n0),
                    ldc as isize,
                    1,
                );
            }
        });
    }

    /// f32 analogue of `dgemm_sub_into`: `C_sub -= A · B` (B contiguous [k×n]).
    /// frankentorch-kgs4.62.
    #[allow(clippy::too_many_arguments)]
    pub fn sgemm_sub_into(
        m: usize,
        k: usize,
        n: usize,
        a: &[f32],
        b: &[f32],
        c: &mut [f32],
        c_off: usize,
        ldc: usize,
    ) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..m * k];
        let b = &b[..k * n];
        let nb = block_cols(n);
        let cp = TilePtr(c.as_mut_ptr());
        (0..n.div_ceil(nb)).into_par_iter().for_each(|blk| {
            let cp = &cp;
            let n0 = blk * nb;
            let bw = (n0 + nb).min(n) - n0;
            // SAFETY: as dgemm_sub_into; disjoint column windows, beta=1, alpha=-1.
            unsafe {
                sgemm_mm(
                    m,
                    k,
                    bw,
                    -1.0,
                    a.as_ptr(),
                    k as isize,
                    1,
                    b.as_ptr().add(n0),
                    n as isize,
                    1,
                    1.0,
                    cp.0.add(c_off + n0),
                    ldc as isize,
                    1,
                );
            }
        });
    }

    /// f32 analogue of `dgemm_bt_sub_into`: `C_sub -= A · B^T` accumulated straight
    /// into a strided submatrix of `c` (start `c_off`, row stride `ldc`) via
    /// matrixmultiply with alpha=-1, beta=1. frankentorch-kgs4.61.
    #[allow(clippy::too_many_arguments)]
    pub fn sgemm_bt_sub_into(
        m: usize,
        k: usize,
        n: usize,
        a: &[f32],
        b: &[f32],
        c: &mut [f32],
        c_off: usize,
        ldc: usize,
    ) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..m * k];
        let b = &b[..n * k];
        let nb = block_cols(n);
        let cp = TilePtr(c.as_mut_ptr());
        (0..n.div_ceil(nb)).into_par_iter().for_each(|blk| {
            let cp = &cp;
            let n0 = blk * nb;
            let bw = (n0 + nb).min(n) - n0;
            // SAFETY: a is m*k; b[n0*k..] holds bw rows of k (B^T via rsb=1,csb=k).
            // Output column windows are disjoint across blocks; beta=1 accumulates,
            // alpha=-1 subtracts the product.
            unsafe {
                sgemm_mm(
                    m,
                    k,
                    bw,
                    -1.0,
                    a.as_ptr(),
                    k as isize,
                    1,
                    b.as_ptr().add(n0 * k),
                    1,
                    k as isize,
                    1.0,
                    cp.0.add(c_off + n0),
                    ldc as isize,
                    1,
                );
            }
        });
    }

    /// Blocked-LU panel triangular solve U12 = L11^{-1} · A12 IN PLACE within `lu`
    /// (row-major, dim n): L11 is the unit-lower block (rows/cols [k0,pe)), A12/U12
    /// occupy rows [k0,pe) cols [pe,n). Each trailing column is an independent
    /// forward substitution, so the work is parallelised over disjoint trailing
    /// column-blocks. The per-column update order is identical to the serial solve,
    /// so the result is BIT-FOR-BIT equal. frankentorch-kgs4.62.
    pub fn ltrsm_unit_lower_panel_f64(lu: &mut [f64], n: usize, k0: usize, pe: usize) {
        let tcols = n - pe;
        if tcols == 0 {
            return;
        }
        if tcols < 64 || rayon::current_num_threads() <= 1 {
            for i in k0..pe {
                for t in k0..i {
                    let lit = lu[i * n + t];
                    if lit != 0.0 {
                        for j in pe..n {
                            lu[i * n + j] -= lit * lu[t * n + j];
                        }
                    }
                }
            }
            return;
        }
        let base = TilePtr(lu.as_mut_ptr());
        let cb = tcols.div_ceil(rayon::current_num_threads() * 4).max(16);
        (0..tcols.div_ceil(cb)).into_par_iter().for_each(|blk| {
            let base = &base;
            let j0 = pe + blk * cb;
            let j1 = (j0 + cb).min(n);
            for i in k0..pe {
                for t in k0..i {
                    // SAFETY: i*n+t indexes L11 (read-only this step). j ∈ [j0,j1) is
                    // this block's EXCLUSIVE trailing-column window (rows t,i ∈ [k0,pe)),
                    // disjoint across blocks, so the writes never race.
                    let lit = unsafe { *base.0.add(i * n + t) };
                    if lit != 0.0 {
                        for j in j0..j1 {
                            unsafe {
                                let src = *base.0.add(t * n + j);
                                *base.0.add(i * n + j) -= lit * src;
                            }
                        }
                    }
                }
            }
        });
    }

    /// f32 analogue of `ltrsm_unit_lower_panel_f64`. frankentorch-kgs4.62.
    pub fn ltrsm_unit_lower_panel_f32(lu: &mut [f32], n: usize, k0: usize, pe: usize) {
        let tcols = n - pe;
        if tcols == 0 {
            return;
        }
        if tcols < 64 || rayon::current_num_threads() <= 1 {
            for i in k0..pe {
                for t in k0..i {
                    let lit = lu[i * n + t];
                    if lit != 0.0 {
                        for j in pe..n {
                            lu[i * n + j] -= lit * lu[t * n + j];
                        }
                    }
                }
            }
            return;
        }
        let base = TilePtr(lu.as_mut_ptr());
        let cb = tcols.div_ceil(rayon::current_num_threads() * 4).max(16);
        (0..tcols.div_ceil(cb)).into_par_iter().for_each(|blk| {
            let base = &base;
            let j0 = pe + blk * cb;
            let j1 = (j0 + cb).min(n);
            for i in k0..pe {
                for t in k0..i {
                    // SAFETY: as ltrsm_unit_lower_panel_f64 — disjoint column windows.
                    let lit = unsafe { *base.0.add(i * n + t) };
                    if lit != 0.0 {
                        for j in j0..j1 {
                            unsafe {
                                let src = *base.0.add(t * n + j);
                                *base.0.add(i * n + j) -= lit * src;
                            }
                        }
                    }
                }
            }
        });
    }

    /// Apply one Householder LEFT reflector to the trailing columns of a row-major
    /// `m_total × n` matrix `a` during Golub–Reinsch bidiagonalization: for each
    /// trailing column `j ∈ [l, n)`, `s = Σ_{k∈[i,m)} a[k][i]·a[k][j]`, then
    /// `a[k][j] += (s/h)·a[k][i]`. Each column `j` is INDEPENDENT (disjoint strided
    /// writes; column `i` is only read), so the work parallelises over columns with
    /// the per-column arithmetic order UNCHANGED → BIT-FOR-BIT identical to the
    /// serial sweep. frankentorch-kgs4.72.
    pub fn bidiag_col_reflector_apply_f64(
        a: &mut [f64],
        n: usize,
        i: usize,
        m: usize,
        l: usize,
        h: f64,
    ) {
        if l >= n {
            return;
        }
        let base = TilePtr(a.as_mut_ptr());
        (l..n).into_par_iter().for_each(|j| {
            let base = &base;
            // SAFETY: column j ∈ [l,n) is this iteration's EXCLUSIVE write set
            // (a[k*n+j], k∈[i,m)); column i (a[k*n+i]) is only read and never
            // written here, so cross-thread sharing of those reads is sound. All
            // indices k*n+{i,j} with k<m are within a (len ≥ m*n).
            unsafe {
                let mut s2 = 0.0;
                for k in i..m {
                    s2 += *base.0.add(k * n + i) * *base.0.add(k * n + j);
                }
                let f2 = s2 / h;
                for k in i..m {
                    let p = base.0.add(k * n + j);
                    *p += f2 * *base.0.add(k * n + i);
                }
            }
        });
    }

    /// SVD left-vector (U) back-transform column update (Golub–Reinsch dorgbr):
    /// for each column `j ∈ [l, n)`, `s = Σ_{k∈[l,m)} a[k][i]·a[k][j]`, then with
    /// `f = (s / a_ii)·g`, `a[k][j] += f·a[k][i]` for `k ∈ [i, m)`. Column-parallel;
    /// the per-column arithmetic (incl. the exact `(s/a_ii)*g` order) is UNCHANGED →
    /// BIT-FOR-BIT identical to the serial sweep. frankentorch-kgs4.72.
    #[allow(clippy::too_many_arguments)]
    pub fn svd_u_backtransform_f64(
        a: &mut [f64],
        n: usize,
        i: usize,
        l: usize,
        m: usize,
        a_ii: f64,
        g: f64,
    ) {
        if l >= n {
            return;
        }
        let base = TilePtr(a.as_mut_ptr());
        (l..n).into_par_iter().for_each(|j| {
            let base = &base;
            // SAFETY: column j ∈ [l,n) is this iteration's exclusive write set;
            // column i is read-only here. All k*n+{i,j}, k<m, are within a.
            unsafe {
                let mut s = 0.0;
                for k in l..m {
                    s += *base.0.add(k * n + i) * *base.0.add(k * n + j);
                }
                let f = (s / a_ii) * g;
                for k in i..m {
                    let p = base.0.add(k * n + j);
                    *p += f * *base.0.add(k * n + i);
                }
            }
        });
    }

    /// SVD right-vector (V) back-transform column update (Golub–Reinsch): for each
    /// column `j ∈ [l, n)`, `s = Σ_{k∈[l,n)} arow[k]·v[k][j]`, then
    /// `v[k][j] += s·v[k][i]` for `k ∈ [l, n)`, where `arow` is row `i` of the
    /// reduced matrix. Column-parallel, BIT-FOR-BIT identical to the serial sweep.
    /// frankentorch-kgs4.72.
    #[allow(clippy::needless_range_loop)] // k also indexes the raw v pointer
    pub fn svd_v_backtransform_f64(v: &mut [f64], arow: &[f64], n: usize, i: usize, l: usize) {
        if l >= n {
            return;
        }
        let base = TilePtr(v.as_mut_ptr());
        (l..n).into_par_iter().for_each(|j| {
            let base = &base;
            // SAFETY: column j ∈ [l,n) is this iteration's exclusive write set;
            // column i is read-only here; arow is a disjoint immutable slice.
            unsafe {
                let mut s = 0.0;
                for k in l..n {
                    s += arow[k] * *base.0.add(k * n + j);
                }
                for k in l..n {
                    let p = base.0.add(k * n + j);
                    *p += s * *base.0.add(k * n + i);
                }
            }
        });
    }

    fn dgemm_bt_block(m: usize, k: usize, n: usize, a: &[f64], b: &[f64], c: &mut [f64]) {
        // SAFETY: a is m*k, b is n*k (read as B^T via rsb=1,csb=k), c is m*n.
        unsafe {
            dgemm_mm(
                m,
                k,
                n,
                1.0,
                a.as_ptr(),
                k as isize,
                1,
                b.as_ptr(),
                1,
                k as isize,
                0.0,
                c.as_mut_ptr(),
                n as isize,
                1,
            );
        }
    }

    // Column (N) parallelism, direct-write: each thread computes the m×bw output for
    // its DISJOINT column window [n0,n0+bw) and writes it straight into C via
    // cp.0.add(n0) (rsc=n,csc=1) — no owned buffer and no serial O(m*n) scatter pass
    // (which did not parallelize and dominated wide small-K matmuls: measured up to
    // 1.89x on m256 k64 n16384). K is not split, so matrixmultiply's accumulation
    // order is unchanged and the result is BIT-FOR-BIT equal to the single
    // dgemm_block call. frankentorch-kgs4.49.
    fn dgemm_col_parallel(m: usize, k: usize, n: usize, a: &[f64], b: &[f64], c: &mut [f64]) {
        dgemm_col_parallel_scaled(m, k, n, 1.0, a, b, c);
    }

    fn dgemm_col_parallel_scaled(
        m: usize,
        k: usize,
        n: usize,
        alpha: f64,
        a: &[f64],
        b: &[f64],
        c: &mut [f64],
    ) {
        let nb = block_cols(n);
        let cp = TilePtr(c.as_mut_ptr());
        (0..n.div_ceil(nb)).into_par_iter().for_each(|blk| {
            let cp = &cp;
            let n0 = blk * nb;
            let bw = (n0 + nb).min(n) - n0;
            // SAFETY: a is m*k; B's strided column window b.add(n0) (rsb=n,csb=1, bw
            // cols, k rows) is in bounds. Output column window [n0,n0+bw) is disjoint
            // across blocks; cp.0.add(n0) (rsc=n,csc=1) writes the m×bw tile whose last
            // element (m-1)*n+n0+bw-1 <= m*n-1.
            unsafe {
                dgemm_mm(
                    m,
                    k,
                    bw,
                    alpha,
                    a.as_ptr(),
                    k as isize,
                    1,
                    b.as_ptr().add(n0),
                    n as isize,
                    1,
                    0.0,
                    cp.0.add(n0),
                    n as isize,
                    1,
                );
            }
        });
    }

    // 2-D (M×N) tiled parallelism. The 1-D row split makes EVERY thread stream the
    // full B from DRAM, so a square GEMM saturates memory bandwidth at ~3.5x even on
    // 16 cores. Tiling BOTH M and N into ~sqrt(threads) blocks each cuts total A+B
    // DRAM traffic from (T+1) units (row-split) to 2*sqrt(T), lifting the bandwidth
    // ceiling. Each output tile C[i0:i1, j0:j1] = A[i0:i1, :] @ B[:, j0:j1]; K is
    // NEVER split, so matrixmultiply's accumulation order is identical to the single
    // call and the result is BIT-FOR-BIT equal to the *_block call (the same
    // invariant the existing row/column splits rely on). Each tile writes its DISJOINT
    // rectangle of C directly (no owned buffer / scatter pass), so 2-D is never slower
    // than the row split for f64. Wired for f64 dgemm (B is [k,n]) and dgemm_bt (B is
    // [n,k], read as B^T, the Linear-layer path); f32 is deferred (more compute-bound,
    // needs a bandwidth gate — kgs4.48). frankentorch-kgs4.45 + kgs4.47.

    // A raw output pointer made Send+Sync so each parallel tile can write its
    // DISJOINT rectangle of C directly (no owned buffer, no scatter pass). Sound
    // because the tile grid is non-overlapping (see tile_blocks).
    struct TilePtr<T>(*mut T);
    // SAFETY: the pointer is only dereferenced for writes into provably-disjoint
    // rectangles of the same allocation; no two tiles touch the same element.
    unsafe impl<T> Send for TilePtr<T> {}
    unsafe impl<T> Sync for TilePtr<T> {}

    // Shared M×N tile grid: ~sqrt(threads) blocks per axis (minimises B+A traffic
    // for square shapes), clamped to the GEMM block-size floors. Returns the block
    // extents and the list of (i0,j0) tile origins — disjoint rectangles tiling C.
    fn tile_shape(m: usize, n: usize) -> (usize, usize) {
        let threads = rayon::current_num_threads().max(1);
        let p = (threads as f64).sqrt().floor().max(1.0) as usize; // M-blocks
        let q = threads.div_ceil(p); // N-blocks
        let mb = m.div_ceil(p).max(MIN_BLOCK_ROWS);
        let nb = n.div_ceil(q).max(MIN_BLOCK_COLS);
        (mb, nb)
    }

    fn tile_blocks(m: usize, n: usize) -> (usize, usize, Vec<(usize, usize)>) {
        let (mb, nb) = tile_shape(m, n);
        let mut tiles: Vec<(usize, usize)> = Vec::new();
        let mut i0 = 0;
        while i0 < m {
            let mut j0 = 0;
            while j0 < n {
                tiles.push((i0, j0));
                j0 += nb;
            }
            i0 += mb;
        }
        (mb, nb, tiles)
    }

    fn dgemm_2d_parallel(m: usize, k: usize, n: usize, a: &[f64], b: &[f64], c: &mut [f64]) {
        dgemm_2d_parallel_scaled(m, k, n, 1.0, a, b, c);
    }

    fn dgemm_2d_parallel_scaled(
        m: usize,
        k: usize,
        n: usize,
        alpha: f64,
        a: &[f64],
        b: &[f64],
        c: &mut [f64],
    ) {
        let (mb, nb) = tile_shape(m, n);
        let cp = TilePtr(c.as_mut_ptr());
        (0..n.div_ceil(nb)).into_par_iter().for_each(|j_blk| {
            let cp = &cp;
            let j0 = j_blk * nb;
            let bj = (j0 + nb).min(n) - j0;
            let mut b_panel = vec![0.0_f64; k * bj];
            for kk in 0..k {
                let src = &b[kk * n + j0..kk * n + j0 + bj];
                let dst = &mut b_panel[kk * bj..(kk + 1) * bj];
                dst.copy_from_slice(src);
            }
            (0..m.div_ceil(mb)).into_par_iter().for_each(|i_blk| {
                let i0 = i_blk * mb;
                let bi = (i0 + mb).min(m) - i0;
                // SAFETY: A rows [i0,i0+bi) = a[i0*k..] (rsa=k,csa=1). The packed
                // B panel is the same logical B[:,j0:j0+bj] values in row-major
                // [k,bj] order, copied before the tile calls. Output is the DISJOINT
                // tile C[i0:i1, j0:j1] written via cp.0.add(i0*n+j0). K is not tiled.
                unsafe {
                    dgemm_mm(
                        bi,
                        k,
                        bj,
                        alpha,
                        a.as_ptr().add(i0 * k),
                        k as isize,
                        1,
                        b_panel.as_ptr(),
                        bj as isize,
                        1,
                        0.0,
                        cp.0.add(i0 * n + j0),
                        n as isize,
                        1,
                    );
                }
            });
        });
    }

    fn dgemm_bt_2d_parallel(m: usize, k: usize, n: usize, a: &[f64], b: &[f64], c: &mut [f64]) {
        let (mb, nb, tiles) = tile_blocks(m, n);
        let cp = TilePtr(c.as_mut_ptr());
        tiles.into_par_iter().for_each(|(i0, j0)| {
            let cp = &cp;
            let bi = (i0 + mb).min(m) - i0;
            let bj = (j0 + nb).min(n) - j0;
            // SAFETY: B is [n,k]; output cols [j0,j0+bj) are B ROWS [j0,j0+bj) =
            // b[j0*k..] read as B^T via rsb=1,csb=k. A rows a[i0*k..] (rsa=k). Output
            // is the disjoint tile via cp.0.add(i0*n+j0) (rsc=n). K not tiled →
            // bit-for-bit equal to dgemm_bt_block.
            unsafe {
                dgemm_mm(
                    bi,
                    k,
                    bj,
                    1.0,
                    a.as_ptr().add(i0 * k),
                    k as isize,
                    1,
                    b.as_ptr().add(j0 * k),
                    1,
                    k as isize,
                    0.0,
                    cp.0.add(i0 * n + j0),
                    n as isize,
                    1,
                );
            }
        });
    }

    fn sgemm_2d_parallel(m: usize, k: usize, n: usize, a: &[f32], b: &[f32], c: &mut [f32]) {
        sgemm_2d_parallel_scaled(m, k, n, 1.0, a, b, c);
    }

    fn sgemm_2d_parallel_scaled(
        m: usize,
        k: usize,
        n: usize,
        alpha: f32,
        a: &[f32],
        b: &[f32],
        c: &mut [f32],
    ) {
        let (mb, nb, tiles) = tile_blocks(m, n);
        let cp = TilePtr(c.as_mut_ptr());
        tiles.into_par_iter().for_each(|(i0, j0)| {
            let cp = &cp;
            let bi = (i0 + mb).min(m) - i0;
            let bj = (j0 + nb).min(n) - j0;
            // SAFETY: f32 mirror of dgemm_2d_parallel (B is [k,n]); disjoint tile.
            unsafe {
                sgemm_mm(
                    bi,
                    k,
                    bj,
                    alpha,
                    a.as_ptr().add(i0 * k),
                    k as isize,
                    1,
                    b.as_ptr().add(j0),
                    n as isize,
                    1,
                    0.0,
                    cp.0.add(i0 * n + j0),
                    n as isize,
                    1,
                );
            }
        });
    }

    fn sgemm_bt_2d_parallel(m: usize, k: usize, n: usize, a: &[f32], b: &[f32], c: &mut [f32]) {
        let (mb, nb, tiles) = tile_blocks(m, n);
        let cp = TilePtr(c.as_mut_ptr());
        tiles.into_par_iter().for_each(|(i0, j0)| {
            let cp = &cp;
            let bi = (i0 + mb).min(m) - i0;
            let bj = (j0 + nb).min(n) - j0;
            // SAFETY: f32 mirror of dgemm_bt_2d_parallel (B is [n,k], B^T read).
            unsafe {
                sgemm_mm(
                    bi,
                    k,
                    bj,
                    1.0,
                    a.as_ptr().add(i0 * k),
                    k as isize,
                    1,
                    b.as_ptr().add(j0 * k),
                    1,
                    k as isize,
                    0.0,
                    cp.0.add(i0 * n + j0),
                    n as isize,
                    1,
                );
            }
        });
    }

    #[cfg(test)]
    mod tile_iso_tests {
        use super::{
            dgemm_2d_parallel, dgemm_block, dgemm_bt_2d_parallel, dgemm_bt_block,
            dgemm_col_parallel, sgemm_2d_parallel, sgemm_block, sgemm_bt_2d_parallel,
            sgemm_bt_block, sgemm_col_parallel,
        };

        const SHAPES: &[(usize, usize, usize)] = &[
            (512, 512, 512),
            (256, 384, 512),
            (640, 128, 384),
            (300, 257, 259),
            (8, 1024, 1024),
        ];

        // Both f64 2-D tile paths must be BIT-FOR-BIT identical to a single serial
        // *_block call (K is never split, so matrixmultiply's accumulation order is
        // unchanged). Covers normal (B is [k,n]) and transposed-B (B is [n,k]).
        #[test]
        fn gemm_2d_parallel_is_bit_exact_vs_serial() {
            for &(m, k, n) in SHAPES {
                let a: Vec<f64> = (0..m * k).map(|i| (i as f64 * 0.001).sin()).collect();
                // Same length (k*n) for the normal [k,n] and transposed [n,k] layouts.
                let b: Vec<f64> = (0..k * n).map(|i| (i as f64 * 0.0017).cos()).collect();

                let mut s = vec![0.0_f64; m * n];
                let mut t = vec![0.0_f64; m * n];
                dgemm_block(m, k, n, &a, &b, &mut s);
                dgemm_2d_parallel(m, k, n, &a, &b, &mut t);
                assert!(
                    s.iter().zip(&t).all(|(x, y)| x.to_bits() == y.to_bits()),
                    "dgemm {m}x{k}x{n}"
                );

                dgemm_bt_block(m, k, n, &a, &b, &mut s);
                dgemm_bt_2d_parallel(m, k, n, &a, &b, &mut t);
                assert!(
                    s.iter().zip(&t).all(|(x, y)| x.to_bits() == y.to_bits()),
                    "dgemm_bt {m}x{k}x{n}"
                );

                let a32: Vec<f32> = a.iter().map(|&x| x as f32).collect();
                let b32: Vec<f32> = b.iter().map(|&x| x as f32).collect();
                let mut s3 = vec![0.0_f32; m * n];
                let mut t3 = vec![0.0_f32; m * n];
                sgemm_block(m, k, n, &a32, &b32, &mut s3);
                sgemm_2d_parallel(m, k, n, &a32, &b32, &mut t3);
                assert!(
                    s3.iter().zip(&t3).all(|(x, y)| x.to_bits() == y.to_bits()),
                    "sgemm {m}x{k}x{n}"
                );

                sgemm_bt_block(m, k, n, &a32, &b32, &mut s3);
                sgemm_bt_2d_parallel(m, k, n, &a32, &b32, &mut t3);
                assert!(
                    s3.iter().zip(&t3).all(|(x, y)| x.to_bits() == y.to_bits()),
                    "sgemm_bt {m}x{k}x{n}"
                );
            }
        }

        // The direct-write column-parallel path (wide matmuls, B is [k,n]) must be
        // BIT-FOR-BIT identical to the single serial *_block call. frankentorch-kgs4.49.
        #[test]
        fn gemm_col_parallel_is_bit_exact_vs_serial() {
            for &(m, k, n) in &[
                (64usize, 256usize, 2048usize),
                (8, 512, 4096),
                (256, 64, 2048),
            ] {
                let a: Vec<f64> = (0..m * k).map(|i| (i as f64 * 0.001).sin()).collect();
                let b: Vec<f64> = (0..k * n).map(|i| (i as f64 * 0.0017).cos()).collect();
                let mut s = vec![0.0_f64; m * n];
                let mut t = vec![0.0_f64; m * n];
                dgemm_block(m, k, n, &a, &b, &mut s);
                dgemm_col_parallel(m, k, n, &a, &b, &mut t);
                assert!(
                    s.iter().zip(&t).all(|(x, y)| x.to_bits() == y.to_bits()),
                    "dgemm_col {m}x{k}x{n}"
                );
                let a32: Vec<f32> = a.iter().map(|&x| x as f32).collect();
                let b32: Vec<f32> = b.iter().map(|&x| x as f32).collect();
                let mut s3 = vec![0.0_f32; m * n];
                let mut t3 = vec![0.0_f32; m * n];
                sgemm_block(m, k, n, &a32, &b32, &mut s3);
                sgemm_col_parallel(m, k, n, &a32, &b32, &mut t3);
                assert!(
                    s3.iter().zip(&t3).all(|(x, y)| x.to_bits() == y.to_bits()),
                    "sgemm_col {m}x{k}x{n}"
                );
            }
        }
    }

    pub fn dgemm_block(m: usize, k: usize, n: usize, a: &[f64], b: &[f64], c: &mut [f64]) {
        dgemm_block_scaled(m, k, n, 1.0, a, b, c);
    }

    pub fn dgemm_block_scaled(
        m: usize,
        k: usize,
        n: usize,
        alpha: f64,
        a: &[f64],
        b: &[f64],
        c: &mut [f64],
    ) {
        // SAFETY: matrixmultiply::dgemm requires valid pointers and correct dimensions.
        // a.len() == m*k, b.len() == k*n, c.len() == m*n (sliced exactly by `dgemm`).
        // Row-major layout: row stride = inner dimension, column stride = 1.
        unsafe {
            dgemm_mm(
                m,
                k,
                n,
                alpha,
                a.as_ptr(),
                k as isize,
                1,
                b.as_ptr(),
                n as isize,
                1,
                0.0,
                c.as_mut_ptr(),
                n as isize,
                1,
            );
        }
    }

    pub fn sgemm(m: usize, k: usize, n: usize, a: &[f32], b: &[f32], c: &mut [f32]) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..m * k];
        let b = &b[..k * n];
        let c = &mut c[..m * n];
        // Same structure as dgemm: column path for WIDE matmuls (n >> m), else
        // row split (square/tall via should_parallelize), else serial.
        if should_parallelize_cols(m, k, n) {
            sgemm_col_parallel(m, k, n, a, b, c);
        } else if should_parallelize(m, k, n) {
            if n >= 2 * MIN_BLOCK_COLS && k <= F32_2D_MAX_K {
                // Bandwidth-bound regime: 2-D tiling cuts the row-split's full-B
                // re-streaming per thread (direct-write, bit-exact). K-gated so the
                // compute-bound large-K case keeps the row split.
                sgemm_2d_parallel(m, k, n, a, b, c);
            } else {
                let br = block_rows(m);
                c.par_chunks_mut(br * n)
                    .zip(a.par_chunks(br * k))
                    .for_each(|(c_blk, a_blk)| {
                        sgemm_block(c_blk.len() / n, k, n, a_blk, b, c_blk);
                    });
            }
        } else {
            sgemm_block(m, k, n, a, b, c);
        }
    }

    pub fn sgemm_scaled(
        m: usize,
        k: usize,
        n: usize,
        alpha: f32,
        a: &[f32],
        b: &[f32],
        c: &mut [f32],
    ) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..m * k];
        let b = &b[..k * n];
        let c = &mut c[..m * n];
        if should_parallelize_cols(m, k, n) {
            sgemm_col_parallel_scaled(m, k, n, alpha, a, b, c);
        } else if should_parallelize(m, k, n) {
            if n >= 2 * MIN_BLOCK_COLS && k <= F32_2D_MAX_K {
                sgemm_2d_parallel_scaled(m, k, n, alpha, a, b, c);
            } else {
                let br = block_rows(m);
                c.par_chunks_mut(br * n)
                    .zip(a.par_chunks(br * k))
                    .for_each(|(c_blk, a_blk)| {
                        sgemm_block_scaled(c_blk.len() / n, k, n, alpha, a_blk, b, c_blk);
                    });
            }
        } else {
            sgemm_block_scaled(m, k, n, alpha, a, b, c);
        }
    }

    // f32 mirror of dgemm_col_parallel: direct-write disjoint column windows.
    fn sgemm_col_parallel(m: usize, k: usize, n: usize, a: &[f32], b: &[f32], c: &mut [f32]) {
        sgemm_col_parallel_scaled(m, k, n, 1.0, a, b, c);
    }

    fn sgemm_col_parallel_scaled(
        m: usize,
        k: usize,
        n: usize,
        alpha: f32,
        a: &[f32],
        b: &[f32],
        c: &mut [f32],
    ) {
        let nb = block_cols(n);
        let cp = TilePtr(c.as_mut_ptr());
        (0..n.div_ceil(nb)).into_par_iter().for_each(|blk| {
            let cp = &cp;
            let n0 = blk * nb;
            let bw = (n0 + nb).min(n) - n0;
            // SAFETY: see dgemm_col_parallel; disjoint output column window [n0,n0+bw).
            unsafe {
                sgemm_mm(
                    m,
                    k,
                    bw,
                    alpha,
                    a.as_ptr(),
                    k as isize,
                    1,
                    b.as_ptr().add(n0),
                    n as isize,
                    1,
                    0.0,
                    cp.0.add(n0),
                    n as isize,
                    1,
                );
            }
        });
    }

    /// f32 mirror of `dgemm_bt`: `C[m,n] = A[m,k] @ B^T` where `B` is `[n,k]`.
    pub fn sgemm_bt(m: usize, k: usize, n: usize, a: &[f32], b: &[f32], c: &mut [f32]) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..m * k];
        let b = &b[..n * k];
        let c = &mut c[..m * n];
        if should_parallelize_cols(m, k, n) {
            // f32 mirror of dgemm_bt col path: direct-write disjoint column windows.
            let nb = block_cols(n);
            let cp = TilePtr(c.as_mut_ptr());
            (0..n.div_ceil(nb)).into_par_iter().for_each(|blk| {
                let cp = &cp;
                let n0 = blk * nb;
                let bw = (n0 + nb).min(n) - n0;
                // SAFETY: a is m*k; b[n0*k..] holds bw rows of k; disjoint output
                // column window [n0,n0+bw) written via cp.0.add(n0) (rsc=n,csc=1).
                unsafe {
                    sgemm_mm(
                        m,
                        k,
                        bw,
                        1.0,
                        a.as_ptr(),
                        k as isize,
                        1,
                        b.as_ptr().add(n0 * k),
                        1,
                        k as isize,
                        0.0,
                        cp.0.add(n0),
                        n as isize,
                        1,
                    );
                }
            });
        } else if should_parallelize(m, k, n) {
            if n >= 2 * MIN_BLOCK_COLS && k <= F32_2D_MAX_K {
                // See sgemm: K-gated 2-D tiling for the bandwidth-bound regime.
                sgemm_bt_2d_parallel(m, k, n, a, b, c);
            } else {
                let br = block_rows(m);
                c.par_chunks_mut(br * n)
                    .zip(a.par_chunks(br * k))
                    .for_each(|(c_blk, a_blk)| {
                        sgemm_bt_block(c_blk.len() / n, k, n, a_blk, b, c_blk);
                    });
            }
        } else {
            sgemm_bt_block(m, k, n, a, b, c);
        }
    }

    /// f32 mirror of [`dgemm_tb`]: `C[m,n] = A^T @ B` with A stored as `[k,m]`.
    pub fn sgemm_tb(m: usize, k: usize, n: usize, a: &[f32], b: &[f32], c: &mut [f32]) {
        sgemm_tb_scaled(m, k, n, 1.0, a, b, c);
    }

    pub fn sgemm_tb_scaled(
        m: usize,
        k: usize,
        n: usize,
        alpha: f32,
        a: &[f32],
        b: &[f32],
        c: &mut [f32],
    ) {
        if m == 0 || n == 0 {
            return;
        }
        let a = &a[..k * m];
        let b = &b[..k * n];
        let c = &mut c[..m * n];
        // SAFETY: see dgemm_tb; f32 version uses the same strided-A contract.
        unsafe {
            sgemm_mm(
                m,
                k,
                n,
                alpha,
                a.as_ptr(),
                1,
                m as isize,
                b.as_ptr(),
                n as isize,
                1,
                0.0,
                c.as_mut_ptr(),
                n as isize,
                1,
            );
        }
    }

    fn sgemm_bt_block(m: usize, k: usize, n: usize, a: &[f32], b: &[f32], c: &mut [f32]) {
        // SAFETY: a is m*k, b is n*k (read as B^T via rsb=1,csb=k), c is m*n.
        unsafe {
            sgemm_mm(
                m,
                k,
                n,
                1.0,
                a.as_ptr(),
                k as isize,
                1,
                b.as_ptr(),
                1,
                k as isize,
                0.0,
                c.as_mut_ptr(),
                n as isize,
                1,
            );
        }
    }

    pub fn sgemm_block(m: usize, k: usize, n: usize, a: &[f32], b: &[f32], c: &mut [f32]) {
        sgemm_block_scaled(m, k, n, 1.0, a, b, c);
    }

    pub fn sgemm_block_scaled(
        m: usize,
        k: usize,
        n: usize,
        alpha: f32,
        a: &[f32],
        b: &[f32],
        c: &mut [f32],
    ) {
        // SAFETY: see `dgemm_block`; slices are sized exactly by `sgemm`.
        unsafe {
            sgemm_mm(
                m,
                k,
                n,
                alpha,
                a.as_ptr(),
                k as isize,
                1,
                b.as_ptr(),
                n as isize,
                1,
                0.0,
                c.as_mut_ptr(),
                n as isize,
                1,
            );
        }
    }

    /// Read the x86 MXCSR control/status register (SSE rounding mode + FTZ/DAZ
    /// denormal-flush + sticky exception flags). Diagnostic for
    /// frankentorch-ft-api-fullsuite-flake: a non-default MXCSR (default 0x1F80)
    /// changes denormal handling / rounding and would make GEMM-heavy kernels
    /// drift bit-for-bit. Non-x86 targets report the default.
    #[must_use]
    pub fn read_mxcsr() -> u32 {
        #[cfg(target_arch = "x86_64")]
        {
            #[allow(deprecated)]
            unsafe {
                core::arch::x86_64::_mm_getcsr()
            }
        }
        #[cfg(not(target_arch = "x86_64"))]
        {
            0x1f80
        }
    }

    /// Restore MXCSR to its default (0x1F80): round-to-nearest, no FTZ/DAZ, all
    /// exception masks set, no sticky flags. No-op off x86_64.
    pub fn set_mxcsr_default() {
        #[cfg(target_arch = "x86_64")]
        {
            #[allow(deprecated)]
            unsafe {
                core::arch::x86_64::_mm_setcsr(0x1f80);
            }
        }
    }

    /// `matrixmultiply::dgemm` that restores MXCSR afterwards.
    ///
    /// `matrixmultiply`'s SIMD micro-kernel sets the x86 FTZ/DAZ denormal-flush
    /// bits in MXCSR and does NOT restore them, so the flush-to-zero state LEAKS
    /// into every later floating-point op on the same thread (and, since libtest
    /// reuses threads, into later tests). That made GEMM-heavy golden digests
    /// drift bit-for-bit depending on whether a GEMM had already run — the
    /// frankentorch-ft-api-fullsuite-flake. Restoring the default immediately
    /// after the call leaves the matmul result itself untouched (the flush only
    /// applied during matrixmultiply's own execution) while stopping the leak.
    ///
    /// # Safety
    /// Same contract as `matrixmultiply::dgemm`: pointers valid for the given
    /// dims/strides; `c` writable.
    #[inline]
    #[allow(clippy::too_many_arguments)]
    unsafe fn dgemm_mm(
        m: usize,
        k: usize,
        n: usize,
        alpha: f64,
        a: *const f64,
        rsa: isize,
        csa: isize,
        b: *const f64,
        rsb: isize,
        csb: isize,
        beta: f64,
        c: *mut f64,
        rsc: isize,
        csc: isize,
    ) {
        unsafe {
            matrixmultiply::dgemm(m, k, n, alpha, a, rsa, csa, b, rsb, csb, beta, c, rsc, csc);
        }
        set_mxcsr_default();
    }

    /// `matrixmultiply::sgemm` that restores MXCSR afterwards. See [`dgemm_mm`].
    ///
    /// # Safety
    /// Same contract as `matrixmultiply::sgemm`.
    #[inline]
    #[allow(clippy::too_many_arguments)]
    unsafe fn sgemm_mm(
        m: usize,
        k: usize,
        n: usize,
        alpha: f32,
        a: *const f32,
        rsa: isize,
        csa: isize,
        b: *const f32,
        rsb: isize,
        csb: isize,
        beta: f32,
        c: *mut f32,
        rsc: isize,
        csc: isize,
    ) {
        unsafe {
            matrixmultiply::sgemm(m, k, n, alpha, a, rsa, csa, b, rsb, csb, beta, c, rsc, csc);
        }
        set_mxcsr_default();
    }
}

/// Read the x86 MXCSR register (SSE rounding + FTZ/DAZ + sticky flags); 0x1F80
/// is the default. Diagnostic for the full-suite determinism flake.
#[must_use]
pub fn read_mxcsr() -> u32 {
    gemm::read_mxcsr()
}

/// Restore MXCSR to its 0x1F80 default. See [`read_mxcsr`].
pub fn set_mxcsr_default() {
    gemm::set_mxcsr_default();
}

use ft_core::{
    Complex128, DType, Device, ScalarTensor, SparseCOOTensor, SparseTensorError, TensorCompatError,
    TensorMeta, ensure_compatible,
};

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum KernelError {
    Incompatible(TensorCompatError),
    ShapeMismatch {
        lhs: Vec<usize>,
        rhs: Vec<usize>,
    },
    UnsupportedLayout {
        side: &'static str,
    },
    StorageSpanOverflow {
        side: &'static str,
        storage_offset: usize,
        numel: usize,
    },
    InsufficientStorage {
        side: &'static str,
        needed: usize,
        available: usize,
    },
    InvalidDimension {
        dim: usize,
        ndim: usize,
    },
    ShapeOverflow {
        context: &'static str,
    },
    SingularMatrix {
        size: usize,
    },
    NotPositiveDefinite,
    /// A reduction that has no identity element (argmax/argmin/max/min)
    /// was applied along a dimension of size zero. PyTorch raises a
    /// runtime error here rather than returning a sentinel.
    EmptyReductionDim {
        dim: usize,
    },
}

impl fmt::Display for KernelError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::Incompatible(error) => write!(f, "incompatible tensors: {error}"),
            Self::ShapeMismatch { lhs, rhs } => {
                write!(f, "shape mismatch: lhs={lhs:?}, rhs={rhs:?}")
            }
            Self::UnsupportedLayout { side } => {
                write!(f, "unsupported non-contiguous layout on {side}")
            }
            Self::StorageSpanOverflow {
                side,
                storage_offset,
                numel,
            } => write!(
                f,
                "storage span overflow on {side}: storage_offset={storage_offset}, numel={numel}"
            ),
            Self::InsufficientStorage {
                side,
                needed,
                available,
            } => write!(
                f,
                "insufficient storage on {side}: needed={needed}, available={available}"
            ),
            Self::InvalidDimension { dim, ndim } => write!(
                f,
                "invalid reduction dimension {dim} for tensor with {ndim} dimensions"
            ),
            Self::ShapeOverflow { context } => {
                write!(f, "shape arithmetic overflow: {context}")
            }
            Self::SingularMatrix { size } => {
                write!(f, "singular matrix: size={size}x{size}")
            }
            Self::NotPositiveDefinite => {
                write!(f, "matrix is not positive definite")
            }
            Self::EmptyReductionDim { dim } => write!(
                f,
                "cannot reduce (argmax/argmin/max/min) over dimension {dim} of size zero"
            ),
        }
    }
}

impl std::error::Error for KernelError {}

impl From<TensorCompatError> for KernelError {
    fn from(value: TensorCompatError) -> Self {
        Self::Incompatible(value)
    }
}

pub fn neg_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(-input.value())
}

pub fn abs_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().abs())
}

pub fn exp_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().exp())
}

pub fn log_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().ln())
}

pub fn relu_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(if input.value() > 0.0 {
        input.value()
    } else {
        0.0
    })
}

pub fn sigmoid_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(1.0 / (1.0 + (-input.value()).exp()))
}

pub fn tanh_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().tanh())
}

pub fn sqrt_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().sqrt())
}

pub fn reciprocal_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(1.0 / input.value())
}

pub fn sin_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().sin())
}

pub fn cos_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().cos())
}

pub fn tan_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().tan())
}

pub fn floor_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().floor())
}

pub fn ceil_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().ceil())
}

fn round_ties_even_f64(value: f64) -> f64 {
    value.round_ties_even()
}

pub fn round_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(round_ties_even_f64(input.value()))
}

pub fn log2_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().log2())
}

pub fn log10_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().log10())
}

pub fn log1p_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().ln_1p())
}

pub fn expm1_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().exp_m1())
}

/// PyTorch parity: `torch.sign` maps both signed zeros to +0.0,
/// propagates NaN, and returns ±1.0 only for non-zero finite values.
/// Rust's `f64::signum` instead returns ±1.0 for ±0.0 (IEEE 754
/// sign-bit semantics), which is observably different — fix it once
/// here so every dispatch backend sees the same semantics.
fn torch_sign_f64(value: f64) -> f64 {
    // torch.sign = (0 < x) - (x < 0): NaN and ±0 fall through both comparisons
    // to 0.0. torch.sign(NaN) == 0.0 (NOT NaN — verified torch 2.12, f64+f32);
    // the prior NaN→NaN branch diverged. frankentorch-z6bl1.
    if value > 0.0 {
        1.0
    } else if value < 0.0 {
        -1.0
    } else {
        0.0
    }
}

pub fn sign_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(torch_sign_f64(input.value()))
}

pub fn trunc_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().trunc())
}

pub fn frac_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().fract())
}

pub fn asin_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().asin())
}

pub fn acos_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().acos())
}

pub fn atan_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().atan())
}

pub fn sinh_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().sinh())
}

pub fn cosh_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(input.value().cosh())
}

fn gelu_value(x: f64) -> f64 {
    // PyTorch default GELU (approximate="none"): exact erf form
    // GELU(x) = 0.5 * x * (1 + erf(x / sqrt(2)))
    // Uses libm-quality erf so we match torch's CPU std::erf path bit-for-bit.
    0.5 * x * (1.0 + libm::erf(x * std::f64::consts::FRAC_1_SQRT_2))
}

pub fn gelu_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(gelu_value(input.value()))
}

fn silu_value(x: f64) -> f64 {
    x / (1.0 + (-x).exp())
}

pub fn silu_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(silu_value(input.value()))
}

fn leaky_relu_value(x: f64) -> f64 {
    if x >= 0.0 { x } else { 0.01 * x }
}

pub fn leaky_relu_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(leaky_relu_value(input.value()))
}

fn elu_value(x: f64) -> f64 {
    // Negative branch uses expm1 (not exp(x)-1.0) to avoid catastrophic
    // cancellation near 0 and match torch's elu bit-for-bit. frankentorch-0f609.
    if x > 0.0 { x } else { x.exp_m1() }
}

pub fn elu_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(elu_value(input.value()))
}

pub fn rsqrt_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(1.0 / input.value().sqrt())
}

/// Gauss error function approximation (Abramowitz and Stegun, formula 7.1.26).
/// Maximum error: |ε(x)| ≤ 1.5×10⁻⁷.
/// f64 error function with libm-quality precision (~1 ULP across the
/// entire f64 domain), via the pure-Rust `libm` crate. The previous
/// implementation used the Abramowitz-Stegun 7.1.26 polynomial
/// approximation whose absolute error of ~1.5e-7 collapsed precision
/// to single-precision territory — an 8-orders-of-magnitude regression
/// vs PyTorch's `torch.erf` which wraps libm `erf`. Routing through
/// `libm::erf` restores f64 precision and bit-aligns with the upstream
/// reference (see `torch_erf_erfc_libm_subprocess_conformance` in
/// ft-conformance).
fn erf_value(x: f64) -> f64 {
    libm::erf(x)
}

/// Companion to `erf_value` for the complementary error function. Using
/// `libm::erfc` directly (instead of computing `1.0 - erf(x)`) preserves
/// precision in the tail region |x| >> 1 where `1 - erf(x)` cancels
/// down to subnormal magnitudes — `1.0 - erf(x)` would round to 0.0
/// for |x| > ~5.95 even though `erfc(x)` is still a tiny but non-zero
/// positive number.
fn erfc_value(x: f64) -> f64 {
    libm::erfc(x)
}

pub fn erf_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(erf_value(input.value()))
}

pub fn erfc_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(erfc_value(input.value()))
}

fn hardswish_value(x: f64) -> f64 {
    if x <= -3.0 {
        0.0
    } else if x >= 3.0 {
        x
    } else {
        x * (x + 3.0) / 6.0
    }
}

pub fn hardswish_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(hardswish_value(input.value()))
}

fn hardsigmoid_value(x: f64) -> f64 {
    if x <= -3.0 {
        0.0
    } else if x >= 3.0 {
        1.0
    } else {
        (x + 3.0) / 6.0
    }
}

pub fn hardsigmoid_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(hardsigmoid_value(input.value()))
}

fn hardtanh_value(x: f64) -> f64 {
    x.clamp(-1.0, 1.0)
}

pub fn hardtanh_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(hardtanh_value(input.value()))
}

fn softplus_value(x: f64) -> f64 {
    // PyTorch: softplus(x) = log1p(exp(beta*x)) / beta, with the
    // upper-threshold short circuit (returns x when beta*x > threshold)
    // for numerical stability when exp would overflow.
    //
    // Defaults: beta = 1, threshold = 20. PyTorch only thresholds in
    // the *upper* direction — for x → -∞, log1p(exp(x)) decays smoothly
    // to 0 without losing precision, so an artificial lower clamp would
    // wrongly flatten values like softplus(-25) ≈ 1.39e-11 to 0.
    //
    // log1p(exp(x)) is the precise form: for negative x, exp(x) is
    // small and `log(1 + small)` would lose a leading digit relative to
    // log1p(small).
    if x > 20.0 { x } else { x.exp().ln_1p() }
}

pub fn softplus_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(softplus_value(input.value()))
}

fn mish_value(x: f64) -> f64 {
    x * softplus_value(x).tanh()
}

pub fn mish_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(mish_value(input.value()))
}

pub fn square_scalar(input: &ScalarTensor) -> ScalarTensor {
    let v = input.value();
    input.with_value(v * v)
}

pub fn isnan_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(if input.value().is_nan() { 1.0 } else { 0.0 })
}

pub fn isinf_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(if input.value().is_infinite() {
        1.0
    } else {
        0.0
    })
}

pub fn isfinite_scalar(input: &ScalarTensor) -> ScalarTensor {
    input.with_value(if input.value().is_finite() { 1.0 } else { 0.0 })
}

pub fn pow_scalar(input: &ScalarTensor, exponent: f64) -> ScalarTensor {
    input.with_value(powf_torch_signed_zero_f64(input.value(), exponent))
}

fn powf_torch_signed_zero_f64(value: f64, exponent: f64) -> f64 {
    // Defer to Rust's f64::powf, which matches libm pow bit-for-bit.
    // The previous body overrode pow(-0, fractional > 0) from +0 to
    // -0 to match an older torch convention, but current libm and
    // torch both return +0 (per IEEE 754-2008 §9.2.1). Pinned by
    // torch_pow_ieee754_subprocess_conformance (vgj2).
    //
    value.powf(exponent)
}

fn powf_torch_signed_zero_f32(value: f32, exponent: f32) -> f32 {
    // Match libm convention: pow(-0, fractional > 0) returns +0.
    // See powf_torch_signed_zero_f64 for the rationale.
    value.powf(exponent)
}

pub fn clamp_scalar(input: &ScalarTensor, min_val: f64, max_val: f64) -> ScalarTensor {
    let value = input.value();
    // clamp is min(max(x, min_val), max_val): the lower bound is applied
    // first, then the upper. When min_val > max_val the upper bound wins,
    // matching PyTorch / std::min(std::max(...)).
    let clamped = if value.is_nan() {
        f64::NAN
    } else {
        let lo = if !min_val.is_nan() && value < min_val {
            min_val
        } else {
            value
        };
        if !max_val.is_nan() && lo > max_val {
            max_val
        } else {
            lo
        }
    };
    input.with_value(clamped)
}

pub fn min_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    let val = if lhs.value().is_nan() || rhs.value().is_nan() {
        f64::NAN
    } else {
        lhs.value().min(rhs.value())
    };
    Ok(lhs.with_value(val))
}

pub fn max_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    let val = if lhs.value().is_nan() || rhs.value().is_nan() {
        f64::NAN
    } else {
        lhs.value().max(rhs.value())
    };
    Ok(lhs.with_value(val))
}

pub fn eq_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(if lhs.value() == rhs.value() { 1.0 } else { 0.0 }))
}

pub fn ne_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(if lhs.value() != rhs.value() { 1.0 } else { 0.0 }))
}

pub fn lt_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(if lhs.value() < rhs.value() { 1.0 } else { 0.0 }))
}

pub fn gt_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(if lhs.value() > rhs.value() { 1.0 } else { 0.0 }))
}

pub fn le_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(if lhs.value() <= rhs.value() { 1.0 } else { 0.0 }))
}

pub fn ge_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(if lhs.value() >= rhs.value() { 1.0 } else { 0.0 }))
}

pub fn add_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(lhs.value() + rhs.value()))
}

pub fn sub_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(lhs.value() - rhs.value()))
}

pub fn div_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(lhs.value() / rhs.value()))
}

pub fn mul_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(lhs.value() * rhs.value()))
}

pub fn atan2_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(lhs.value().atan2(rhs.value())))
}

pub fn fmod_scalar(lhs: &ScalarTensor, rhs: &ScalarTensor) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    Ok(lhs.with_value(lhs.value() % rhs.value()))
}

pub fn remainder_scalar(
    lhs: &ScalarTensor,
    rhs: &ScalarTensor,
) -> Result<ScalarTensor, KernelError> {
    ensure_compatible(lhs, rhs)?;
    let a = lhs.value();
    let b = rhs.value();
    Ok(lhs.with_value(a - (a / b).floor() * b))
}

fn ensure_dtype_device_and_layout(lhs: &TensorMeta, rhs: &TensorMeta) -> Result<(), KernelError> {
    if lhs.dtype() != rhs.dtype() {
        return Err(KernelError::Incompatible(
            TensorCompatError::DTypeMismatch {
                lhs: lhs.dtype(),
                rhs: rhs.dtype(),
            },
        ));
    }

    if lhs.device() != rhs.device() {
        return Err(KernelError::Incompatible(
            TensorCompatError::DeviceMismatch {
                lhs: lhs.device(),
                rhs: rhs.device(),
            },
        ));
    }

    if !lhs.is_contiguous() {
        return Err(KernelError::UnsupportedLayout { side: "lhs" });
    }

    if !rhs.is_contiguous() {
        return Err(KernelError::UnsupportedLayout { side: "rhs" });
    }

    Ok(())
}

fn ensure_meta_shape_and_dtype(lhs: &TensorMeta, rhs: &TensorMeta) -> Result<(), KernelError> {
    if lhs.dtype() != rhs.dtype() {
        return Err(KernelError::Incompatible(
            TensorCompatError::DTypeMismatch {
                lhs: lhs.dtype(),
                rhs: rhs.dtype(),
            },
        ));
    }

    if lhs.device() != rhs.device() {
        return Err(KernelError::Incompatible(
            TensorCompatError::DeviceMismatch {
                lhs: lhs.device(),
                rhs: rhs.device(),
            },
        ));
    }

    if lhs.shape() != rhs.shape() {
        return Err(KernelError::ShapeMismatch {
            lhs: lhs.shape().to_vec(),
            rhs: rhs.shape().to_vec(),
        });
    }

    Ok(())
}

fn matmul_dims(
    lhs_meta: &TensorMeta,
    rhs_meta: &TensorMeta,
) -> Result<(usize, usize, usize), KernelError> {
    if lhs_meta.shape().len() != 2 || rhs_meta.shape().len() != 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: lhs_meta.shape().to_vec(),
            rhs: rhs_meta.shape().to_vec(),
        });
    }

    let m = lhs_meta.shape()[0];
    let k = lhs_meta.shape()[1];
    let rhs_k = rhs_meta.shape()[0];
    let n = rhs_meta.shape()[1];
    if k != rhs_k {
        return Err(KernelError::ShapeMismatch {
            lhs: lhs_meta.shape().to_vec(),
            rhs: rhs_meta.shape().to_vec(),
        });
    }

    Ok((m, k, n))
}

fn contiguous_required_len(meta: &TensorMeta, side: &'static str) -> Result<usize, KernelError> {
    let numel = meta.numel();
    if numel == 0 {
        return Ok(0);
    }

    meta.storage_offset()
        .checked_add(numel)
        .ok_or(KernelError::StorageSpanOverflow {
            side,
            storage_offset: meta.storage_offset(),
            numel,
        })
}

fn ensure_storage_len(
    buffer: &[f64],
    meta: &TensorMeta,
    side: &'static str,
) -> Result<(), KernelError> {
    let needed = contiguous_required_len(meta, side)?;
    if buffer.len() < needed {
        return Err(KernelError::InsufficientStorage {
            side,
            needed,
            available: buffer.len(),
        });
    }
    Ok(())
}

fn elementwise_f64<F>(
    lhs: &[f64],
    rhs: &[f64],
    lhs_meta: &TensorMeta,
    rhs_meta: &TensorMeta,
    op: F,
) -> Result<Vec<f64>, KernelError>
where
    F: Fn(f64, f64) -> f64 + Sync,
{
    ensure_meta_shape_and_dtype(lhs_meta, rhs_meta)?;

    if !lhs_meta.is_contiguous() || !rhs_meta.is_contiguous() {
        return elementwise_strided_f64(lhs, rhs, lhs_meta, rhs_meta, op);
    }

    ensure_storage_len(lhs, lhs_meta, "lhs")?;
    ensure_storage_len(rhs, rhs_meta, "rhs")?;

    let numel = lhs_meta.numel();
    if numel == 0 {
        return Ok(Vec::new());
    }

    let lhs_start = lhs_meta.storage_offset();
    let rhs_start = rhs_meta.storage_offset();
    let lhs_window = &lhs[lhs_start..lhs_start + numel];
    let rhs_window = &rhs[rhs_start..rhs_start + numel];

    if numel >= PARALLEL_THRESHOLD {
        Ok(lhs_window
            .par_iter()
            .zip(rhs_window.par_iter())
            .map(|(left, right)| op(*left, *right))
            .collect())
    } else {
        Ok(lhs_window
            .iter()
            .zip(rhs_window.iter())
            .map(|(left, right)| op(*left, *right))
            .collect())
    }
}

fn ensure_unary_layout_and_storage(buffer: &[f64], meta: &TensorMeta) -> Result<(), KernelError> {
    if !meta.is_contiguous() {
        return Err(KernelError::UnsupportedLayout { side: "input" });
    }
    ensure_storage_len(buffer, meta, "input")
}

// Retained utility: the strided f64 kernels now unravel flat indices inline, but
// this coords->index helper is kept for the coords-based strided paths and tests.
#[allow(dead_code)]
fn strided_index(coords: &[usize], strides: &[usize], offset: usize) -> usize {
    let mut idx = offset;
    for (c, s) in coords.iter().zip(strides.iter()) {
        idx += c * s;
    }
    idx
}

// Retained utility: the strided f64 kernels now unravel flat indices inline; this
// row-major coords incrementer is kept for any remaining coords-based traversal.
#[allow(dead_code)]
fn increment_coords(coords: &mut [usize], shape: &[usize]) -> bool {
    for d in (0..coords.len()).rev() {
        coords[d] += 1;
        if coords[d] < shape[d] {
            return true;
        }
        coords[d] = 0;
    }
    false
}

fn elementwise_strided_f64<F>(
    lhs: &[f64],
    rhs: &[f64],
    lhs_meta: &TensorMeta,
    rhs_meta: &TensorMeta,
    op: F,
) -> Result<Vec<f64>, KernelError>
where
    F: Fn(f64, f64) -> f64 + Sync,
{
    let shape = lhs_meta.shape();
    let numel = lhs_meta.numel();
    if numel == 0 {
        return Ok(Vec::new());
    }

    let lhs_strides = lhs_meta.strides();
    let rhs_strides = rhs_meta.strides();
    let lhs_offset = lhs_meta.storage_offset();
    let rhs_offset = rhs_meta.storage_offset();
    let ndim = shape.len();

    // Row-major contiguous strides of the (logical) output, so a flat output
    // index unravels to per-dim coords WITHOUT a running coords vector — making
    // each output element independent. The unravel walks dims in the same order
    // as the old `increment_coords` sweep (last dim fastest), so the indexed map
    // yields output[i] in identical order => bit-for-bit identical to the serial
    // loop. The per-element strided index decode (div/mod over dims) is the work,
    // so this is compute-bound and parallelizes cleanly above PARALLEL_THRESHOLD.
    let mut out_strides = vec![1usize; ndim];
    for d in (0..ndim.saturating_sub(1)).rev() {
        out_strides[d] = out_strides[d + 1] * shape[d + 1];
    }

    let compute = |i: usize| -> f64 {
        let mut rem = i;
        let mut lhs_idx = lhs_offset;
        let mut rhs_idx = rhs_offset;
        for d in 0..ndim {
            let coord = rem / out_strides[d];
            rem %= out_strides[d];
            lhs_idx += coord * lhs_strides[d];
            rhs_idx += coord * rhs_strides[d];
        }
        op(lhs[lhs_idx], rhs[rhs_idx])
    };

    let output: Vec<f64> = if numel >= PARALLEL_THRESHOLD {
        (0..numel).into_par_iter().map(compute).collect()
    } else {
        (0..numel).map(compute).collect()
    };

    Ok(output)
}

fn unary_strided_f64<F>(input: &[f64], meta: &TensorMeta, op: F) -> Result<Vec<f64>, KernelError>
where
    F: Fn(f64) -> f64 + Sync,
{
    let shape = meta.shape();
    let numel = meta.numel();
    if numel == 0 {
        return Ok(Vec::new());
    }

    let strides = meta.strides();
    let offset = meta.storage_offset();
    let ndim = shape.len();

    // Per-flat-index unravel (row-major over the logical shape, last dim fastest),
    // identical traversal order to the old `increment_coords` sweep, so output[i]
    // is byte-identical => bit-for-bit == serial. Per-element strided decode +
    // (for transcendental ops) the op itself make this compute-bound; fans over
    // the rayon pool above PARALLEL_THRESHOLD, serial fallback below.
    let mut out_strides = vec![1usize; ndim];
    for d in (0..ndim.saturating_sub(1)).rev() {
        out_strides[d] = out_strides[d + 1] * shape[d + 1];
    }

    let compute = |i: usize| -> f64 {
        let mut rem = i;
        let mut idx = offset;
        for d in 0..ndim {
            let coord = rem / out_strides[d];
            rem %= out_strides[d];
            idx += coord * strides[d];
        }
        op(input[idx])
    };

    let output: Vec<f64> = if numel >= PARALLEL_THRESHOLD {
        (0..numel).into_par_iter().map(compute).collect()
    } else {
        (0..numel).map(compute).collect()
    };

    Ok(output)
}

fn checked_shape_numel(shape: &[usize], context: &'static str) -> Result<usize, KernelError> {
    let mut product = 1usize;
    for dim in shape.iter().copied() {
        if dim == 0 {
            return Ok(0);
        }
        product = product
            .checked_mul(dim)
            .ok_or(KernelError::ShapeOverflow { context })?;
    }
    Ok(product)
}

fn checked_mul(lhs: usize, rhs: usize, context: &'static str) -> Result<usize, KernelError> {
    lhs.checked_mul(rhs)
        .ok_or(KernelError::ShapeOverflow { context })
}

fn checked_contiguous_range(
    outer: usize,
    block_len: usize,
    context: &'static str,
) -> Result<std::ops::Range<usize>, KernelError> {
    let start = checked_mul(outer, block_len, context)?;
    let end = start
        .checked_add(block_len)
        .ok_or(KernelError::ShapeOverflow { context })?;
    Ok(start..end)
}

fn checked_dim_loop_sizes(
    shape: &[usize],
    dim: usize,
    context: &'static str,
) -> Result<(usize, usize, usize), KernelError> {
    let outer_size = checked_shape_numel(&shape[..dim], context)?;
    let inner_size = checked_shape_numel(&shape[dim + 1..], context)?;
    let total_size = checked_shape_numel(shape, context)?;
    Ok((outer_size, inner_size, total_size))
}

const PARALLEL_THRESHOLD: usize = 8192;

// The SIMD unary ops (relu/sqrt/reciprocal/...) were SERIAL while the scalar-map
// unary path (exp/tanh/...) parallelises — so relu was ~36-59x slower than torch
// at large N purely from single-threading. Parallelise above this gate (cheap
// per-element work, so amortise rayon split/join only at large N, same as the
// scalar path's threshold).
const SIMD_UNARY_PARALLEL_THRESHOLD: usize = 1 << 19; // 524288

// The generic scalar-map unary path (exp/ln/sin/gelu/erf/...) is dominated by a
// per-element libm call (~15-20 ns), but rayon's split/join/collect overhead on
// a many-core pool only amortises at very large N. A same-worker A/B
// (RAYON_NUM_THREADS=1 vs default, 64-core) showed `tensor_exp` PARALLEL was a
// net loss until ~0.5M elements:
//   exp/10000   serial 149 us  vs parallel 833 us   (5.6x slower parallel)
//   exp/100000  serial 1.28 ms vs parallel 2.63 ms  (2.0x slower parallel)
//   exp/1000000 serial 19.5 ms vs parallel 9.0 ms   (2.2x faster parallel)
// So gate the scalar-unary parallel path much higher than the cheap/SIMD ops.
// The map is elementwise with no cross-element accumulation, so serial and
// parallel are bit-for-bit identical — this only changes scheduling.
const SCALAR_UNARY_PARALLEL_THRESHOLD: usize = 1 << 19; // 524288

// Row-parallel softmax/log_softmax over the last dim spreads independent rows
// across the rayon pool, but for the common classifier/attention shapes the
// total work is tiny and rayon's split/join dominates. Same-worker A/B
// (RAYON_NUM_THREADS=1 vs default, 64-core) on softmax/vocab [32, n]:
//   numel 4096   serial 72 us   vs parallel 556 us  (7.7x slower parallel)
//   numel 16384  serial 214 us  vs parallel 676 us  (3.2x slower parallel)
//   numel 65536  serial 1.03 ms vs parallel 1.02 ms (break-even)
//   numel 262144 serial 2.74 ms vs parallel 1.13 ms (2.4x faster parallel)
// Gate the per-row parallel path at the ~65536 crossover. Rows are independent
// and each is reduced identically regardless of thread, so output is
// bit-for-bit identical to the single-threaded path.
const SOFTMAX_PARALLEL_NUMEL_THRESHOLD: usize = 1 << 16; // 65536

fn unary_f64<F>(input: &[f64], meta: &TensorMeta, op: F) -> Result<Vec<f64>, KernelError>
where
    F: Fn(f64) -> f64 + Sync,
{
    unary_f64_with_threshold(input, meta, op, SCALAR_UNARY_PARALLEL_THRESHOLD)
}

/// Like [`unary_f64`] but for COMPUTE-BOUND element ops (erf/gelu/softplus/… —
/// each ~exp+log of work, the same class as `pow`). Their per-element cost is far
/// higher than the cheap ops (sign/round/clamp) that set
/// `SCALAR_UNARY_PARALLEL_THRESHOLD = 524288`, so they pay off across the rayon
/// pool at much smaller sizes: gate at the low `PARALLEL_THRESHOLD = 8192` that
/// `pow_tensor_contiguous_f64` already uses for the identical exp/log workload.
/// The map is a pure per-element function, so the parallel result is bit-identical
/// to the serial one. frankentorch-kgs4.89.
fn unary_f64_compute_bound<F>(
    input: &[f64],
    meta: &TensorMeta,
    op: F,
) -> Result<Vec<f64>, KernelError>
where
    F: Fn(f64) -> f64 + Sync,
{
    unary_f64_with_threshold(input, meta, op, PARALLEL_THRESHOLD)
}

fn unary_f64_with_threshold<F>(
    input: &[f64],
    meta: &TensorMeta,
    op: F,
    parallel_threshold: usize,
) -> Result<Vec<f64>, KernelError>
where
    F: Fn(f64) -> f64 + Sync,
{
    if !meta.is_contiguous() {
        return unary_strided_f64(input, meta, op);
    }

    ensure_storage_len(input, meta, "input")?;

    let numel = meta.numel();
    if numel == 0 {
        return Ok(Vec::new());
    }

    let start = meta.storage_offset();
    let window = &input[start..start + numel];

    if numel >= parallel_threshold {
        Ok(window.par_iter().map(|value| op(*value)).collect())
    } else {
        Ok(window.iter().map(|value| op(*value)).collect())
    }
}

fn simd_unary_f64<F, S>(window: &[f64], scalar_op: F, simd_op: S) -> Vec<f64>
where
    F: Fn(f64) -> f64 + Sync,
    S: Fn(f64x4) -> f64x4 + Sync,
{
    let numel = window.len();
    let mut output = vec![0.0; numel];

    // One contiguous block: SIMD over the SIMD_WIDTH-aligned bulk, scalar tail.
    let block = |out: &mut [f64], inp: &[f64]| {
        let simd_len = out.len() / SIMD_WIDTH * SIMD_WIDTH;
        for (o, i) in out[..simd_len]
            .chunks_exact_mut(SIMD_WIDTH)
            .zip(inp[..simd_len].chunks_exact(SIMD_WIDTH))
        {
            let a = f64x4::new([i[0], i[1], i[2], i[3]]);
            o.copy_from_slice(simd_op(a).as_array_ref());
        }
        for (o, &v) in out[simd_len..].iter_mut().zip(&inp[simd_len..]) {
            *o = scalar_op(v);
        }
    };

    if numel >= SIMD_UNARY_PARALLEL_THRESHOLD {
        // SIMD_WIDTH-aligned grains: every grain but the last is a whole number
        // of SIMD lanes, so the SIMD/scalar element split is identical to the
        // serial path -> bit-for-bit identical output.
        let threads = rayon::current_num_threads().max(1);
        let grain = numel
            .div_ceil(4 * threads)
            .max(SIMD_WIDTH)
            .div_ceil(SIMD_WIDTH)
            * SIMD_WIDTH;
        output
            .par_chunks_mut(grain)
            .zip(window.par_chunks(grain))
            .for_each(|(out, inp)| block(out, inp));
    } else {
        block(&mut output, window);
    }

    output
}

fn simd_unary_f64_kernel<F, S>(
    input: &[f64],
    meta: &TensorMeta,
    scalar_op: F,
    _simd_op: S,
) -> Result<Vec<f64>, KernelError>
where
    F: Fn(f64) -> f64 + Sync,
    S: Fn(f64x4) -> f64x4 + Sync,
{
    if !meta.is_contiguous() {
        return unary_strided_f64(input, meta, scalar_op);
    }

    ensure_storage_len(input, meta, "input")?;

    let numel = meta.numel();
    if numel == 0 {
        return Ok(Vec::new());
    }

    let start = meta.storage_offset();
    let window = &input[start..start + numel];

    Ok(simd_unary_f64(window, scalar_op, _simd_op))
}

/// Vectorised `exp` over one f64x4 lane group.
///
/// Alien-artifact foundation for a SIMD transcendental family (the no-gaps
/// directive's "portable SIMD elementwise"). `wide`'s degree-13 polynomial with
/// ln2 range reduction is accurate to ~1-2 ULP for the common finite range
/// `|x| < 708.39`. Outside that, `wide::exp` flushes the lane to 0.0, which is
/// WRONG for: overflow (should be +inf), the finite `[708.39, 709.78]` band,
/// the `[-745, -708.39]` denormal-underflow band, `+inf` (should be +inf) and
/// `NaN` (should be NaN). When ANY lane is out of the fast range we recompute
/// the whole group with scalar `f64::exp`, which is exact per libm — these
/// extreme inputs are rare, so the common path stays fully vectorised.
///
/// NOTE: in the fast range this is NOT bit-identical to scalar `f64::exp` (the
/// polynomial differs by ~1-2 ULP). It is a *tolerance-accurate* kernel. It is
/// intentionally NOT yet wired into the production `exp`/`sigmoid`/`softmax`
/// paths: those are currently pinned bit-exact to scalar libm by unit tests, so
/// adopting this requires moving the transcendental parity contract from
/// bit-exact-to-libm to within-tolerance-of-torch (a deliberate project policy
/// decision). `exp_f64x4_matches_scalar_within_tolerance` proves the accuracy
/// and edge-case obligations are met.
#[inline]
#[must_use]
pub fn exp_f64x4(x: f64x4) -> f64x4 {
    // wide's vectorised polynomial is valid (and ~1-2 ULP) exactly when every
    // lane is finite with |x| < 708.39; otherwise it wrongly flushes to 0.0.
    const FAST_LIMIT: f64 = 708.39;
    let xa = x.to_array();
    let lane_fast = |v: f64| v.is_finite() && v.abs() < FAST_LIMIT;
    if xa.iter().copied().all(lane_fast) {
        x.exp()
    } else {
        // Any extreme/non-finite lane present: recompute the whole group with
        // scalar libm so overflow->+inf, +inf->+inf, NaN->NaN, the finite
        // 708.39..=709.78 band and denormal underflow are all exact.
        f64x4::new([xa[0].exp(), xa[1].exp(), xa[2].exp(), xa[3].exp()])
    }
}

fn broadcast_strides(
    input_shape: &[usize],
    target_shape: &[usize],
    context: &'static str,
) -> Result<Vec<usize>, KernelError> {
    let ndim = input_shape.len();
    debug_assert_eq!(ndim, target_shape.len());

    let mut strides = vec![0usize; ndim];
    let mut running_stride = 1usize;
    for d in (0..ndim).rev() {
        strides[d] = if input_shape[d] == 1 && target_shape[d] > 1 {
            0
        } else {
            running_stride
        };
        running_stride = running_stride
            .checked_mul(input_shape[d])
            .ok_or(KernelError::ShapeOverflow { context })?;
    }

    Ok(strides)
}

pub fn compute_broadcast_shape(
    lhs_shape: &[usize],
    rhs_shape: &[usize],
) -> Result<Vec<usize>, KernelError> {
    let lhs_ndim = lhs_shape.len();
    let rhs_ndim = rhs_shape.len();
    let out_ndim = lhs_ndim.max(rhs_ndim);

    let mut out_shape = vec![0usize; out_ndim];
    for i in 0..out_ndim {
        let lhs_dim = if i < out_ndim - lhs_ndim {
            1
        } else {
            lhs_shape[i - (out_ndim - lhs_ndim)]
        };
        let rhs_dim = if i < out_ndim - rhs_ndim {
            1
        } else {
            rhs_shape[i - (out_ndim - rhs_ndim)]
        };

        if lhs_dim == rhs_dim {
            out_shape[i] = lhs_dim;
        } else if lhs_dim == 1 {
            out_shape[i] = rhs_dim;
        } else if rhs_dim == 1 {
            out_shape[i] = lhs_dim;
        } else {
            return Err(KernelError::ShapeMismatch {
                lhs: lhs_shape.to_vec(),
                rhs: rhs_shape.to_vec(),
            });
        }
    }

    Ok(out_shape)
}

fn broadcast_idx(
    flat_idx: usize,
    out_shape: &[usize],
    in_shape: &[usize],
    in_strides: &[usize],
    in_offset: usize,
) -> usize {
    let out_ndim = out_shape.len();
    let in_ndim = in_shape.len();

    let mut idx = in_offset;
    let mut remaining = flat_idx;

    for i in (0..out_ndim).rev() {
        let coord = remaining % out_shape[i];
        remaining /= out_shape[i];

        if i >= out_ndim - in_ndim {
            let in_i = i - (out_ndim - in_ndim);
            if in_shape[in_i] > 1 {
                idx += coord * in_strides[in_i];
            }
        }
    }

    idx
}

fn elementwise_broadcast_f64<F>(
    lhs: &[f64],
    rhs: &[f64],
    lhs_meta: &TensorMeta,
    rhs_meta: &TensorMeta,
    op: F,
) -> Result<(Vec<f64>, Vec<usize>), KernelError>
where
    F: Fn(f64, f64) -> f64 + Sync,
{
    let out_shape = compute_broadcast_shape(lhs_meta.shape(), rhs_meta.shape())?;
    let out_numel = checked_shape_numel(&out_shape, "broadcast output")?;

    if out_numel == 0 {
        return Ok((Vec::new(), out_shape));
    }

    let lhs_strides = lhs_meta.strides();
    let rhs_strides = rhs_meta.strides();
    let lhs_offset = lhs_meta.storage_offset();
    let rhs_offset = rhs_meta.storage_offset();

    // Each output element independently unravels its flat index `i` into the two
    // source indices (per-dim div/mod over both operands) — that index arithmetic,
    // not the scalar op, dominates the per-element cost, so the broadcast loop is
    // compute-bound and parallelizes cleanly. Pure indexed map → bit-identical to
    // the serial loop. frankentorch-kgs4.93.
    let eval = |i: usize| {
        let lhs_idx = broadcast_idx(i, &out_shape, lhs_meta.shape(), lhs_strides, lhs_offset);
        let rhs_idx = broadcast_idx(i, &out_shape, rhs_meta.shape(), rhs_strides, rhs_offset);
        op(lhs[lhs_idx], rhs[rhs_idx])
    };
    let output: Vec<f64> = if out_numel >= PARALLEL_THRESHOLD {
        (0..out_numel).into_par_iter().map(eval).collect()
    } else {
        (0..out_numel).map(eval).collect()
    };

    Ok((output, out_shape))
}

pub fn reduce_sum_for_broadcast(
    expanded_grad: &[f64],
    expanded_shape: &[usize],
    original_shape: &[usize],
) -> Result<Vec<f64>, KernelError> {
    let ndim = expanded_shape.len();
    if ndim != original_shape.len() {
        return Err(KernelError::ShapeMismatch {
            lhs: expanded_shape.to_vec(),
            rhs: original_shape.to_vec(),
        });
    }

    for d in 0..ndim {
        let expanded = expanded_shape[d];
        let original = original_shape[d];
        if original != expanded && original != 1 {
            return Err(KernelError::ShapeMismatch {
                lhs: expanded_shape.to_vec(),
                rhs: original_shape.to_vec(),
            });
        }
    }

    let expanded_numel = checked_shape_numel(expanded_shape, "broadcast reduction expanded shape")?;
    if expanded_grad.len() != expanded_numel {
        return Err(KernelError::ShapeMismatch {
            lhs: vec![expanded_grad.len()],
            rhs: vec![expanded_numel],
        });
    }

    let original_numel = checked_shape_numel(original_shape, "broadcast reduction original shape")?;
    if original_numel == 0 {
        return Ok(Vec::new());
    }

    // The serial sweep adds expanded_grad[e] (row-major e) into reduced[orig(e)].
    // Equivalently, reduced[o] = Σ of the grads whose expanded index maps to `o`,
    // summed in increasing expanded-flat-index order. Computing each output
    // independently in that exact order lets us parallelize over outputs WITHOUT
    // changing the floating-point accumulation order — bit-identical to the serial
    // scatter-add. The per-output index decode (not the single read) dominates, so
    // it is compute-bound. frankentorch-kgs4.95.
    let expanded_strides = ft_core::contiguous_strides(expanded_shape);
    let original_cstrides = ft_core::contiguous_strides(original_shape);
    // Dims that were broadcast (original size 1, expanded > 1): the contributors to
    // each output range over the cartesian product of these, in row-major order.
    let bcast_dims: Vec<usize> = (0..ndim)
        .filter(|&d| original_shape[d] == 1 && expanded_shape[d] > 1)
        .collect();
    let bcast_sizes: Vec<usize> = bcast_dims.iter().map(|&d| expanded_shape[d]).collect();
    let num_contrib: usize = bcast_sizes.iter().product();

    let reduce_one = |o: usize| -> f64 {
        // Base expanded-flat index from the (fixed) non-broadcast coordinates.
        let mut rem = o;
        let mut base = 0usize;
        for d in 0..ndim {
            let oc = rem / original_cstrides[d];
            rem %= original_cstrides[d];
            base += oc * expanded_strides[d];
        }
        // Sum contributors in increasing expanded-flat order (row-major over the
        // broadcast dims, last broadcast dim varying fastest) — matches the serial
        // sweep's visitation order for this output exactly.
        let mut acc = 0.0_f64;
        for count in 0..num_contrib {
            let mut c = count;
            let mut offset = 0usize;
            for k in (0..bcast_dims.len()).rev() {
                let coord = c % bcast_sizes[k];
                c /= bcast_sizes[k];
                offset += coord * expanded_strides[bcast_dims[k]];
            }
            acc += expanded_grad[base + offset];
        }
        acc
    };

    let reduced: Vec<f64> = if expanded_numel >= PARALLEL_THRESHOLD {
        (0..original_numel)
            .into_par_iter()
            .map(reduce_one)
            .collect()
    } else {
        (0..original_numel).map(reduce_one).collect()
    };

    Ok(reduced)
}

