/// Backward of [`conv2d_forward_f64`]. Returns `(dpadded, dweight_flat, dbias?)`.
/// `dweight = dout^T @ panel`, `dpanel = dout @ weight_flat`, `dpadded =
/// col2im(dpanel)`, `dbias = sum over (n,oh,ow)`.
#[allow(clippy::too_many_arguments)]
#[must_use]
pub fn conv2d_backward_f64(
    dout: &[f64],
    padded: &[f64],
    weight_flat: &[f64],
    batch: usize,
    in_ch: usize,
    ph: usize,
    pw: usize,
    kh: usize,
    kw: usize,
    oh: usize,
    ow: usize,
    sh: usize,
    sw: usize,
    out_ch: usize,
    has_bias: bool,
) -> (Vec<f64>, Vec<f64>, Option<Vec<f64>>) {
    let patch_width = in_ch * kh * kw;
    let patch_count = oh * ow;
    let flat = batch * patch_count;
    // Gather dout [N,out_ch,patch_count] -> dout_flat [flat, out_ch].
    let mut dout_flat = vec![0.0f64; flat * out_ch];
    dout_flat
        .par_chunks_mut(out_ch)
        .enumerate()
        .for_each(|(row, dr)| {
            let n = row / patch_count;
            let p = row % patch_count;
            for (oc, d) in dr.iter_mut().enumerate() {
                *d = dout[(n * out_ch + oc) * patch_count + p];
            }
        });
    let panel = conv2d_im2col_f64(padded, batch, in_ch, ph, pw, kh, kw, oh, ow, sh, sw);
    // dweight_flat [out_ch, patch_width] = dout_flat^T @ panel.
    // Transpose dout_flat [flat, out_ch] -> dout_t [out_ch, flat] in parallel over
    // out_ch (each row is an independent strided gather — pure copy, so the result
    // is identical; this was a serial O(flat*out_ch) pass). frankentorch-convbwd.
    let mut dout_t = vec![0.0f64; out_ch * flat];
    dout_t
        .par_chunks_exact_mut(flat)
        .enumerate()
        .for_each(|(oc, row)| {
            for (r, slot) in row.iter_mut().enumerate() {
                *slot = dout_flat[r * out_ch + oc];
            }
        });
    let mut dweight = vec![0.0f64; out_ch * patch_width];
    gemm::dgemm(out_ch, flat, patch_width, &dout_t, &panel, &mut dweight);
    // dpanel [flat, patch_width] = dout_flat @ weight_flat.
    let mut dpanel = vec![0.0f64; flat * patch_width];
    gemm::dgemm(
        flat,
        out_ch,
        patch_width,
        &dout_flat,
        weight_flat,
        &mut dpanel,
    );
    let dpadded = conv2d_col2im_f64(&dpanel, batch, in_ch, ph, pw, kh, kw, oh, ow, sh, sw);
    let dbias = if has_bias {
        // Parallel over out_ch: each channel's bias gradient is an independent
        // reduction with the same (n outer, p inner) summation order, so the
        // result is bit-identical to the serial loop. frankentorch-convbwd.
        let mut db = vec![0.0f64; out_ch];
        db.par_iter_mut().enumerate().for_each(|(oc, dbo)| {
            let mut s = 0.0f64;
            for n in 0..batch {
                let base = (n * out_ch + oc) * patch_count;
                for p in 0..patch_count {
                    s += dout[base + p];
                }
            }
            *dbo = s;
        });
        Some(db)
    } else {
        None
    };
    (dpadded, dweight, dbias)
}

/// Fused cdist forward (f64): pairwise `p`-norm distances between rows of `x1`
/// `[batch, p_dim, m]` and `x2` `[batch, r_dim, m]`, returning `[batch, p_dim,
/// r_dim]`. For each output `(b, i, j)` it streams the `m` feature differences
/// and reduces them in ONE pass — no `O(P·R·M)` broadcasted-difference tensor is
/// ever materialised (the op-graph path builds ~4 of them). Parallel over the
/// `batch·p_dim` output rows; the per-`k` accumulation order is identical to the
/// serial reference, so the result matches the broadcast path to f64 round-off.
///
/// `p == +inf` reduces by max-abs; finite `p > 0` accumulates `Σ|Δ|^p` then takes
/// the `1/p` power. (`p == 0` / `p == 2` are handled by their own paths.)
#[must_use]
pub fn cdist_forward_f64(
    x1: &[f64],
    x2: &[f64],
    batch: usize,
    p_dim: usize,
    r_dim: usize,
    m: usize,
    p: f64,
) -> Vec<f64> {
    let mut result = vec![0.0f64; batch * p_dim * r_dim];
    if batch * p_dim * r_dim == 0 {
        return result;
    }
    let inv_p = 1.0 / p;
    let is_inf = p == f64::INFINITY;
    // p == 1 (Manhattan) is `Σ|Δ|` with NO per-element `powf(1.0)` and NO final
    // `powf(1.0)`. Since `pow(x, 1.0) == x` exactly (glibc/IEEE), eliding both is
    // BIT-EXACT vs the general `powf` path but skips one libm `pow` call per
    // element — the dominant cost on the p=1 path. frankentorch-cdist-p1.
    let is_one = p == 1.0;
    // One output row = one (b, i) pair owning a contiguous r_dim slice.
    result
        .par_chunks_mut(r_dim)
        .enumerate()
        .for_each(|(row, out)| {
            let b = row / p_dim;
            let i = row % p_dim;
            let x1_base = b * p_dim * m + i * m;
            let x2_base = b * r_dim * m;
            for (j, slot) in out.iter_mut().enumerate() {
                let x2_row = x2_base + j * m;
                let mut dist = 0.0f64;
                if is_inf {
                    for k in 0..m {
                        let diff = (x1[x1_base + k] - x2[x2_row + k]).abs();
                        if diff > dist {
                            dist = diff;
                        }
                    }
                } else if is_one {
                    for k in 0..m {
                        dist += (x1[x1_base + k] - x2[x2_row + k]).abs();
                    }
                } else {
                    for k in 0..m {
                        let diff = (x1[x1_base + k] - x2[x2_row + k]).abs();
                        dist += diff.powf(p);
                    }
                    dist = dist.powf(inv_p);
                }
                *slot = dist;
            }
        });
    result
}

/// Fused pdist forward (f64): pairwise `p`-norm distances between every i<j pair
/// of rows of `input` `[n, m]`, returning the flattened strict upper triangle
/// `[n·(n-1)/2]` in `(i, then j)` order — the same layout torch's `pdist` and the
/// op-graph (index_select+sub+abs+pow+sum_dim+pow) produce. Each pair streams its
/// `m` feature differences in ONE pass with no `O(out_len·m)` pair-difference
/// tensor materialised. Parallel over the `i` rows; the per-`k` accumulation order
/// matches the op-graph, so the result is bit-identical to the broadcast path.
///
/// `p == +inf` reduces by max-abs; finite `p > 0` accumulates `Σ|Δ|^p` then takes
/// the `1/p` power. (`p == 0` / `p == 2` are handled by their own paths.)
#[must_use]
pub fn pdist_forward_f64(input: &[f64], n: usize, m: usize, p: f64) -> Vec<f64> {
    let out_len = n * (n - 1) / 2;
    if out_len == 0 {
        return Vec::new();
    }
    let is_inf = p == f64::INFINITY;
    let inv_p = 1.0 / p;
    // p == 1 (Manhattan): `Σ|Δ|` with NO per-element `powf(1.0)` and NO final
    // `powf(1.0)` — bit-exact (`pow(x, 1.0) == x`), one fewer libm `pow` per
    // element. frankentorch-cdist-p1.
    let is_one = p == 1.0;
    // Row i owns the (n-1-i) outputs for j in (i+1)..n; build per-row then flatten
    // (the concat is O(out_len), negligible vs the O(n^2·m) reduction).
    let rows: Vec<Vec<f64>> = (0..n - 1)
        .into_par_iter()
        .map(|i| {
            let i_base = i * m;
            let mut row = Vec::with_capacity(n - 1 - i);
            for j in (i + 1)..n {
                let j_base = j * m;
                let mut dist = 0.0f64;
                if is_inf {
                    for k in 0..m {
                        let diff = (input[i_base + k] - input[j_base + k]).abs();
                        if diff > dist {
                            dist = diff;
                        }
                    }
                } else if is_one {
                    for k in 0..m {
                        dist += (input[i_base + k] - input[j_base + k]).abs();
                    }
                } else {
                    for k in 0..m {
                        let diff = (input[i_base + k] - input[j_base + k]).abs();
                        dist += diff.powf(p);
                    }
                    dist = dist.powf(inv_p);
                }
                row.push(dist);
            }
            row
        })
        .collect();
    let mut result = Vec::with_capacity(out_len);
    for row in &rows {
        result.extend_from_slice(row);
    }
    result
}

/// Fused Supervised-Contrastive (SupCon) loss forward (f64), no-grad.
///
/// Replaces the ~16-op op-graph (L2-normalize + [N,N] cosine gram + two
/// materialised [N,N] label-mask leaves + masked log-sum-exp + masked
/// positive-mean + reduction) with: one L2-normalize pass, ONE gram GEMM
/// (`gemm::dgemm_bt`, the only heavy compute, kept), and a single fused pass over
/// the gram rows that computes the masked log-sum-exp denominator and the
/// positive-mean numerator inline from `labels` — no [N,N] sim/mask intermediates,
/// no tape. Each step mirrors the op-graph's exact arithmetic and reduction order
/// (sequential per-`d` normalize sum, `tensor_logsumexp`'s max-subtract pass,
/// sequential per-`j` masked sum, sequential per-`i` final sum), so the scalar
/// loss matches the op-graph to f64 round-off.
///
/// `labels[i]` is the class of row `i`; `pos_count_safe[i] = max(|P(i)|, 1)`;
/// `valid[i]` is 1.0 iff row `i` has >=1 positive; `count` is the number of valid
/// anchors (caller guarantees `count > 0`). Returns the scalar SupCon loss.
#[allow(clippy::too_many_arguments)]
#[must_use]
pub fn supcon_loss_forward_f64(
    embeddings: &[f64],
    labels: &[i64],
    pos_count_safe: &[f64],
    valid: &[f64],
    count: usize,
    temperature: f64,
    n: usize,
    d: usize,
) -> f64 {
    // 1. L2-normalize each row (sumsq sequential over d, then clamp >= 1e-12).
    let mut normalized = vec![0.0f64; n * d];
    normalized
        .par_chunks_mut(d)
        .enumerate()
        .for_each(|(i, out)| {
            let base = i * d;
            let mut sumsq = 0.0f64;
            for k in 0..d {
                let v = embeddings[base + k];
                sumsq += v * v;
            }
            let norm = sumsq.sqrt().max(1e-12);
            for (k, slot) in out.iter_mut().enumerate() {
                *slot = embeddings[base + k] / norm;
            }
        });

    // 2. Cosine gram [N,N] = normalized @ normalized^T (the one heavy GEMM).
    let mut gram = vec![0.0f64; n * n];
    gemm::dgemm_bt(n, d, n, &normalized, &normalized, &mut gram);

    // 3. Fused per-row masked log-sum-exp denominator + positive-mean numerator,
    //    streaming the gram row once. `inv_temp` scales the cosine to logits; the
    //    diagonal is pushed to -1e30 (matches `sim + diag_mask`) so it underflows
    //    out of the denominator. Parallel over rows; the final sum over i is done
    //    sequentially afterwards to preserve the op-graph's reduction order.
    let inv_temp = 1.0 / temperature;
    let masked_term: Vec<f64> = (0..n)
        .into_par_iter()
        .map(|i| {
            let row = i * n;
            // Denominator: max-subtract pass exactly like tensor_logsumexp.
            let mut max_val = f64::NEG_INFINITY;
            for j in 0..n {
                let mut s = gram[row + j] * inv_temp;
                if j == i {
                    s -= 1e30;
                }
                if s > max_val {
                    max_val = s;
                }
            }
            let mut sum_exp = 0.0f64;
            for j in 0..n {
                let mut s = gram[row + j] * inv_temp;
                if j == i {
                    s -= 1e30;
                }
                sum_exp += (s - max_val).exp();
            }
            let log_denom = max_val + sum_exp.ln();
            // Numerator: sum of sim over same-label j != i (masked-sum order j=0..n).
            let mut num = 0.0f64;
            for j in 0..n {
                if i != j && labels[i] == labels[j] {
                    num += gram[row + j] * inv_temp;
                }
            }
            let mean_pos = num / pos_count_safe[i];
            (mean_pos - log_denom) * valid[i]
        })
        .collect();

    let mut summed = 0.0f64;
    for &t in &masked_term {
        summed += t;
    }
    #[allow(clippy::cast_precision_loss)]
    {
        summed * (-1.0 / count as f64)
    }
}

/// Fused max-pool3d forward (f64): per output, the max over its `kd×kh×kw`
/// window of `[batch, ch, id, ih, iw]`. Parallel over `(batch,ch)` volumes.
#[allow(clippy::too_many_arguments)]
#[must_use]
pub fn max_pool3d_forward_f64(
    input: &[f64],
    batch: usize,
    ch: usize,
    id: usize,
    ih: usize,
    iw: usize,
    kd: usize,
    kh: usize,
    kw: usize,
    od: usize,
    oh: usize,
    ow: usize,
    sd: usize,
    sh: usize,
    sw: usize,
) -> Vec<f64> {
    let mut out = vec![0.0f64; batch * ch * od * oh * ow];
    out.par_chunks_mut(od * oh * ow)
        .enumerate()
        .for_each(|(plane, orow)| {
            let ibase = plane * id * ih * iw;
            for oz in 0..od {
                let bd = oz * sd;
                for oy in 0..oh {
                    let bh = oy * sh;
                    for ox in 0..ow {
                        let bw = ox * sw;
                        let mut m = f64::NEG_INFINITY;
                        for kdd in 0..kd {
                            let dz = ibase + (bd + kdd) * ih * iw;
                            for kr in 0..kh {
                                let irow = dz + (bh + kr) * iw + bw;
                                for kc in 0..kw {
                                    let v = input[irow + kc];
                                    if v > m {
                                        m = v;
                                    }
                                }
                            }
                        }
                        orow[(oz * oh + oy) * ow + ox] = m;
                    }
                }
            }
        });
    out
}

/// Fused max-pool3d forward plus first-argmax sidecar (f64). The sidecar stores
/// the plane-local input offset as `f64`, matching the 1-D/2-D pool context
/// convention while avoiding a full saved input in autograd.
#[allow(clippy::too_many_arguments)]
#[must_use]
pub fn max_pool3d_forward_with_indices_f64(
    input: &[f64],
    batch: usize,
    ch: usize,
    id: usize,
    ih: usize,
    iw: usize,
    kd: usize,
    kh: usize,
    kw: usize,
    od: usize,
    oh: usize,
    ow: usize,
    sd: usize,
    sh: usize,
    sw: usize,
) -> (Vec<f64>, Vec<f64>) {
    let mut out = vec![0.0f64; batch * ch * od * oh * ow];
    let mut arg_offsets = vec![0.0f64; batch * ch * od * oh * ow];
    out.par_chunks_mut(od * oh * ow)
        .zip(arg_offsets.par_chunks_mut(od * oh * ow))
        .enumerate()
        .for_each(|(plane, (orow, arow))| {
            let ibase = plane * id * ih * iw;
            for oz in 0..od {
                let bd = oz * sd;
                for oy in 0..oh {
                    let bh = oy * sh;
                    for ox in 0..ow {
                        let bw = ox * sw;
                        let mut m = f64::NEG_INFINITY;
                        let mut arg = 0usize;
                        for kdd in 0..kd {
                            let dz = (bd + kdd) * ih * iw;
                            for kr in 0..kh {
                                let loc = dz + (bh + kr) * iw + bw;
                                for kc in 0..kw {
                                    let v = input[ibase + loc + kc];
                                    if v > m {
                                        m = v;
                                        arg = loc + kc;
                                    }
                                }
                            }
                        }
                        let oidx = (oz * oh + oy) * ow + ox;
                        orow[oidx] = m;
                        arow[oidx] = arg as f64;
                    }
                }
            }
        });
    (out, arg_offsets)
}

#[allow(clippy::too_many_arguments)]
fn max_pool3d_sum_pairwise_leaf_with_indices_f64(
    input: &[f64],
    arg_offsets: &mut [f64],
    start: usize,
    id: usize,
    ih: usize,
    iw: usize,
    kd: usize,
    kh: usize,
    kw: usize,
    od: usize,
    oh: usize,
    ow: usize,
    sd: usize,
    sh: usize,
    sw: usize,
) -> f64 {
    if kd == 2 && kh == 2 && kw == 2 && sd == 2 && sh == 2 && sw == 2 {
        return max_pool3d_sum_2x2s2_leaf_with_indices_f64(
            input,
            arg_offsets,
            start,
            id,
            ih,
            iw,
            od,
            oh,
            ow,
        );
    }

    let out_plane_len = od * oh * ow;
    let out_row_len = oh * ow;
    let mut plane = start / out_plane_len;
    let mut rem = start - plane * out_plane_len;
    let mut oz = rem / out_row_len;
    rem -= oz * out_row_len;
    let mut oy = rem / ow;
    let mut ox = rem - oy * ow;
    let mut sum = 0.0_f64;
    for arg_slot in arg_offsets {
        let ibase = plane * id * ih * iw;
        let bd = oz * sd;
        let bh = oy * sh;
        let bw = ox * sw;
        let mut max_value = f64::NEG_INFINITY;
        let mut arg = 0usize;
        for kdd in 0..kd {
            let dz = (bd + kdd) * ih * iw;
            for kr in 0..kh {
                let loc = dz + (bh + kr) * iw + bw;
                for kc in 0..kw {
                    let candidate_arg = loc + kc;
                    let v = input[ibase + candidate_arg];
                    if v > max_value {
                        max_value = v;
                        arg = candidate_arg;
                    }
                }
            }
        }
        *arg_slot = arg as f64;
        sum += max_value;

        ox += 1;
        if ox == ow {
            ox = 0;
            oy += 1;
            if oy == oh {
                oy = 0;
                oz += 1;
                if oz == od {
                    oz = 0;
                    plane += 1;
                }
            }
        }
    }
    sum
}

#[allow(clippy::too_many_arguments)]
fn max_pool3d_sum_2x2s2_leaf_with_indices_f64(
    input: &[f64],
    arg_offsets: &mut [f64],
    start: usize,
    id: usize,
    ih: usize,
    iw: usize,
    od: usize,
    oh: usize,
    ow: usize,
) -> f64 {
    let plane_len = id * ih * iw;
    let out_plane_len = od * oh * ow;
    let out_row_len = oh * ow;
    let depth_stride = ih * iw;
    let mut plane = start / out_plane_len;
    let mut rem = start - plane * out_plane_len;
    let mut oz = rem / out_row_len;
    rem -= oz * out_row_len;
    let mut oy = rem / ow;
    let mut ox = rem - oy * ow;
    let mut sum = 0.0_f64;
    for arg_slot in arg_offsets {
        let input_plane_base = plane * plane_len;
        let z0 = (oz * 2) * depth_stride;
        let z1 = z0 + depth_stride;
        let row00 = z0 + (oy * 2) * iw;
        let row01 = row00 + iw;
        let row10 = z1 + (oy * 2) * iw;
        let row11 = row10 + iw;
        let x0 = ox * 2;
        let loc000 = row00 + x0;
        let loc001 = loc000 + 1;
        let loc010 = row01 + x0;
        let loc011 = loc010 + 1;
        let loc100 = row10 + x0;
        let loc101 = loc100 + 1;
        let loc110 = row11 + x0;
        let loc111 = loc110 + 1;

        let mut max_value = input[input_plane_base + loc000];
        let mut arg = loc000;
        let candidate = input[input_plane_base + loc001];
        if candidate > max_value {
            max_value = candidate;
            arg = loc001;
        }
        let candidate = input[input_plane_base + loc010];
        if candidate > max_value {
            max_value = candidate;
            arg = loc010;
        }
        let candidate = input[input_plane_base + loc011];
        if candidate > max_value {
            max_value = candidate;
            arg = loc011;
        }
        let candidate = input[input_plane_base + loc100];
        if candidate > max_value {
            max_value = candidate;
            arg = loc100;
        }
        let candidate = input[input_plane_base + loc101];
        if candidate > max_value {
            max_value = candidate;
            arg = loc101;
        }
        let candidate = input[input_plane_base + loc110];
        if candidate > max_value {
            max_value = candidate;
            arg = loc110;
        }
        let candidate = input[input_plane_base + loc111];
        if candidate > max_value {
            max_value = candidate;
            arg = loc111;
        }

        *arg_slot = arg as f64;
        sum += max_value;

        ox += 1;
        if ox == ow {
            ox = 0;
            oy += 1;
            if oy == oh {
                oy = 0;
                oz += 1;
                if oz == od {
                    oz = 0;
                    plane += 1;
                }
            }
        }
    }
    sum
}

#[allow(clippy::too_many_arguments)]
fn max_pool3d_sum_pairwise_range_with_indices_f64(
    input: &[f64],
    arg_offsets: &mut [f64],
    start: usize,
    id: usize,
    ih: usize,
    iw: usize,
    kd: usize,
    kh: usize,
    kw: usize,
    od: usize,
    oh: usize,
    ow: usize,
    sd: usize,
    sh: usize,
    sw: usize,
) -> f64 {
    const BLOCK: usize = 128;
    if arg_offsets.len() <= BLOCK {
        return max_pool3d_sum_pairwise_leaf_with_indices_f64(
            input,
            arg_offsets,
            start,
            id,
            ih,
            iw,
            kd,
            kh,
            kw,
            od,
            oh,
            ow,
            sd,
            sh,
            sw,
        );
    }
    let mid = arg_offsets.len() / 2;
    let (left, right) = arg_offsets.split_at_mut(mid);
    max_pool3d_sum_pairwise_range_with_indices_f64(
        input, left, start, id, ih, iw, kd, kh, kw, od, oh, ow, sd, sh, sw,
    ) + max_pool3d_sum_pairwise_range_with_indices_f64(
        input,
        right,
        start + mid,
        id,
        ih,
        iw,
        kd,
        kh,
        kw,
        od,
        oh,
        ow,
        sd,
        sh,
        sw,
    )
}

#[allow(clippy::too_many_arguments)]
fn max_pool3d_sum_pairwise_range_with_indices_f64_par(
    input: &[f64],
    arg_offsets: &mut [f64],
    start: usize,
    id: usize,
    ih: usize,
    iw: usize,
    kd: usize,
    kh: usize,
    kw: usize,
    od: usize,
    oh: usize,
    ow: usize,
    sd: usize,
    sh: usize,
    sw: usize,
) -> f64 {
    const PAR_BLOCK: usize = 1 << 14;
    if arg_offsets.len() <= PAR_BLOCK {
        return max_pool3d_sum_pairwise_range_with_indices_f64(
            input,
            arg_offsets,
            start,
            id,
            ih,
            iw,
            kd,
            kh,
            kw,
            od,
            oh,
            ow,
            sd,
            sh,
            sw,
        );
    }
    let mid = arg_offsets.len() / 2;
    let (left, right) = arg_offsets.split_at_mut(mid);
    let (ls, rs) = rayon::join(
        || {
            max_pool3d_sum_pairwise_range_with_indices_f64_par(
                input, left, start, id, ih, iw, kd, kh, kw, od, oh, ow, sd, sh, sw,
            )
        },
        || {
            max_pool3d_sum_pairwise_range_with_indices_f64_par(
                input,
                right,
                start + mid,
                id,
                ih,
                iw,
                kd,
                kh,
                kw,
                od,
                oh,
                ow,
                sd,
                sh,
                sw,
            )
        },
    );
    ls + rs
}

/// Fused `sum(max_pool3d(...))` forward plus first-argmax sidecar (f64).
///
/// This avoids materializing the pooled output while preserving the exact
/// pairwise reduction tree used by `tensor_sum(max_pool3d(...))`.
#[allow(clippy::too_many_arguments)]
#[must_use]
pub fn max_pool3d_sum_forward_with_indices_f64(
    input: &[f64],
    batch: usize,
    ch: usize,
    id: usize,
    ih: usize,
    iw: usize,
    kd: usize,
    kh: usize,
    kw: usize,
    od: usize,
    oh: usize,
    ow: usize,
    sd: usize,
    sh: usize,
    sw: usize,
) -> (f64, Vec<f64>) {
    const FUSED_POOL_SUM_PARALLEL_THRESHOLD: usize = 1 << 13;
    let len = batch * ch * od * oh * ow;
    let mut arg_offsets = vec![0.0_f64; len];
    let sum = if len >= FUSED_POOL_SUM_PARALLEL_THRESHOLD {
        max_pool3d_sum_pairwise_range_with_indices_f64_par(
            input,
            &mut arg_offsets,
            0,
            id,
            ih,
            iw,
            kd,
            kh,
            kw,
            od,
            oh,
            ow,
            sd,
            sh,
            sw,
        )
    } else {
        max_pool3d_sum_pairwise_range_with_indices_f64(
            input,
            &mut arg_offsets,
            0,
            id,
            ih,
            iw,
            kd,
            kh,
            kw,
            od,
            oh,
            ow,
            sd,
            sh,
            sw,
        )
    };
    (sum, arg_offsets)
}

/// f32 mirror of [`max_pool3d_forward_f64`]: per output, the max over its
/// `kd×kh×kw` window, one pass parallel over `(batch,ch)` volumes. Replaces the
/// f32 op-graph (narrow/amax/cat) the f32 no-grad path fell through to.
#[allow(clippy::too_many_arguments)]
#[must_use]
pub fn max_pool3d_forward_f32(
    input: &[f32],
    batch: usize,
    ch: usize,
    id: usize,
    ih: usize,
    iw: usize,
    kd: usize,
    kh: usize,
    kw: usize,
    od: usize,
    oh: usize,
    ow: usize,
    sd: usize,
    sh: usize,
    sw: usize,
) -> Vec<f32> {
    let mut out = vec![0.0f32; batch * ch * od * oh * ow];
    out.par_chunks_mut(od * oh * ow)
        .enumerate()
        .for_each(|(plane, orow)| {
            let ibase = plane * id * ih * iw;
            for oz in 0..od {
                let bd = oz * sd;
                for oy in 0..oh {
                    let bh = oy * sh;
                    for ox in 0..ow {
                        let bw = ox * sw;
                        let mut m = f32::NEG_INFINITY;
                        for kdd in 0..kd {
                            let dz = ibase + (bd + kdd) * ih * iw;
                            for kr in 0..kh {
                                let irow = dz + (bh + kr) * iw + bw;
                                for kc in 0..kw {
                                    let v = input[irow + kc];
                                    if v > m {
                                        m = v;
                                    }
                                }
                            }
                        }
                        orow[(oz * oh + oy) * ow + ox] = m;
                    }
                }
            }
        });
    out
}

/// Backward of [`max_pool3d_forward_f64`]: routes each output gradient to its
/// window's (first) argmax. Parallel over `(batch,ch)`; overlaps accumulate.
#[allow(clippy::too_many_arguments)]
#[must_use]
fn max_pool3d_backward_2x2s2_f64(
    dout: &[f64],
    input: &[f64],
    batch: usize,
    ch: usize,
    id: usize,
    ih: usize,
    iw: usize,
    od: usize,
    oh: usize,
    ow: usize,
) -> Vec<f64> {
    let plane_len = id * ih * iw;
    let out_plane_len = od * oh * ow;
    let depth_stride = ih * iw;
    let mut din = vec![0.0f64; batch * ch * plane_len];
    din.par_chunks_mut(plane_len)
        .enumerate()
        .for_each(|(plane, drow)| {
            let input_plane = &input[plane * plane_len..plane * plane_len + plane_len];
            let dout_plane = &dout[plane * out_plane_len..plane * out_plane_len + out_plane_len];
            for oz in 0..od {
                let z0 = (oz * 2) * depth_stride;
                let z1 = z0 + depth_stride;
                for oy in 0..oh {
                    let row00 = z0 + (oy * 2) * iw;
                    let row01 = row00 + iw;
                    let row10 = z1 + (oy * 2) * iw;
                    let row11 = row10 + iw;
                    for ox in 0..ow {
                        let x0 = ox * 2;
                        let loc000 = row00 + x0;
                        let loc001 = loc000 + 1;
                        let loc010 = row01 + x0;
                        let loc011 = loc010 + 1;
                        let loc100 = row10 + x0;
                        let loc101 = loc100 + 1;
                        let loc110 = row11 + x0;
                        let loc111 = loc110 + 1;
                        let mut m = f64::NEG_INFINITY;
                        let mut arg = loc000;

                        let candidate = input_plane[loc000];
                        if candidate > m {
                            m = candidate;
                            arg = loc000;
                        }
                        let candidate = input_plane[loc001];
                        if candidate > m {
                            m = candidate;
                            arg = loc001;
                        }
                        let candidate = input_plane[loc010];
                        if candidate > m {
                            m = candidate;
                            arg = loc010;
                        }
                        let candidate = input_plane[loc011];
                        if candidate > m {
                            m = candidate;
                            arg = loc011;
                        }
                        let candidate = input_plane[loc100];
                        if candidate > m {
                            m = candidate;
                            arg = loc100;
                        }
                        let candidate = input_plane[loc101];
                        if candidate > m {
                            m = candidate;
                            arg = loc101;
                        }
                        let candidate = input_plane[loc110];
                        if candidate > m {
                            m = candidate;
                            arg = loc110;
                        }
                        let candidate = input_plane[loc111];
                        if candidate > m {
                            arg = loc111;
                        }

                        drow[arg] += dout_plane[(oz * oh + oy) * ow + ox];
                    }
                }
            }
        });
    din
}

/// Backward of [`max_pool3d_forward_with_indices_f64`]: scatter each output
/// gradient to the saved first-argmax offset. Parallel and accumulation order
/// match [`max_pool3d_backward_f64`].
#[allow(clippy::too_many_arguments)]
#[must_use]
pub fn max_pool3d_backward_from_indices_f64(
    dout: &[f64],
    arg_offsets: &[f64],
    batch: usize,
    ch: usize,
    id: usize,
    ih: usize,
    iw: usize,
    od: usize,
    oh: usize,
    ow: usize,
) -> Vec<f64> {
    let plane_len = id * ih * iw;
    let out_plane_len = od * oh * ow;
    let mut din = vec![0.0f64; batch * ch * plane_len];
    din.par_chunks_mut(plane_len)
        .enumerate()
        .for_each(|(plane, drow)| {
            let dbase = plane * out_plane_len;
            for oz in 0..od {
                for oy in 0..oh {
                    for ox in 0..ow {
                        let oidx = dbase + (oz * oh + oy) * ow + ox;
                        let arg = arg_offsets[oidx] as usize;
                        drow[arg] += dout[oidx];
                    }
                }
            }
        });
    din
}

/// Scalar-loss backward for [`max_pool3d_sum_forward_with_indices_f64`].
///
/// Equivalent to scattering a dense `dout` filled with `upstream`, but avoids
/// allocating that output-gradient buffer for `loss = sum(pool)`.
#[allow(clippy::too_many_arguments)]
#[must_use]
pub fn max_pool3d_backward_from_indices_scalar_f64(
    upstream: f64,
    arg_offsets: &[f64],
    batch: usize,
    ch: usize,
    id: usize,
    ih: usize,
    iw: usize,
    od: usize,
    oh: usize,
    ow: usize,
) -> Vec<f64> {
    let plane_len = id * ih * iw;
    let out_plane_len = od * oh * ow;
    let mut din = vec![0.0f64; batch * ch * plane_len];
    din.par_chunks_mut(plane_len)
        .enumerate()
        .for_each(|(plane, drow)| {
            let dbase = plane * out_plane_len;
            let plane_offsets = &arg_offsets[dbase..dbase + out_plane_len];
            for &arg_offset in plane_offsets {
                let arg = arg_offset as usize;
                drow[arg] += upstream;
            }
        });
    din
}

#[allow(clippy::too_many_arguments)]
#[must_use]
pub fn max_pool3d_backward_f64(
    dout: &[f64],
    input: &[f64],
    batch: usize,
    ch: usize,
    id: usize,
    ih: usize,
    iw: usize,
    kd: usize,
    kh: usize,
    kw: usize,
    od: usize,
    oh: usize,
    ow: usize,
    sd: usize,
    sh: usize,
    sw: usize,
) -> Vec<f64> {
    if kd == 2 && kh == 2 && kw == 2 && sd == 2 && sh == 2 && sw == 2 {
        return max_pool3d_backward_2x2s2_f64(
            dout, input, batch, ch, id, ih, iw, od, oh, ow,
        );
    }

    let mut din = vec![0.0f64; batch * ch * id * ih * iw];
    din.par_chunks_mut(id * ih * iw)
        .enumerate()
        .for_each(|(plane, drow)| {
            let dbase = plane * od * oh * ow;
            for oz in 0..od {
                let bd = oz * sd;
                for oy in 0..oh {
                    let bh = oy * sh;
                    for ox in 0..ow {
                        let bw = ox * sw;
                        let mut m = f64::NEG_INFINITY;
                        let mut arg = 0usize;
                        for kdd in 0..kd {
                            let dz = (bd + kdd) * ih * iw;
                            for kr in 0..kh {
                                let loc = dz + (bh + kr) * iw + bw;
                                for kc in 0..kw {
                                    let v = input[plane * id * ih * iw + loc + kc];
                                    if v > m {
                                        m = v;
                                        arg = loc + kc;
                                    }
                                }
                            }
                        }
                        drow[arg] += dout[dbase + (oz * oh + oy) * ow + ox];
                    }
                }
            }
        });
    din
}

/// Fused avg-pool2d forward (f64) over a PADDED `[batch, ch, ph, pw]` input.
/// Per output: sum over its (clamped) `kh×kw` window divided by the divisor —
/// `count_include_pad` ? window size : in-bounds (non-pad) element count. Padded
/// zeros sum to 0 so the sum is identical either way; only the divisor differs.
/// `ceil_mode` is handled by the window clamp (`row_end = min(start+kh, ph)`).
#[allow(clippy::too_many_arguments)]
#[must_use]
pub fn avg_pool2d_forward_f64(
    padded: &[f64],
    batch: usize,
    ch: usize,
    ph: usize,
    pw: usize,
    kh: usize,
    kw: usize,
    oh: usize,
    ow: usize,
    sh: usize,
    sw: usize,
    pad_h: usize,
    pad_w: usize,
    ih: usize,
    iw: usize,
    count_include_pad: bool,
) -> Vec<f64> {
    if kh == 2
        && kw == 2
        && sh == 2
        && sw == 2
        && pad_h == 0
        && pad_w == 0
        && count_include_pad
        && ph == ih
        && pw == iw
        && oh == ih / 2
        && ow == iw / 2
    {
        return avg_pool2d_forward_2x2s2_f64(padded, batch, ch, ih, iw, oh, ow);
    }
    let mut out = vec![0.0f64; batch * ch * oh * ow];
    out.par_chunks_mut(oh * ow)
        .enumerate()
        .for_each(|(plane, orow)| {
            let pbase = plane * ph * pw;
            for oy in 0..oh {
                let rs = oy * sh;
                let re = (rs + kh).min(ph);
                let vrlen = re.min(pad_h + ih).saturating_sub(rs.max(pad_h));
                for ox in 0..ow {
                    let cs = ox * sw;
                    let ce = (cs + kw).min(pw);
                    let vclen = ce.min(pad_w + iw).saturating_sub(cs.max(pad_w));
                    let mut sum = 0.0f64;
                    for r in rs..re {
                        let irow = pbase + r * pw;
                        for c in cs..ce {
                            sum += padded[irow + c];
                        }
                    }
                    let div = if count_include_pad {
                        ((re - rs) * (ce - cs)) as f64
                    } else {
                        (vrlen * vclen) as f64
                    };
                    orow[oy * ow + ox] = sum / div;
                }
            }
        });
    out
}

fn avg_pool2d_forward_2x2s2_f64(
    input: &[f64],
    batch: usize,
    ch: usize,
    ih: usize,
    iw: usize,
    oh: usize,
    ow: usize,
) -> Vec<f64> {
    let mut out = vec![0.0f64; batch * ch * oh * ow];
    out.par_chunks_mut(oh * ow)
        .enumerate()
        .for_each(|(plane, orow)| {
            let ibase = plane * ih * iw;
            for oy in 0..oh {
                let r0 = (oy * 2) * iw;
                let r1 = r0 + iw;
                for ox in 0..ow {
                    let c0 = ox * 2;
                    let v00 = input[ibase + r0 + c0];
                    let v01 = input[ibase + r0 + c0 + 1];
                    let v10 = input[ibase + r1 + c0];
                    let v11 = input[ibase + r1 + c0 + 1];
                    orow[oy * ow + ox] = (((v00 + v01) + v10) + v11) / 4.0;
                }
            }
        });
    out
}

/// f32 mirror of [`avg_pool2d_forward_f64`]: one windowed-mean pass over the
/// padded input, parallel over `(batch,ch)` planes. Replaces the f32 op-graph
/// (narrow/sum/div/cat) the f32 no-grad path fell through to.
