impl FrancisShadowAudit {
    fn new(n: usize) -> Self {
        Self {
            profile: EigFrancisProfile::new(n),
            active_sweep: None,
            sweeps_checked: 0,
            sweep_mismatches: 0,
        }
    }

    fn replay_sweep(sweep: &FrancisShadowSweep) -> Vec<f64> {
        const TILE: usize = 16;
        let n = sweep.n;
        let mut scratch = sweep.h_before.clone();
        for step in &sweep.steps {
            if let Some(col) = step.subdiag_col {
                scratch[step.k * n + col] = step.subdiag_value;
            }
            let mut block_start = step.k;
            while block_start < step.row_end {
                let block_end = (block_start + TILE).min(step.row_end);
                for j in block_start..block_end {
                    let mut p2 = scratch[step.k * n + j] + step.q_s * scratch[(step.k + 1) * n + j];
                    if step.notlast {
                        p2 += step.r_s * scratch[(step.k + 2) * n + j];
                        scratch[(step.k + 2) * n + j] -= p2 * step.zr;
                    }
                    scratch[(step.k + 1) * n + j] -= p2 * step.yr;
                    scratch[step.k * n + j] -= p2 * step.xr;
                }
                block_start = block_end;
            }
            let mut col_block_start = step.col_start;
            while col_block_start <= step.jmax {
                let col_block_end = (col_block_start + TILE).min(step.jmax + 1);
                for i in col_block_start..col_block_end {
                    let mut p2 =
                        step.xr * scratch[i * n + step.k] + step.yr * scratch[i * n + (step.k + 1)];
                    if step.notlast {
                        p2 += step.zr * scratch[i * n + (step.k + 2)];
                        scratch[i * n + (step.k + 2)] -= p2 * step.r_s;
                    }
                    scratch[i * n + (step.k + 1)] -= p2 * step.q_s;
                    scratch[i * n + step.k] -= p2;
                }
                col_block_start = col_block_end;
            }
        }
        scratch
    }
}

impl FrancisTraceSink for FrancisShadowAudit {
    const ENABLED: bool = true;

    fn reset(&mut self, n: usize) {
        *self = Self::new(n);
    }

    fn observe_active_window(&mut self, active_first: usize, active_last: usize) {
        self.profile
            .observe_active_window(active_first, active_last);
    }

    fn record_one_by_one_deflation(&mut self) {
        self.profile.record_one_by_one_deflation();
    }

    fn record_two_by_two_deflation(&mut self) {
        self.profile.record_two_by_two_deflation();
    }

    fn record_fallback_non_convergence(&mut self, max_total_exhausted: bool) {
        self.profile
            .record_fallback_non_convergence(max_total_exhausted);
    }

    fn record_sweep(&mut self) {
        self.profile.record_sweep();
    }

    fn record_shift(&mut self, sample: EigFrancisShiftSample) {
        self.profile.record_shift(sample);
    }

    fn record_selected_m(&mut self, m: usize) {
        self.profile.record_selected_m(m);
    }

    fn record_shadow_sweep_start(
        &mut self,
        h: &[f64],
        n: usize,
        _m: usize,
        _en: usize,
        _want_vectors: bool,
    ) {
        self.active_sweep = Some(FrancisShadowSweep {
            h_before: h.to_vec(),
            n,
            steps: Vec::new(),
        });
    }

    fn record_shadow_bulge_step(&mut self, step: FrancisBulgeStep) {
        if let Some(sweep) = self.active_sweep.as_mut() {
            sweep.steps.push(step);
        }
    }

    fn record_shadow_sweep_end(&mut self, h: &[f64]) {
        if let Some(sweep) = self.active_sweep.take() {
            self.sweeps_checked += 1;
            let replayed = Self::replay_sweep(&sweep);
            if !f64_slices_bit_equal(&replayed, h) {
                self.sweep_mismatches += 1;
            }
        }
    }
}

fn f64_slices_bit_equal(lhs: &[f64], rhs: &[f64]) -> bool {
    lhs.len() == rhs.len()
        && lhs
            .iter()
            .zip(rhs)
            .all(|(&left, &right)| left.to_bits() == right.to_bits())
}

fn eig_francis_shift_sample_bit_equal(
    lhs: &EigFrancisShiftSample,
    rhs: &EigFrancisShiftSample,
) -> bool {
    lhs.active_first == rhs.active_first
        && lhs.active_last == rhs.active_last
        && lhs.iteration_in_window == rhs.iteration_in_window
        && lhs.accumulated_shift.to_bits() == rhs.accumulated_shift.to_bits()
        && lhs.x.to_bits() == rhs.x.to_bits()
        && lhs.y.to_bits() == rhs.y.to_bits()
        && lhs.w.to_bits() == rhs.w.to_bits()
        && lhs.exceptional == rhs.exceptional
}

fn eig_francis_profiles_bit_equal(lhs: &EigFrancisProfile, rhs: &EigFrancisProfile) -> bool {
    lhs.n == rhs.n
        && lhs.total_sweeps == rhs.total_sweeps
        && lhs.one_by_one_deflations == rhs.one_by_one_deflations
        && lhs.two_by_two_deflations == rhs.two_by_two_deflations
        && lhs.fallback_deflations == rhs.fallback_deflations
        && lhs.max_total_exhaustions == rhs.max_total_exhaustions
        && lhs.exceptional_shifts == rhs.exceptional_shifts
        && lhs.max_active_window_width == rhs.max_active_window_width
        && lhs.active_windows == rhs.active_windows
        && lhs.selected_m == rhs.selected_m
        && lhs.shift_samples_truncated == rhs.shift_samples_truncated
        && lhs.shift_samples.len() == rhs.shift_samples.len()
        && lhs
            .shift_samples
            .iter()
            .zip(&rhs.shift_samples)
            .all(|(left, right)| eig_francis_shift_sample_bit_equal(left, right))
}

fn eig_initial_q_acc(n: usize, want_vectors: bool) -> Vec<f64> {
    if !want_vectors {
        return Vec::new();
    }
    let mut q_acc = vec![0.0f64; n * n];
    for i in 0..n {
        q_acc[i * n + i] = 1.0;
    }
    q_acc
}

fn eig_impl(data: &[f64], meta: &TensorMeta, want_vectors: bool) -> Result<EigResult, KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 || shape[0] != shape[1] {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![2],
        });
    }
    let n = shape[0];
    if n == 0 {
        return Ok(EigResult {
            eigenvalues: Vec::new(),
            eigenvectors: Vec::new(),
            n: 0,
        });
    }

    let offset = meta.storage_offset();

    // Copy matrix to working storage
    let mut h = vec![0.0f64; n * n];
    for i in 0..n {
        for j in 0..n {
            h[i * n + j] = data[offset + i * n + j];
        }
    }

    // Initialize Q only for eigenvector-producing paths. The values-only
    // Francis/Hessenberg code guards every Q update behind `want_vectors`.
    let mut q_acc = eig_initial_q_acc(n, want_vectors);

    // Step 1: Reduce to upper Hessenberg form H = Q^T A Q.
    // Large n uses the compact-WY BLOCKED reduction (BLAS-3 GEMM trailing, ~2x;
    // the Hessenberg dominates eigvals at ~74%); small n keeps the per-reflector
    // scalar sweep (no panel/GEMM overhead, byte-identical). frankentorch-9y5bi.
    if n >= 128 {
        hessenberg_reduce_blocked(&mut h, &mut q_acc, n, want_vectors);
    } else {
        for k in 0..(n.saturating_sub(2)) {
            // Compute Householder vector for column k below diagonal
            let mut col_norm_sq = 0.0;
            for i in (k + 1)..n {
                col_norm_sq += h[i * n + k] * h[i * n + k];
            }
            if col_norm_sq < 1e-30 {
                continue;
            }
            let col_norm = col_norm_sq.sqrt();
            let sign = if h[(k + 1) * n + k] >= 0.0 { 1.0 } else { -1.0 };
            let v0 = h[(k + 1) * n + k] + sign * col_norm;
            let mut v = vec![0.0f64; n - k - 1];
            v[0] = v0;
            for i in 1..(n - k - 1) {
                v[i] = h[(k + 2 + i - 1) * n + k];
            }
            let v_norm_sq: f64 = v.iter().map(|x| x * x).sum();
            if v_norm_sq < 1e-30 {
                continue;
            }

            // Apply H = I - 2vv^T/|v|^2 to H from left and right. The reflector only
            // spans rows/cols (k+1):, so each row update is independent and
            // row-contiguous — parallelized BIT-EXACTLY (each row keeps the scalar
            // path's per-row dot/scale expression and arithmetic order). The big
            // Hessenberg O(n^3) phase of the non-symmetric eig (frankentorch-l9xod).
            let m_sub = n - k - 1;
            let par = n >= 64;

            // Left multiply. For eigvals-only, columns before k are outside the
            // active Hessenberg band and are never read by the QR phase; skipping
            // them preserves the exact scalar arithmetic for every live slot. Full
            // eig keeps the legacy full-column update so the vector path is unchanged.
            // Precompute per-column scale = 2*(v^T H)[j]/|v|^2 from the UNMODIFIED H in
            // the same i-order as the scalar dot (bit-exact), then row-parallel update:
            // row (k+1+i) only needs scale[j] and v[i].
            // Each column j's dot v^T H[(k+1):, j] is independent and reads the
            // UNMODIFIED `h` (mutated only by the row update below), so this sweep —
            // the serial O(n^2)-per-step companion to the already row-parallel update,
            // i.e. the remaining Amdahl tail of the Hessenberg phase — parallelizes
            // BIT-EXACTLY: each slot keeps the scalar path's i-order dot (l9xod).
            let left_start = if want_vectors { 0 } else { k };
            let mut left_scale = vec![0.0f64; n - left_start];
            let col_scale = |(j_rel, slot): (usize, &mut f64)| {
                let j = left_start + j_rel;
                let mut dot = 0.0;
                for i in 0..m_sub {
                    dot += v[i] * h[(k + 1 + i) * n + j];
                }
                *slot = 2.0 * dot / v_norm_sq;
            };
            if par {
                left_scale.par_iter_mut().enumerate().for_each(col_scale);
            } else {
                left_scale.iter_mut().enumerate().for_each(col_scale);
            }
            {
                let rows = &mut h[(k + 1) * n..];
                let upd = |(i, row): (usize, &mut [f64])| {
                    let vi = v[i];
                    for j in left_start..n {
                        row[j] -= left_scale[j - left_start] * vi;
                    }
                };
                if par {
                    rows.par_chunks_mut(n).enumerate().for_each(upd);
                } else {
                    rows.chunks_mut(n).enumerate().for_each(upd);
                }
            }

            // Right multiply: H[:, (k+1):] -= 2 * (H[:, (k+1):] @ v) @ v^T / |v|^2.
            {
                let upd = |row: &mut [f64]| {
                    let mut dot = 0.0;
                    for j in 0..m_sub {
                        dot += row[k + 1 + j] * v[j];
                    }
                    let scale = 2.0 * dot / v_norm_sq;
                    for j in 0..m_sub {
                        row[k + 1 + j] -= scale * v[j];
                    }
                };
                if par {
                    h.par_chunks_mut(n).for_each(upd);
                } else {
                    h.chunks_mut(n).for_each(upd);
                }
            }

            // Accumulate Q: Q[:, (k+1):] -= 2 * (Q[:, (k+1):] @ v) @ v^T / |v|^2.
            // Pure eigenvector work — skip when only eigenvalues are requested.
            if want_vectors {
                let upd = |row: &mut [f64]| {
                    let mut dot = 0.0;
                    for j in 0..m_sub {
                        dot += row[k + 1 + j] * v[j];
                    }
                    let scale = 2.0 * dot / v_norm_sq;
                    for j in 0..m_sub {
                        row[k + 1 + j] -= scale * v[j];
                    }
                };
                if par {
                    q_acc.par_chunks_mut(n).for_each(upd);
                } else {
                    q_acc.chunks_mut(n).for_each(upd);
                }
            }
        }
    }

    // Step 2: Francis double-shift implicit QR (extracted to `eig_francis_schur`
    // so the multishift + AED rewrite can recursively Schur-factor sub-windows).
    let eigenvalues = eig_francis_schur(&mut h, &mut q_acc, n, want_vectors);
    if want_vectors {
        eig_backsub_eigenvectors(&mut h, &mut q_acc, &eigenvalues, n);
    }
    Ok(EigResult {
        eigenvalues,
        eigenvectors: q_acc,
        n,
    })
}

/// Francis double-shift implicit QR (EISPACK `hqr2` lineage) on the upper-
/// Hessenberg `h`, accumulating the orthogonal transforms into `q_acc` (real-
/// Schur vectors) when `want_vectors`. The IMPLICIT DOUBLE SHIFT converges
/// trailing 2x2 blocks with COMPLEX-conjugate eigenvalues in real arithmetic
/// (a single-Wilkinson-shift Givens QR could not — frankentorch-09zy). Returns
/// the eigenvalues as interleaved (re, im) pairs (length `2*n`). Extracted
/// verbatim from `eig_impl` (BIT-EXACT, golden-anchored) so the small-bulge
/// multishift + AED rewrite (frankentorch-fql10) can recursively factor a
/// Hessenberg sub-window for aggressive early deflation. frankentorch-j4fgz.
fn eig_francis_schur(h: &mut [f64], q_acc: &mut [f64], n: usize, want_vectors: bool) -> Vec<f64> {
    let mut trace = FrancisTraceDisabled;
    if want_vectors {
        eig_francis_schur_traced::<true, _>(h, q_acc, n, &mut trace)
    } else {
        eig_francis_schur_traced::<false, _>(h, q_acc, n, &mut trace)
    }
}

fn eig_francis_schur_traced<const WANT_VECTORS: bool, T: FrancisTraceSink>(
    h: &mut [f64],
    q_acc: &mut [f64],
    n: usize,
    trace: &mut T,
) -> Vec<f64> {
    if T::ENABLED {
        trace.reset(n);
    }
    let mut eigenvalues = vec![0.0f64; 2 * n];
    {
        // Frobenius-ish norm over the Hessenberg band for convergence tests.
        let mut anorm = 0.0f64;
        for i in 0..n {
            for j in i.saturating_sub(1)..n {
                anorm += h[i * n + j].abs();
            }
        }
        let eps = f64::EPSILON;
        let mut t = 0.0f64; // accumulated shift
        let mut en: isize = n as isize - 1; // bottom of the active block (0-based)
        // Reusable buffer of one bulge-chase sweep's Givens rotations. The Schur
        // vectors q_acc are updated ONCE per sweep (parallel over independent
        // rows) by replaying these, instead of dispatching a tiny per-k
        // par_chunks_mut — dropping the rayon dispatch count from O(n^2) to O(n).
        // Bit-exact vs the serial per-k update: each row replays the identical
        // rotation sequence in k-order, and rows never interact (l9xod).
        // WHOLE-stream deferral: collect EVERY q_acc operation (bulge reflectors +
        // 2x2-standardization Givens) across the entire Francis QR, then replay onto
        // q_acc in ONE row-parallel pass below. One rayon dispatch instead of
        // O(sweeps), so it wins even at n=256 where the old per-sweep replay
        // regressed (hence was gated to n>=512). frankentorch-9y5bi.
        let mut sweep_rot: Vec<EigQaccOp> = Vec::new();
        let mut total_iter = 0usize;
        let max_total = 60 * n + 100;

        while en >= 0 {
            let en_u = en as usize;
            let mut its = 0usize;
            loop {
                // Find `l`: top of the unreduced block ending at `en`.
                let mut l = en_u;
                while l > 0 {
                    let mut s = h[(l - 1) * n + (l - 1)].abs() + h[l * n + l].abs();
                    if s == 0.0 {
                        s = anorm;
                    }
                    if h[l * n + (l - 1)].abs() <= eps * s {
                        break;
                    }
                    l -= 1;
                }
                if T::ENABLED {
                    trace.observe_active_window(l, en_u);
                }

                let mut x = h[en_u * n + en_u];
                if l == en_u {
                    // One real root.
                    h[en_u * n + en_u] = x + t;
                    eigenvalues[2 * en_u] = x + t;
                    eigenvalues[2 * en_u + 1] = 0.0;
                    if T::ENABLED {
                        trace.record_one_by_one_deflation();
                    }
                    en -= 1;
                    break;
                }

                let na = en_u - 1;
                let mut y = h[na * n + na];
                let mut w = h[en_u * n + na] * h[na * n + en_u];
                if l == na {
                    // Two roots (real pair or complex-conjugate pair).
                    let pp = (y - x) / 2.0;
                    let q = pp * pp + w;
                    let zz = q.abs().sqrt();
                    let xx = x + t;
                    h[en_u * n + en_u] = xx;
                    h[na * n + na] = y + t;
                    if q >= 0.0 {
                        let zz2 = if pp >= 0.0 { pp + zz } else { pp - zz };
                        let r1 = xx + zz2;
                        let r2 = if zz2 != 0.0 { xx - w / zz2 } else { r1 };
                        eigenvalues[2 * na] = r1;
                        eigenvalues[2 * na + 1] = 0.0;
                        eigenvalues[2 * en_u] = r2;
                        eigenvalues[2 * en_u + 1] = 0.0;
                        if WANT_VECTORS {
                            // Standardize the 2x2 (Givens rotation) for the Schur vectors.
                            let xr = h[en_u * n + na];
                            let s = xr.abs() + zz2.abs();
                            if s != 0.0 {
                                let mut cp = xr / s;
                                let mut cq = zz2 / s;
                                let r = (cp * cp + cq * cq).sqrt();
                                cp /= r;
                                cq /= r;
                                for j in na..n {
                                    let z1 = h[na * n + j];
                                    h[na * n + j] = cq * z1 + cp * h[en_u * n + j];
                                    h[en_u * n + j] = cq * h[en_u * n + j] - cp * z1;
                                }
                                for i in 0..=en_u {
                                    let z1 = h[i * n + na];
                                    h[i * n + na] = cq * z1 + cp * h[i * n + en_u];
                                    h[i * n + en_u] = cq * h[i * n + en_u] - cp * z1;
                                }
                                // Defer the q_acc 2x2 Givens into the ordered stream
                                // (columns na, en_u==na+1), replayed below in order.
                                sweep_rot.push(EigQaccOp::Givens(na, cq, cp));
                            }
                        }
                    } else {
                        eigenvalues[2 * na] = xx + pp;
                        eigenvalues[2 * na + 1] = zz;
                        eigenvalues[2 * en_u] = xx + pp;
                        eigenvalues[2 * en_u + 1] = -zz;
                    }
                    if T::ENABLED {
                        trace.record_two_by_two_deflation();
                    }
                    en -= 2;
                    break;
                }

                if its >= 30 || total_iter >= max_total {
                    // No convergence — record the diagonal estimate and deflate.
                    let max_total_exhausted = total_iter >= max_total;
                    h[en_u * n + en_u] = x + t;
                    eigenvalues[2 * en_u] = x + t;
                    eigenvalues[2 * en_u + 1] = 0.0;
                    if T::ENABLED {
                        trace.record_fallback_non_convergence(max_total_exhausted);
                    }
                    en -= 1;
                    break;
                }

                // Form the (double) shift.
                let iteration_in_window = its;
                let mut exceptional_shift = false;
                if its == 10 || its == 20 {
                    // Exceptional shift to break stagnation.
                    t += x;
                    for i in 0..=en_u {
                        h[i * n + i] -= x;
                    }
                    let s = h[en_u * n + na].abs() + h[na * n + (na - 1)].abs();
                    x = 0.75 * s;
                    y = x;
                    w = -0.4375 * s * s;
                    exceptional_shift = true;
                }
                its += 1;
                total_iter += 1;
                if T::ENABLED {
                    trace.record_sweep();
                    trace.record_shift(EigFrancisShiftSample {
                        active_first: l,
                        active_last: en_u,
                        iteration_in_window,
                        accumulated_shift: t,
                        x,
                        y,
                        w,
                        exceptional: exceptional_shift,
                    });
                }

                // Find `m`: two consecutive small sub-diagonals (start of the bulge).
                let mut m = en_u - 2;
                let (mut p_s, mut q_s, mut r_s);
                loop {
                    let zz = h[m * n + m];
                    let r = x - zz;
                    let s = y - zz;
                    p_s = (r * s - w) / h[(m + 1) * n + m] + h[m * n + (m + 1)];
                    q_s = h[(m + 1) * n + (m + 1)] - zz - r - s;
                    r_s = h[(m + 2) * n + (m + 1)];
                    let norm = p_s.abs() + q_s.abs() + r_s.abs();
                    p_s /= norm;
                    q_s /= norm;
                    r_s /= norm;
                    if m == l {
                        break;
                    }
                    let test1 = p_s.abs()
                        * (h[(m - 1) * n + (m - 1)].abs()
                            + zz.abs()
                            + h[(m + 1) * n + (m + 1)].abs());
                    let test2 = h[m * n + (m - 1)].abs() * (q_s.abs() + r_s.abs());
                    if test2 <= eps * test1 {
                        break;
                    }
                    m -= 1;
                }
                if T::ENABLED {
                    trace.record_selected_m(m);
                }
                // Clear the sub-sub-diagonal spike left of the bulge.
                for i in (m + 2)..=en_u {
                    h[i * n + (i - 2)] = 0.0;
                    if i != m + 2 {
                        h[i * n + (i - 3)] = 0.0;
                    }
                }
                if T::ENABLED {
                    trace.record_shadow_sweep_start(h, n, m, en_u, WANT_VECTORS);
                }

                // Double QR (bulge-chase) step on rows [m, en].
                let mut k = m;
                while k <= na {
                    let notlast = k != na;
                    if k != m {
                        p_s = h[k * n + (k - 1)];
                        q_s = h[(k + 1) * n + (k - 1)];
                        r_s = if notlast {
                            h[(k + 2) * n + (k - 1)]
                        } else {
                            0.0
                        };
                        x = p_s.abs() + q_s.abs() + r_s.abs();
                        if x == 0.0 {
                            k += 1;
                            continue;
                        }
                        p_s /= x;
                        q_s /= x;
                        r_s /= x;
                    }
                    let s = (p_s * p_s + q_s * q_s + r_s * r_s).sqrt().copysign(p_s);
                    if k == m {
                        if l != m {
                            h[k * n + (k - 1)] = -h[k * n + (k - 1)];
                        }
                    } else {
                        h[k * n + (k - 1)] = -s * x;
                    }
                    p_s += s;
                    let xr = p_s / s;
                    let yr = q_s / s;
                    let zr = r_s / s;
                    q_s /= p_s;
                    r_s /= p_s;
                    // Row modification. For eigenvectors (real-Schur form) the
                    // whole row [k, n) must be transformed. For eigenvalues only,
                    // columns (en, n) belong to already-deflated trailing blocks
                    // that never feed back into the active block's recurrence nor
                    // the diagonal the eigenvalues are read from, so restricting to
                    // [k, en] is BIT-EXACT for the eigenvalues and skips the
                    // growing trailing band as the matrix deflates (hqr range, not
                    // hqr2). frankentorch-eig-eigvals-rowrange.
                    let row_end = if WANT_VECTORS { n } else { en_u + 1 };
                    if T::ENABLED {
                        let subdiag_col = if k == m {
                            if l != m { Some(k - 1) } else { None }
                        } else {
                            Some(k - 1)
                        };
                        let subdiag_value = subdiag_col.map_or(0.0, |col| h[k * n + col]);
                        trace.record_shadow_bulge_step(FrancisBulgeStep {
                            k,
                            notlast,
                            subdiag_col,
                            subdiag_value,
                            xr,
                            yr,
                            zr,
                            q_s,
                            r_s,
                            col_start: if WANT_VECTORS { 0 } else { l },
                            row_end,
                            jmax: (k + 3).min(en_u),
                        });
                    }
                    for j in k..row_end {
                        let mut p2 = h[k * n + j] + q_s * h[(k + 1) * n + j];
                        if notlast {
                            p2 += r_s * h[(k + 2) * n + j];
                            h[(k + 2) * n + j] -= p2 * zr;
                        }
                        h[(k + 1) * n + j] -= p2 * yr;
                        h[k * n + j] -= p2 * xr;
                    }
                    // Column modification. Values-only Schur keeps this inside the active
                    // unreduced window; full eig still updates all rows for Schur vectors.
                    let jmax = (k + 3).min(en_u);
                    let col_start = if WANT_VECTORS { 0 } else { l };
                    for i in col_start..=jmax {
                        let mut p2 = xr * h[i * n + k] + yr * h[i * n + (k + 1)];
                        if notlast {
                            p2 += zr * h[i * n + (k + 2)];
                            h[i * n + (k + 2)] -= p2 * r_s;
                        }
                        h[i * n + (k + 1)] -= p2 * q_s;
                        h[i * n + k] -= p2;
                    }
                    if WANT_VECTORS {
                        // Defer EVERY rotation across the WHOLE Francis-QR run; the
                        // q_acc Schur vectors are a pure sink (the bulge chase reads
                        // /writes only `h`), so the complete ordered rotation stream
                        // is replayed onto q_acc in ONE parallel pass after the chase.
                        // Whole-stream (not per-sweep) deferral drops the rayon
                        // dispatch count from O(sweeps) to 1, so it WINS even at the
                        // n=256 sizes where the per-sweep variant regressed. Bit-exact
                        // vs the inline per-k update (same rotations, same per-row
                        // k-order). frankentorch-9y5bi (SVD whole-stream lesson).
                        sweep_rot.push(EigQaccOp::Bulge(k, xr, yr, zr, q_s, r_s, notlast));
                    }
                    k += 1;
                }
                if T::ENABLED {
                    trace.record_shadow_sweep_end(h);
                }
                // (rotations accumulated into `sweep_rot`; replayed once below.)
            }
        }
        // Replay the COMPLETE ordered rotation stream onto q_acc in ONE pass —
        // each row independently applies every rotation in k-order, bit-identical
        // to the inline per-k update but parallel over rows with a single rayon
        // dispatch (vs O(sweeps)). frankentorch-9y5bi.
        if WANT_VECTORS && !sweep_rot.is_empty() {
            const EIG_QACC_PAR_WORK: u64 = 1 << 14;
            // Row-BLOCKED, op-outer replay (frankentorch-x53r3): the whole-stream
            // q_acc replay re-streamed the ops Vec from RAM once PER ROW
            // (`par_chunks_mut(n)`) — bandwidth-bound at large n. Grouping a small
            // cache-resident block of rows reads the stream once per BLOCK while the
            // block stays in L1/L2. Bit-identical to the per-row replay (same ops,
            // same order per row). Same lever as the eigh/svd QL replay block.
            const EIG_QACC_REPLAY_BLOCK_ROWS: usize = 8;
            let work = (n as u64) * (sweep_rot.len() as u64);
            let rots: &[EigQaccOp] = &sweep_rot;
            let apply_block = |block: &mut [f64]| {
                let nrows = block.len() / n;
                for op in rots {
                    match *op {
                        EigQaccOp::Bulge(kk, xr, yr, zr, q_s, r_s, notlast) => {
                            for r in 0..nrows {
                                let row = &mut block[r * n..r * n + n];
                                let mut p2 = xr * row[kk] + yr * row[kk + 1];
                                if notlast {
                                    p2 += zr * row[kk + 2];
                                    row[kk + 2] -= p2 * r_s;
                                }
                                row[kk + 1] -= p2 * q_s;
                                row[kk] -= p2;
                            }
                        }
                        EigQaccOp::Givens(col, cq, cp) => {
                            for r in 0..nrows {
                                let row = &mut block[r * n..r * n + n];
                                let z1 = row[col];
                                row[col] = cq * z1 + cp * row[col + 1];
                                row[col + 1] = cq * row[col + 1] - cp * z1;
                            }
                        }
                    }
                }
            };
            if work >= EIG_QACC_PAR_WORK {
                q_acc
                    .par_chunks_mut(EIG_QACC_REPLAY_BLOCK_ROWS * n)
                    .for_each(apply_block);
            } else {
                apply_block(q_acc);
            }
        }
    }
    eigenvalues
}

/// Complex division `(ar + ai·i) / (br + bi·i)` (EISPACK `cdiv`).
fn eig_cdiv(ar: f64, ai: f64, br: f64, bi: f64) -> (f64, f64) {
    if br.abs() >= bi.abs() {
        let r = bi / br;
        let d = br + bi * r;
        ((ar + ai * r) / d, (ai - ar * r) / d)
    } else {
        let r = br / bi;
        let d = br * r + bi;
        ((ar * r + ai) / d, (ai * r - ar) / d)
    }
}

/// Eigenvector back-substitution for a real upper-quasi-triangular Schur form
/// `h` (EISPACK `hqr2` lineage). Computes eigenvectors of `h` into its own
/// columns, then overwrites `z` (the accumulated Schur vectors) with the
/// eigenvectors of the original matrix `z·(vectors of h)`. `evals` holds the
/// interleaved (re, im) eigenvalues. Complex eigenvalue pairs are stored as a
/// (real-part column, imag-part column) pair.
fn eig_backsub_eigenvectors(h: &mut [f64], z: &mut [f64], evals: &[f64], n: usize) {
    if n == 0 {
        return;
    }
    let mut norm = 0.0f64;
    for i in 0..n {
        for j in i..n {
            norm += h[i * n + j].abs();
        }
    }
    if norm == 0.0 {
        return;
    }
    let eps = f64::EPSILON;
    let wr = |i: usize| evals[2 * i];
    let wi = |i: usize| evals[2 * i + 1];

    let mut en_i: isize = n as isize - 1;
    while en_i >= 0 {
        let en = en_i as usize;
        let p = wr(en);
        let q = wi(en);
        if q == 0.0 {
            // Real eigenvalue.
            let mut m = en;
            h[en * n + en] = 1.0;
            if en > 0 {
                let (mut zz_c, mut s_c) = (0.0f64, 0.0f64);
                let mut i_i = en as isize - 1;
                while i_i >= 0 {
                    let i = i_i as usize;
                    let w = h[i * n + i] - p;
                    let mut r = 0.0;
                    for j in m..=en {
                        r += h[i * n + j] * h[j * n + en];
                    }
                    if wi(i) < 0.0 {
                        zz_c = w;
                        s_c = r;
                        i_i -= 1;
                        continue;
                    }
                    m = i;
                    if wi(i) == 0.0 {
                        let mut t = w;
                        if t == 0.0 {
                            t = eps * norm;
                        }
                        h[i * n + en] = -r / t;
                    } else {
                        let x = h[i * n + (i + 1)];
                        let y = h[(i + 1) * n + i];
                        let q2 = (wr(i) - p) * (wr(i) - p) + wi(i) * wi(i);
                        let t = (x * s_c - zz_c * r) / q2;
                        h[i * n + en] = t;
                        if x.abs() > zz_c.abs() {
                            h[(i + 1) * n + en] = (-r - w * t) / x;
                        } else {
                            h[(i + 1) * n + en] = (-s_c - y * t) / zz_c;
                        }
                    }
                    i_i -= 1;
                }
            }
            en_i -= 1;
        } else if q < 0.0 {
            // Complex pair: `en` is the conjugate (wi<0) root, `na = en-1` its mate.
            let na = en - 1;
            let mut m = na;
            if h[en * n + na].abs() > h[na * n + en].abs() {
                h[na * n + na] = q / h[en * n + na];
                h[na * n + en] = -(h[en * n + en] - p) / h[en * n + na];
            } else {
                let (cr, ci) = eig_cdiv(0.0, -h[na * n + en], h[na * n + na] - p, q);
                h[na * n + na] = cr;
                h[na * n + en] = ci;
            }
            h[en * n + na] = 0.0;
            h[en * n + en] = 1.0;
            if na > 0 {
                let (mut zz_c, mut r_c, mut s_c) = (0.0f64, 0.0f64, 0.0f64);
                let mut i_i = na as isize - 1;
                while i_i >= 0 {
                    let i = i_i as usize;
                    let w = h[i * n + i] - p;
                    let mut ra = 0.0;
                    let mut sa = 0.0;
                    for j in m..=en {
                        ra += h[i * n + j] * h[j * n + na];
                        sa += h[i * n + j] * h[j * n + en];
                    }
                    if wi(i) < 0.0 {
                        zz_c = w;
                        r_c = ra;
                        s_c = sa;
                        i_i -= 1;
                        continue;
                    }
                    m = i;
                    if wi(i) == 0.0 {
                        let (cr, ci) = eig_cdiv(-ra, -sa, w, q);
                        h[i * n + na] = cr;
                        h[i * n + en] = ci;
                    } else {
                        let x = h[i * n + (i + 1)];
                        let y = h[(i + 1) * n + i];
                        let mut vr = (wr(i) - p) * (wr(i) - p) + wi(i) * wi(i) - q * q;
                        let vi = (wr(i) - p) * 2.0 * q;
                        if vr == 0.0 && vi == 0.0 {
                            vr = eps * norm * (w.abs() + q.abs() + x.abs() + y.abs() + zz_c.abs());
                        }
                        let (cr, ci) = eig_cdiv(
                            x * r_c - zz_c * ra + q * sa,
                            x * s_c - zz_c * sa - q * ra,
                            vr,
                            vi,
                        );
                        h[i * n + na] = cr;
                        h[i * n + en] = ci;
                        if x.abs() > zz_c.abs() + q.abs() {
                            h[(i + 1) * n + na] = (-ra - w * h[i * n + na] + q * h[i * n + en]) / x;
                            h[(i + 1) * n + en] = (-sa - w * h[i * n + en] - q * h[i * n + na]) / x;
                        } else {
                            let (cr2, ci2) = eig_cdiv(
                                -r_c - y * h[i * n + na],
                                -s_c - y * h[i * n + en],
                                zz_c,
                                q,
                            );
                            h[(i + 1) * n + na] = cr2;
                            h[(i + 1) * n + en] = ci2;
                        }
                    }
                    i_i -= 1;
                }
            }
            en_i -= 2;
        } else {
            // q > 0: upper root of a pair, handled with its conjugate below it.
            en_i -= 1;
        }
    }

    // Eigenvectors of the original matrix: Z := Z · U where U is the upper triangle
    // of `h` (Z[:, j] = Z[:, 0..=j] · h[0..=j, j]). Large n routes this O(n^3/2)
    // triangular matmul through the cache-blocked parallel gemm::dgemm (BLAS-3);
    // small n keeps the byte-identical serial sweep. The GEMM reassociates the
    // k-sum, so the eigenvectors match the serial path only to TOLERANCE (they are
    // non-unique up to scale anyway). frankentorch-9y5bi.
    if n >= 128 {
        let mut u = vec![0.0f64; n * n];
        for k in 0..n {
            let row = k * n;
            u[row + k..row + n].copy_from_slice(&h[row + k..row + n]);
        }
        let mut znew = vec![0.0f64; n * n];
        gemm::dgemm(n, n, n, z, &u, &mut znew);
        z.copy_from_slice(&znew);
    } else {
        for j in (0..n).rev() {
            for i in 0..n {
                let mut acc = 0.0;
                for k in 0..=j {
                    acc += z[i * n + k] * h[k * n + j];
                }
                z[i * n + j] = acc;
            }
        }
    }
}

#[doc(hidden)]
pub fn eig_francis_profile_f64(
    data: &[f64],
    meta: &TensorMeta,
    want_vectors: bool,
) -> Result<EigFrancisProfileResult, KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 || shape[0] != shape[1] {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![2],
        });
    }
    let n = shape[0];

    let offset = meta.storage_offset();
    let mut h = vec![0.0f64; n * n];
    for i in 0..n {
        for j in 0..n {
            h[i * n + j] = data[offset + i * n + j];
        }
    }

    let mut q_acc = eig_initial_q_acc(n, want_vectors);

    if n >= 128 {
        hessenberg_reduce_blocked(&mut h, &mut q_acc, n, want_vectors);
    } else {
        for k in 0..(n.saturating_sub(2)) {
            let mut col_norm_sq = 0.0;
            for i in (k + 1)..n {
                col_norm_sq += h[i * n + k] * h[i * n + k];
            }
            if col_norm_sq < 1e-30 {
                continue;
            }
            let col_norm = col_norm_sq.sqrt();
            let sign = if h[(k + 1) * n + k] >= 0.0 { 1.0 } else { -1.0 };
            let v0 = h[(k + 1) * n + k] + sign * col_norm;
            let mut v = vec![0.0f64; n - k - 1];
            v[0] = v0;
            for i in 1..(n - k - 1) {
                v[i] = h[(k + 2 + i - 1) * n + k];
            }
            let v_norm_sq: f64 = v.iter().map(|x| x * x).sum();
            if v_norm_sq < 1e-30 {
                continue;
            }

            let m_sub = n - k - 1;
            let par = n >= 64;
            let left_start = if want_vectors { 0 } else { k };
            let mut left_scale = vec![0.0f64; n - left_start];
            let col_scale = |(j_rel, slot): (usize, &mut f64)| {
                let j = left_start + j_rel;
                let mut dot = 0.0;
                for i in 0..m_sub {
                    dot += v[i] * h[(k + 1 + i) * n + j];
                }
                *slot = 2.0 * dot / v_norm_sq;
            };
            if par {
                left_scale.par_iter_mut().enumerate().for_each(col_scale);
            } else {
                left_scale.iter_mut().enumerate().for_each(col_scale);
            }
            {
                let rows = &mut h[(k + 1) * n..];
                let upd = |(i, row): (usize, &mut [f64])| {
                    let vi = v[i];
                    for j in left_start..n {
                        row[j] -= left_scale[j - left_start] * vi;
                    }
                };
                if par {
                    rows.par_chunks_mut(n).enumerate().for_each(upd);
                } else {
                    rows.chunks_mut(n).enumerate().for_each(upd);
                }
            }

            {
                let upd = |row: &mut [f64]| {
                    let mut dot = 0.0;
                    for j in 0..m_sub {
                        dot += row[k + 1 + j] * v[j];
                    }
                    let scale = 2.0 * dot / v_norm_sq;
                    for j in 0..m_sub {
                        row[k + 1 + j] -= scale * v[j];
                    }
                };
                if par {
                    h.par_chunks_mut(n).for_each(upd);
                } else {
                    h.chunks_mut(n).for_each(upd);
                }
            }

            if want_vectors {
                let upd = |row: &mut [f64]| {
                    let mut dot = 0.0;
                    for j in 0..m_sub {
                        dot += row[k + 1 + j] * v[j];
                    }
                    let scale = 2.0 * dot / v_norm_sq;
                    for j in 0..m_sub {
                        row[k + 1 + j] -= scale * v[j];
                    }
                };
                if par {
                    q_acc.par_chunks_mut(n).for_each(upd);
                } else {
                    q_acc.chunks_mut(n).for_each(upd);
                }
            }
        }
    }

    let mut profile = EigFrancisProfile::new(n);
    let eigenvalues = if want_vectors {
        eig_francis_schur_traced::<true, _>(&mut h, &mut q_acc, n, &mut profile)
    } else {
        eig_francis_schur_traced::<false, _>(&mut h, &mut q_acc, n, &mut profile)
    };
    if want_vectors {
        eig_backsub_eigenvectors(&mut h, &mut q_acc, &eigenvalues, n);
    }

    Ok(EigFrancisProfileResult {
        result: EigResult {
            eigenvalues,
            eigenvectors: q_acc,
            n,
        },
        profile,
    })
}

#[doc(hidden)]
pub fn eig_francis_shadow_profile_f64(
    data: &[f64],
    meta: &TensorMeta,
    want_vectors: bool,
) -> Result<EigFrancisShadowProfileResult, KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 || shape[0] != shape[1] {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![2],
        });
    }
    let n = shape[0];

    let offset = meta.storage_offset();
    let mut h = vec![0.0f64; n * n];
    for i in 0..n {
        for j in 0..n {
            h[i * n + j] = data[offset + i * n + j];
        }
    }

    let mut q_acc = vec![0.0f64; n * n];
    for i in 0..n {
        q_acc[i * n + i] = 1.0;
    }

    if n >= 128 {
        hessenberg_reduce_blocked(&mut h, &mut q_acc, n, want_vectors);
    } else {
        for k in 0..(n.saturating_sub(2)) {
            let mut col_norm_sq = 0.0;
            for i in (k + 1)..n {
                col_norm_sq += h[i * n + k] * h[i * n + k];
            }
            if col_norm_sq < 1e-30 {
                continue;
            }
            let col_norm = col_norm_sq.sqrt();
            let sign = if h[(k + 1) * n + k] >= 0.0 { 1.0 } else { -1.0 };
            let v0 = h[(k + 1) * n + k] + sign * col_norm;
            let mut v = vec![0.0f64; n - k - 1];
            v[0] = v0;
            for i in 1..(n - k - 1) {
                v[i] = h[(k + 2 + i - 1) * n + k];
            }
            let v_norm_sq: f64 = v.iter().map(|x| x * x).sum();
            if v_norm_sq < 1e-30 {
                continue;
            }

            let m_sub = n - k - 1;
            let par = n >= 64;
            let left_start = if want_vectors { 0 } else { k };
            let mut left_scale = vec![0.0f64; n - left_start];
            let col_scale = |(j_rel, slot): (usize, &mut f64)| {
                let j = left_start + j_rel;
                let mut dot = 0.0;
                for i in 0..m_sub {
                    dot += v[i] * h[(k + 1 + i) * n + j];
                }
                *slot = 2.0 * dot / v_norm_sq;
            };
            if par {
                left_scale.par_iter_mut().enumerate().for_each(col_scale);
            } else {
                left_scale.iter_mut().enumerate().for_each(col_scale);
            }
            {
                let rows = &mut h[(k + 1) * n..];
                let upd = |(i, row): (usize, &mut [f64])| {
                    let vi = v[i];
                    for j in left_start..n {
                        row[j] -= left_scale[j - left_start] * vi;
                    }
                };
                if par {
                    rows.par_chunks_mut(n).enumerate().for_each(upd);
                } else {
                    rows.chunks_mut(n).enumerate().for_each(upd);
                }
            }

            {
                let upd = |row: &mut [f64]| {
                    let mut dot = 0.0;
                    for j in 0..m_sub {
                        dot += row[k + 1 + j] * v[j];
                    }
                    let scale = 2.0 * dot / v_norm_sq;
                    for j in 0..m_sub {
                        row[k + 1 + j] -= scale * v[j];
                    }
                };
                if par {
                    h.par_chunks_mut(n).for_each(upd);
                } else {
                    h.chunks_mut(n).for_each(upd);
                }
            }

            if want_vectors {
                let upd = |row: &mut [f64]| {
                    let mut dot = 0.0;
                    for j in 0..m_sub {
                        dot += row[k + 1 + j] * v[j];
                    }
                    let scale = 2.0 * dot / v_norm_sq;
                    for j in 0..m_sub {
                        row[k + 1 + j] -= scale * v[j];
                    }
                };
                if par {
                    q_acc.par_chunks_mut(n).for_each(upd);
                } else {
                    q_acc.chunks_mut(n).for_each(upd);
                }
            }
        }
    }

    let mut scalar_h = h.clone();
    let mut scalar_q_acc = q_acc.clone();
    let mut shadow_h = h;
    let mut shadow_q_acc = q_acc;

    let mut scalar_profile = EigFrancisProfile::new(n);
    let scalar_eigenvalues = if want_vectors {
        eig_francis_schur_traced::<true, _>(
            &mut scalar_h,
            &mut scalar_q_acc,
            n,
            &mut scalar_profile,
        )
    } else {
        eig_francis_schur_traced::<false, _>(
            &mut scalar_h,
            &mut scalar_q_acc,
            n,
            &mut scalar_profile,
        )
    };
    let scalar_schur = scalar_h.clone();
    let scalar_q_schur = scalar_q_acc.clone();

    let mut shadow_audit = FrancisShadowAudit::new(n);
    let shadow_eigenvalues = if want_vectors {
        eig_francis_schur_traced::<true, _>(&mut shadow_h, &mut shadow_q_acc, n, &mut shadow_audit)
    } else {
        eig_francis_schur_traced::<false, _>(&mut shadow_h, &mut shadow_q_acc, n, &mut shadow_audit)
    };
    let shadow_profile = shadow_audit.profile.clone();
    let shadow_schur = shadow_h.clone();
    let shadow_q_schur = shadow_q_acc.clone();
    let shadow_sweeps_checked = shadow_audit.sweeps_checked;
    let shadow_sweep_mismatches = shadow_audit.sweep_mismatches;

    let profiles_match = eig_francis_profiles_bit_equal(&scalar_profile, &shadow_profile);
    let eigenvalues_match = f64_slices_bit_equal(&scalar_eigenvalues, &shadow_eigenvalues);
    let schur_form_match = f64_slices_bit_equal(&scalar_schur, &shadow_schur)
        && f64_slices_bit_equal(&scalar_q_schur, &shadow_q_schur);

    if want_vectors {
        eig_backsub_eigenvectors(&mut scalar_h, &mut scalar_q_acc, &scalar_eigenvalues, n);
        eig_backsub_eigenvectors(&mut shadow_h, &mut shadow_q_acc, &shadow_eigenvalues, n);
    }
    let eigenvectors_match = !want_vectors || f64_slices_bit_equal(&scalar_q_acc, &shadow_q_acc);

    Ok(EigFrancisShadowProfileResult {
        result: EigResult {
            eigenvalues: scalar_eigenvalues,
            eigenvectors: scalar_q_acc,
            n,
        },
        scalar_profile,
        shadow_profile,
        profiles_match,
        eigenvalues_match,
        schur_form_match,
        eigenvectors_match,
        shadow_sweeps_checked,
        shadow_sweep_mismatches,
    })
}

/// Batched general (non-symmetric) eigenvalues: input `[..., k, k]` -> `[B*2k]` row-major, each plane's
/// k complex eigenvalues as interleaved `[re, im]` pairs (the `[k, 2]` layout). Parallelizes the verified
/// 2-D [`eigvals_contiguous_f64`] (geev / Francis QR) over the batch. PyTorch loops LAPACK geev per plane
/// (157-484ms small k); FT parallel is ~12-14x faster. Bit-identical to looping the 2-D eigvals.
/// frankentorch-batched-eigh. (BlackThrush)
pub fn eigvals_batched_contiguous_f64(
    data: &[f64],
    meta: &TensorMeta,
) -> Result<Vec<f64>, KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    let nd = shape.len();
    if nd < 2 || shape[nd - 1] != shape[nd - 2] {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![nd],
        });
    }
    let k = shape[nd - 1];
    let bb: usize = shape[..nd - 2].iter().product();
    let plane = k * k;
    let out_plane = 2 * k;
    let offset = meta.storage_offset();
    let data = &data[offset..offset + bb * plane];
    let kmeta = TensorMeta::from_shape(vec![k, k], DType::F64, Device::Cpu);
    let mut out = vec![0.0f64; bb * out_plane];
    let first_err = std::sync::Mutex::new(None);
    out.par_chunks_mut(out_plane)
        .zip(data.par_chunks(plane))
        .for_each(|(o, pl)| match eigvals_contiguous_f64(pl, &kmeta) {
            Ok(w) => o.copy_from_slice(&w),
            Err(e) => {
                let mut g = first_err.lock().unwrap();
                if g.is_none() {
                    *g = Some(e);
                }
            }
        });
    if let Some(e) = first_err.into_inner().unwrap() {
        return Err(e);
    }
    Ok(out)
}

/// Compute just the eigenvalues of a general matrix (as complex pairs).
pub fn eigvals_contiguous_f64(data: &[f64], meta: &TensorMeta) -> Result<Vec<f64>, KernelError> {
    // Eigenvalues-only: skip the O(n^3) Schur-vector accumulation. The
    // eigenvalues are read from the quasi-triangular `h`, which does not depend
    // on `q_acc`, so they are bit-for-bit identical to
    // `eig_contiguous_f64(...).eigenvalues`.
    let result = eig_impl(data, meta, false)?;
    Ok(result.eigenvalues)
}

/// Result of SVD decomposition.
#[derive(Debug, Clone)]
pub struct SvdResult {
    /// Left singular vectors U in row-major order.
    pub u: Vec<f64>,
    /// Singular values (1D, sorted descending, non-negative).
    pub s: Vec<f64>,
    /// Right singular vectors Vh (V-hermitian/transpose) in row-major order.
    pub vh: Vec<f64>,
    /// Input rows.
    pub m: usize,
    /// Input columns.
    pub n: usize,
    /// k = min(m, n)
    pub k: usize,
}

/// A/B override for the SVD bidiagonal-QR replay row-block (frankentorch-x53r3).
/// `0` = production default (8). doc-hidden, NOT production dispatch — exists only
/// so a same-worker A/B can confirm the row-block win against block=1 (per-row).
static SVD_QR_REPLAY_BLOCK_OVERRIDE: std::sync::atomic::AtomicUsize =
    std::sync::atomic::AtomicUsize::new(0);
#[doc(hidden)]
pub fn set_svd_qr_replay_block_override(b: usize) {
    SVD_QR_REPLAY_BLOCK_OVERRIDE.store(b, std::sync::atomic::Ordering::Relaxed);
}
fn svd_qr_replay_block_rows() -> usize {
    match SVD_QR_REPLAY_BLOCK_OVERRIDE.load(std::sync::atomic::Ordering::Relaxed) {
        0 => 8,
        b => b,
    }
}

/// Compute the SVD of an (m x n) matrix: A = U @ diag(S) @ Vh.
///
/// Uses Golub-Kahan bidiagonalization followed by implicit QR shifts.
/// If `full_matrices` is true, U is (m x m) and Vh is (n x n).
/// If `full_matrices` is false (reduced), U is (m x k) and Vh is (k x n) where k = min(m,n).
/// Batched SVD: input `[..., m, n]` -> `(U [B*urows*ucols], S [B*min(m,n)], Vh [B*vrows*vcols])` where
/// (urows,ucols,vrows,vcols) = (m,m,n,n) if `full_matrices` else (m,kk,kk,n), kk=min(m,n). Parallelizes
/// the verified 2-D [`svd_contiguous_f64`] over the batch. PyTorch loops LAPACK gesdd per plane
/// (339-668ms small k); FT parallel is ~9-16x faster (the 189x scalar-SVD penalty is large-matrix-only;
/// for k<=16 the per-plane SVD is cheap). Bit-identical to looping the 2-D SVD. frankentorch-batched-eigh.
/// (BlackThrush)
pub fn svd_batched_contiguous_f64(
    data: &[f64],
    meta: &TensorMeta,
    full_matrices: bool,
) -> Result<(Vec<f64>, Vec<f64>, Vec<f64>), KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    let nd = shape.len();
    if nd < 2 {
        return Err(KernelError::InvalidDimension { dim: nd, ndim: 2 });
    }
    let m = shape[nd - 2];
    let n = shape[nd - 1];
    let kk = m.min(n);
    let (urows, ucols, vrows, vcols) = if full_matrices {
        (m, m, n, n)
    } else {
        (m, kk, kk, n)
    };
    let bb: usize = shape[..nd - 2].iter().product();
    let plane = m * n;
    let up = urows * ucols;
    let sp = kk;
    let vp = vrows * vcols;
    let offset = meta.storage_offset();
    let data = &data[offset..offset + bb * plane];
    let pmeta = TensorMeta::from_shape(vec![m, n], DType::F64, Device::Cpu);
    let mut out_u = vec![0.0f64; bb * up];
    let mut out_s = vec![0.0f64; bb * sp];
    let mut out_v = vec![0.0f64; bb * vp];
    let first_err = std::sync::Mutex::new(None);
    out_u
        .par_chunks_mut(up)
        .zip(out_s.par_chunks_mut(sp))
        .zip(out_v.par_chunks_mut(vp))
        .zip(data.par_chunks(plane))
        .for_each(|(((uc, sc), vc), pl)| {
            match svd_contiguous_f64(pl, &pmeta, full_matrices) {
                Ok(r) => {
                    uc.copy_from_slice(&r.u);
                    sc.copy_from_slice(&r.s);
                    vc.copy_from_slice(&r.vh);
                }
                Err(e) => {
                    let mut g = first_err.lock().unwrap();
                    if g.is_none() {
                        *g = Some(e);
                    }
                }
            }
        });
    if let Some(e) = first_err.into_inner().unwrap() {
        return Err(e);
    }
    Ok((out_u, out_s, out_v))
}

pub fn svd_contiguous_f64(
    data: &[f64],
    meta: &TensorMeta,
    full_matrices: bool,
) -> Result<SvdResult, KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![2],
        });
    }
    let m = shape[0];
    let n = shape[1];
    let k = m.min(n);
    let offset = meta.storage_offset();

    if m == 0 || n == 0 {
        let u_cols = if full_matrices { m } else { k };
        let vh_rows = if full_matrices { n } else { k };
        return Ok(SvdResult {
            u: vec![0.0; m * u_cols],
            s: Vec::new(),
            vh: vec![0.0; vh_rows * n],
            m,
            n,
            k,
        });
    }

    // Copy input matrix
    let mut a = vec![0.0f64; m * n];
    for i in 0..m {
        for j in 0..n {
            a[i * n + j] = data[offset + i * n + j];
        }
    }

    // One-sided Jacobi SVD for simplicity and numerical robustness
    // This works well for all matrix sizes and shapes

    if m >= n {
        svd_tall(&a, m, n, full_matrices)
    } else {
        // For wide matrices (m < n), compute SVD of A^T, then swap U/Vh
        let mut at = vec![0.0f64; n * m];
        for i in 0..m {
            for j in 0..n {
                at[j * m + i] = a[i * n + j];
            }
        }
        let result = svd_tall(&at, n, m, full_matrices)?;
        // SVD(A^T) = U_t @ diag(S) @ Vh_t
        // SVD(A) = Vh_t^T @ diag(S) @ U_t^T
        let u_rows = if full_matrices { m } else { k };
        let vh_cols = if full_matrices { n } else { k };
        // U for A = Vh_t^T: result.vh is (vh_t_rows x m), transpose to (m x vh_t_rows)
        let _vh_t_rows = if full_matrices { m } else { k };
        let mut u = vec![0.0f64; m * u_rows];
        for i in 0..m {
            for j in 0..u_rows {
                u[i * u_rows + j] = result.vh[j * m + i];
            }
        }
        // Vh for A = U_t^T: result.u is (n x u_t_cols), transpose to (u_t_cols x n)
        let u_t_cols = if full_matrices { n } else { k };
        let mut vh = vec![0.0f64; vh_cols * n];
        for i in 0..vh_cols {
            for j in 0..n {
                vh[i * n + j] = result.u[j * u_t_cols + i];
            }
        }
        Ok(SvdResult {
            u,
            s: result.s,
            vh,
            m,
            n,
            k,
        })
    }
}

/// `|a|` carrying the sign of `b` (Numerical-Recipes `SIGN`).
fn nr_sign(a: f64, b: f64) -> f64 {
    if b >= 0.0 { a.abs() } else { -a.abs() }
}

/// Golub-Reinsch SVD of a real `m x n` matrix with `m >= n`, row-major.
///
/// On input `a` is the matrix; on output `a` is overwritten with the (reduced,
/// m x n) left singular vectors U. Returns `(w, v)` where `w[0..n]` are the
/// non-negative singular values (unsorted, bidiagonal order) and `v` is the
/// `n x n` right singular vectors as columns, so `A = U diag(w) V^T`.
///
/// This is the classic Householder-bidiagonalization + implicit-shift QR
/// diagonalization of the bidiagonal form: it never forms `A^T A`, so it keeps
/// full singular-value/-vector accuracy (no condition-number squaring), unlike
/// the Gram-matrix shortcuts. O(m n^2) with a small constant. `pythag` is the
/// stable hypot already used by the eigensolver.
fn golub_reinsch_svd(
    a: &mut [f64],
    m: usize,
    n: usize,
) -> Result<(Vec<f64>, Vec<f64>), KernelError> {
    golub_reinsch_svd_impl(a, m, n, true)
}

fn golub_reinsch_svd_right_only(
    a: &mut [f64],
    m: usize,
    n: usize,
) -> Result<(Vec<f64>, Vec<f64>), KernelError> {
    golub_reinsch_svd_impl(a, m, n, false)
}

/// One deferred right-singular-vector (V) operation from the bidiagonal-QR
/// sweep: either a Givens rotation of adjacent columns `(j, j+1)` or a
/// convergence sign-flip of column `k`. The sweep's recurrence never reads V, so
/// the whole ordered stream is collected first and replayed row-parallel.
#[derive(Clone, Copy)]
enum SvdVOp {
    Rot(usize, f64, f64),
    Neg(usize),
}

fn golub_reinsch_svd_impl(
    a: &mut [f64],
    m: usize,
    n: usize,
    track_left: bool,
) -> Result<(Vec<f64>, Vec<f64>), KernelError> {
    let mut w = vec![0.0f64; n];
    let mut v = vec![0.0f64; n * n];
    let mut rv1 = vec![0.0f64; n];

    let mut g = 0.0f64;
    let mut scale = 0.0f64;
    let mut anorm = 0.0f64;

    // --- Householder reduction to bidiagonal form ---
    for i in 0..n {
        let l = i + 1;
        rv1[i] = scale * g;
        g = 0.0;
        let mut s = 0.0;
        scale = 0.0;
        if i < m {
            for k in i..m {
                scale += a[k * n + i].abs();
            }
            if scale != 0.0 {
                for k in i..m {
                    a[k * n + i] /= scale;
                    s += a[k * n + i] * a[k * n + i];
                }
                let f = a[i * n + i];
                g = -nr_sign(s.sqrt(), f);
                let h = f * g - s;
                a[i * n + i] = f - g;
                // Apply the reflector to the trailing columns [l,n). Each column is an
                // INDEPENDENT dot+axpy, so parallelise (bit-exact) when the work is
                // large enough; the gate falls back to the serial sweep for small
                // panels where the rayon overhead would dominate. frankentorch-kgs4.72.
                if (n - l) as u64 * (m - i) as u64 >= (1 << 14) && rayon::current_num_threads() > 1
                {
                    gemm::bidiag_col_reflector_apply_f64(a, n, i, m, l, h);
                } else {
                    for j in l..n {
                        let mut s2 = 0.0;
                        for k in i..m {
                            s2 += a[k * n + i] * a[k * n + j];
                        }
                        let f2 = s2 / h;
                        for k in i..m {
                            a[k * n + j] += f2 * a[k * n + i];
                        }
                    }
                }
                for k in i..m {
                    a[k * n + i] *= scale;
                }
            }
        }
        w[i] = scale * g;
        g = 0.0;
        s = 0.0;
        scale = 0.0;
        if i < m && i != n - 1 {
            for k in l..n {
                scale += a[i * n + k].abs();
            }
            if scale != 0.0 {
                for k in l..n {
                    a[i * n + k] /= scale;
                    s += a[i * n + k] * a[i * n + k];
                }
                let f = a[i * n + l];
                g = -nr_sign(s.sqrt(), f);
                let h = f * g - s;
                a[i * n + l] = f - g;
                for k in l..n {
                    rv1[k] = a[i * n + k] / h;
                }
                // Apply the reflector to the trailing rows [l,m). Each row is an
                // INDEPENDENT dot+axpy and is contiguous; row i (< l) is read-only,
                // so split it off and parallelise over the trailing rows (bit-exact)
                // when the work is large enough. frankentorch-kgs4.72.
                if (m - l) as u64 * (n - l) as u64 >= (1 << 14) && rayon::current_num_threads() > 1
                {
                    let (head, tail) = a.split_at_mut(l * n);
                    let row_i = &head[i * n..i * n + n];
                    tail.par_chunks_mut(n).for_each(|row_j| {
                        let mut s2 = 0.0;
                        for k in l..n {
                            s2 += row_j[k] * row_i[k];
                        }
                        for k in l..n {
                            row_j[k] += s2 * rv1[k];
                        }
                    });
                } else {
                    for j in l..m {
                        let mut s2 = 0.0;
                        for k in l..n {
                            s2 += a[j * n + k] * a[i * n + k];
                        }
                        for k in l..n {
                            a[j * n + k] += s2 * rv1[k];
                        }
                    }
                }
                for k in l..n {
                    a[i * n + k] *= scale;
                }
            }
        }
        anorm = anorm.max(w[i].abs() + rv1[i].abs());
    }

    // --- Accumulation of right-hand transformations (V) ---
    for i in (0..n).rev() {
        let l = i + 1;
        if i < n - 1 {
            if g != 0.0 {
                for j in l..n {
                    // Avoid possible underflow via division as in NR.
                    v[j * n + i] = (a[i * n + j] / a[i * n + l]) / g;
                }
                if (n - l) as u64 * (n - l) as u64 >= (1 << 14) && rayon::current_num_threads() > 1
                {
                    let arow = &a[i * n..i * n + n];
                    gemm::svd_v_backtransform_f64(&mut v, arow, n, i, l);
                } else {
                    for j in l..n {
                        let mut s = 0.0;
                        for k in l..n {
                            s += a[i * n + k] * v[k * n + j];
                        }
                        for k in l..n {
                            v[k * n + j] += s * v[k * n + i];
                        }
                    }
                }
            }
            for j in l..n {
                v[i * n + j] = 0.0;
                v[j * n + i] = 0.0;
            }
        }
        v[i * n + i] = 1.0;
        g = rv1[i];
    }

    if track_left {
        // --- Accumulation of left-hand transformations (U, overwriting a) ---
        for i in (0..n).rev() {
            let l = i + 1;
            g = w[i];
            for j in l..n {
                a[i * n + j] = 0.0;
            }
            if g != 0.0 {
                g = 1.0 / g;
                if (n - l) as u64 * (m - l) as u64 >= (1 << 14) && rayon::current_num_threads() > 1
                {
                    let a_ii = a[i * n + i];
                    gemm::svd_u_backtransform_f64(a, n, i, l, m, a_ii, g);
                } else {
                    for j in l..n {
                        let mut s = 0.0;
                        for k in l..m {
                            s += a[k * n + i] * a[k * n + j];
                        }
                        let f = (s / a[i * n + i]) * g;
                        for k in i..m {
                            a[k * n + j] += f * a[k * n + i];
                        }
                    }
                }
                for j in i..m {
                    a[j * n + i] *= g;
                }
            } else {
                for j in i..m {
                    a[j * n + i] = 0.0;
                }
            }
            a[i * n + i] += 1.0;
        }
    }

    // --- Diagonalization of the bidiagonal form: QR with implicit shifts ---
    // PERF NOTE: this implicit-QR sweep is the DOMINANT cost of the full SVD — a
    // long sequence of BLAS-1 Givens rotations applied to U (m rows) and V (n
    // rows). An earlier attempt row-parallelized each rotation individually (2
    // elements/row/fork-join) and regressed: memory-bound, O(n^2) fork/joins.
    // Transposing U/V also regressed (~1.4x): the two rotated columns are adjacent
    // (j, j+1) and already share a cache line in row-major; transposing splits
    // them `stride` apart.
    //
    // LEVER (bit-exact, DEFERRED whole-stream replay): the entire recurrence
    // (singular values + split/convergence decisions) reads only w/rv1, never U
    // or V. So log the COMPLETE ordered operation stream first, then replay it
    // across rows in a SINGLE parallel pass each — two fork/joins for the whole
    // O(n^3) back-transform, not one per rotation (the regressing attempt) or per
    // sweep (still O(n) fork/joins, ~1.1x net). Each of the n (m) rows independently
    // replays the whole log in order, so every entry is bit-for-bit identical to
    // the inline form. V's stream is rotations + convergence sign-flips; U's is the
    // cancellation + main-chase rotations (its own (c,s), distinct columns).
    // Same-worker RAYON A/B @256: full_matrices=true 2.26x, deferred-left 2.15x.
    let mut v_ops: Vec<SvdVOp> = Vec::new();
    let mut u_ops: Vec<(usize, usize, f64, f64)> = Vec::new();
    for k in (0..n).rev() {
        for _its in 0..30 {
            let mut flag = true;
            let mut l = k;
            let mut nm;
            // Test for splitting (find a negligible super-diagonal element).
            loop {
                nm = l.saturating_sub(1);
                if l == 0 || (rv1[l].abs() + anorm) == anorm {
                    flag = false;
                    break;
                }
                if (w[nm].abs() + anorm) == anorm {
                    break;
                }
                l -= 1;
            }
            if flag {
                // Cancellation of rv1[l], if l > 0.
                let mut c = 0.0;
                let mut s = 1.0;
                for i in l..=k {
                    let f = s * rv1[i];
                    rv1[i] *= c;
                    if (f.abs() + anorm) == anorm {
                        break;
                    }
                    g = w[i];
                    let h = eigh_pythag(f, g);
                    w[i] = h;
                    let hinv = 1.0 / h;
                    c = g * hinv;
                    s = -f * hinv;
                    if track_left {
                        u_ops.push((nm, i, c, s));
                    }
                }
            }
            let z = w[k];
            if l == k {
                // Convergence: make the singular value non-negative.
                if z < 0.0 {
                    w[k] = -z;
                    v_ops.push(SvdVOp::Neg(k));
                }
                break;
            }
            if _its == 29 {
                return Err(KernelError::SingularMatrix { size: n });
            }
            // Shift from bottom 2x2 minor.
            let mut x = w[l];
            nm = k - 1;
            let mut y = w[nm];
            g = rv1[nm];
            let mut h = rv1[k];
            let mut f = ((y - z) * (y + z) + (g - h) * (g + h)) / (2.0 * h * y);
            g = eigh_pythag(f, 1.0);
            f = ((x - z) * (x + z) + h * ((y / (f + nr_sign(g, f))) - h)) / x;
            // Next QR transformation (Givens rotations). Log the rotation chain
            // from the (U/V-independent) recurrence; it is replayed after the
            // whole sweep. V uses the first (c,s) of each step, U the second.
            let mut c = 1.0;
            let mut s = 1.0;
            for j in l..=nm {
                let i = j + 1;
                g = rv1[i];
                y = w[i];
                h = s * g;
                g *= c;
                let mut zz = eigh_pythag(f, h);
                rv1[j] = zz;
                c = f / zz;
                s = h / zz;
                f = x * c + g * s;
                g = g * c - x * s;
                h = y * s;
                y *= c;
                v_ops.push(SvdVOp::Rot(j, c, s));
                zz = eigh_pythag(f, h);
                w[j] = zz;
                if zz != 0.0 {
                    let zinv = 1.0 / zz;
                    c = f * zinv;
                    s = h * zinv;
                }
                f = c * g + s * y;
                x = c * y - s * g;
                if track_left {
                    u_ops.push((j, i, c, s));
                }
            }
            rv1[l] = 0.0;
            rv1[k] = f;
            w[k] = x;
        }
    }

    // Replay the full V/U operation streams. Each row applies the entire ordered
    // log independently (the recurrence never read U/V), so this whole O(n^3)
    // back-transform is parallel. ROW-BLOCKED, op-outer (frankentorch-x53r3): the
    // ops Vec is ≈2·n² rotations (tens of MB at large n); the old per-row form
    // (`par_chunks_mut(n)`) re-streamed it from RAM once PER ROW (bandwidth bound).
    // Grouping a small cache-resident block of rows reads ops once per BLOCK while
    // the block stays in L1/L2. Bit-identical to the per-row replay (same ops, same
    // order per row). 8 rows matches the eigh-QL replay A/B optimum.
    let svd_replay_block = svd_qr_replay_block_rows();
    if !v_ops.is_empty() {
        let ops = &v_ops;
        let br = svd_replay_block;
        v.par_chunks_mut(br * n).for_each(|block| {
            let nrows = block.len() / n;
            for &op in ops {
                match op {
                    SvdVOp::Rot(j, c, s) => {
                        for r in 0..nrows {
                            let base = r * n;
                            let xv = block[base + j];
                            let zv = block[base + j + 1];
                            block[base + j] = xv * c + zv * s;
                            block[base + j + 1] = zv * c - xv * s;
                        }
                    }
                    SvdVOp::Neg(k) => {
                        for r in 0..nrows {
                            block[r * n + k] = -block[r * n + k];
                        }
                    }
                }
            }
        });
    }
    // Replay the U (left-vector) rotation stream the same way over the m rows.
    if track_left && !u_ops.is_empty() {
        let ops = &u_ops;
        let br = svd_replay_block;
        a.par_chunks_mut(br * n).for_each(|block| {
            let nrows = block.len() / n;
            for &(c0, c1, c, s) in ops {
                for r in 0..nrows {
                    let base = r * n;
                    let yu = block[base + c0];
                    let zu = block[base + c1];
                    block[base + c0] = yu * c + zu * s;
                    block[base + c1] = zu * c - yu * s;
                }
            }
        });
    }

    Ok((w, v))
}

/// Singular VALUES only of a real `m x n` matrix with `m >= n`, row-major.
///
/// Same Householder bidiagonalization + implicit-shift QR recurrence as
/// [`golub_reinsch_svd`], but it never accumulates the `U`/`V` rotation
/// matrices (the Givens rotations are applied only to the diagonal `w` and
/// super-diagonal `rv1`). The `w` recurrence is identical to the full routine's,
/// so the returned values match the full SVD's singular values to working
/// precision while skipping the O(m n^2) U accumulation and all per-rotation
/// matrix updates. `a` is used as scratch and overwritten. Returns the `n`
/// non-negative singular values in bidiagonal order (caller sorts).
fn golub_reinsch_singular_values(
    a: &mut [f64],
    m: usize,
    n: usize,
) -> Result<Vec<f64>, KernelError> {
    let mut w = vec![0.0f64; n];
    let mut rv1 = vec![0.0f64; n];
    let mut g = 0.0f64;
    let mut scale = 0.0f64;
    let mut anorm = 0.0f64;

    // --- Householder reduction to bidiagonal form (identical to the full SVD) ---
    for i in 0..n {
        let l = i + 1;
        rv1[i] = scale * g;
        g = 0.0;
        let mut s = 0.0;
        scale = 0.0;
        if i < m {
            for k in i..m {
                scale += a[k * n + i].abs();
            }
            if scale != 0.0 {
                for k in i..m {
                    a[k * n + i] /= scale;
                    s += a[k * n + i] * a[k * n + i];
                }
                let f = a[i * n + i];
                g = -nr_sign(s.sqrt(), f);
                let h = f * g - s;
                a[i * n + i] = f - g;
                // Apply the reflector to the trailing columns [l,n). Each column is an
                // INDEPENDENT dot+axpy, so parallelise (bit-exact) when the work is
                // large enough; the gate falls back to the serial sweep for small
                // panels where the rayon overhead would dominate. frankentorch-kgs4.72.
                if (n - l) as u64 * (m - i) as u64 >= (1 << 14) && rayon::current_num_threads() > 1
                {
                    gemm::bidiag_col_reflector_apply_f64(a, n, i, m, l, h);
                } else {
                    for j in l..n {
                        let mut s2 = 0.0;
                        for k in i..m {
                            s2 += a[k * n + i] * a[k * n + j];
                        }
                        let f2 = s2 / h;
                        for k in i..m {
                            a[k * n + j] += f2 * a[k * n + i];
                        }
                    }
                }
                for k in i..m {
                    a[k * n + i] *= scale;
                }
            }
        }
        w[i] = scale * g;
        g = 0.0;
        s = 0.0;
        scale = 0.0;
        if i < m && i != n - 1 {
            for k in l..n {
                scale += a[i * n + k].abs();
            }
            if scale != 0.0 {
                for k in l..n {
                    a[i * n + k] /= scale;
                    s += a[i * n + k] * a[i * n + k];
                }
                let f = a[i * n + l];
                g = -nr_sign(s.sqrt(), f);
                let h = f * g - s;
                a[i * n + l] = f - g;
                for k in l..n {
                    rv1[k] = a[i * n + k] / h;
                }
                // Apply the reflector to the trailing rows [l,m). Each row is an
                // INDEPENDENT dot+axpy and is contiguous; row i (< l) is read-only,
                // so split it off and parallelise over the trailing rows (bit-exact)
                // when the work is large enough. frankentorch-kgs4.72.
                if (m - l) as u64 * (n - l) as u64 >= (1 << 14) && rayon::current_num_threads() > 1
                {
                    let (head, tail) = a.split_at_mut(l * n);
                    let row_i = &head[i * n..i * n + n];
                    tail.par_chunks_mut(n).for_each(|row_j| {
                        let mut s2 = 0.0;
                        for k in l..n {
                            s2 += row_j[k] * row_i[k];
                        }
                        for k in l..n {
                            row_j[k] += s2 * rv1[k];
                        }
                    });
                } else {
                    for j in l..m {
                        let mut s2 = 0.0;
                        for k in l..n {
                            s2 += a[j * n + k] * a[i * n + k];
                        }
                        for k in l..n {
                            a[j * n + k] += s2 * rv1[k];
                        }
                    }
                }
                for k in l..n {
                    a[i * n + k] *= scale;
                }
            }
        }
        anorm = anorm.max(w[i].abs() + rv1[i].abs());
    }

    // --- Diagonalize the bidiagonal form, tracking only w / rv1 (no U, no V) ---
    for k in (0..n).rev() {
        for _its in 0..30 {
            let mut flag = true;
            let mut l = k;
            let mut nm;
            loop {
                nm = l.saturating_sub(1);
                if l == 0 || (rv1[l].abs() + anorm) == anorm {
                    flag = false;
                    break;
                }
                if (w[nm].abs() + anorm) == anorm {
                    break;
                }
                l -= 1;
            }
            if flag {
                let mut c = 0.0;
                let mut s = 1.0;
                for i in l..=k {
                    let f = s * rv1[i];
                    rv1[i] *= c;
                    if (f.abs() + anorm) == anorm {
                        break;
                    }
                    g = w[i];
                    let h = eigh_pythag(f, g);
                    w[i] = h;
                    let hinv = 1.0 / h;
                    c = g * hinv;
                    s = -f * hinv;
                }
            }
            let z = w[k];
            if l == k {
                if z < 0.0 {
                    w[k] = -z;
                }
                break;
            }
            if _its == 29 {
                return Err(KernelError::SingularMatrix { size: n });
            }
            let mut x = w[l];
            nm = k - 1;
            let mut y = w[nm];
            g = rv1[nm];
            let mut h = rv1[k];
            let mut f = ((y - z) * (y + z) + (g - h) * (g + h)) / (2.0 * h * y);
            g = eigh_pythag(f, 1.0);
            f = ((x - z) * (x + z) + h * ((y / (f + nr_sign(g, f))) - h)) / x;
            let mut c = 1.0;
            let mut s = 1.0;
            for j in l..=nm {
                let i = j + 1;
                g = rv1[i];
                y = w[i];
                h = s * g;
                g *= c;
                let mut zz = eigh_pythag(f, h);
                rv1[j] = zz;
                c = f / zz;
                s = h / zz;
                f = x * c + g * s;
                g = g * c - x * s;
                h = y * s;
                y *= c;
                zz = eigh_pythag(f, h);
                w[j] = zz;
                if zz != 0.0 {
                    let zinv = 1.0 / zz;
                    c = f * zinv;
                    s = h * zinv;
                }
                f = c * g + s * y;
                x = c * y - s * g;
            }
            rv1[l] = 0.0;
            rv1[k] = f;
            w[k] = x;
        }
    }

    Ok(w)
}

fn same_column_bits(a: &[f64], rows: usize, cols: usize, lhs: usize, rhs: usize) -> bool {
    for row in 0..rows {
        if a[row * cols + lhs].to_bits() != a[row * cols + rhs].to_bits() {
            return false;
        }
    }
    true
}

fn duplicate_column_groups(a: &[f64], rows: usize, cols: usize) -> Option<Vec<Vec<usize>>> {
    let probe_rows = rows.min(8);
    let mut probe_fingerprints = Vec::with_capacity(cols);
    for col in 0..cols {
        let mut hash = 0x517c_c1b7_2722_0a95u64;
        for row in 0..probe_rows {
            hash ^= a[row * cols + col].to_bits();
            hash = hash.rotate_left(23).wrapping_mul(0x9e37_79b9_7f4a_7c15u64);
        }
        probe_fingerprints.push((hash, col));
    }

    probe_fingerprints.sort_unstable();
    let mut probe_duplicates = 0usize;
    let mut start = 0usize;
    while start < probe_fingerprints.len() {
        let fingerprint = probe_fingerprints[start].0;
        let mut end = start + 1;
        while end < probe_fingerprints.len() && probe_fingerprints[end].0 == fingerprint {
            end += 1;
        }
        probe_duplicates += end - start - 1;
        start = end;
    }
    if probe_duplicates == 0 || probe_duplicates * 8 < cols {
        return None;
    }

    let mut fingerprints = Vec::with_capacity(cols);
    for col in 0..cols {
        let mut hash = 0x9e37_79b9_7f4a_7c15u64;
        for row in 0..rows {
            hash ^= a[row * cols + col].to_bits();
            hash = hash.rotate_left(27).wrapping_mul(0x94d0_49bb_1331_11ebu64);
        }
        fingerprints.push((hash, col));
    }

    fingerprints.sort_unstable();
    let mut groups: Vec<Vec<usize>> = Vec::new();
    let mut start = 0usize;
    while start < fingerprints.len() {
        let fingerprint = fingerprints[start].0;
        let mut end = start + 1;
        while end < fingerprints.len() && fingerprints[end].0 == fingerprint {
            end += 1;
        }

        let run_group_start = groups.len();
        'col: for &(_, col) in &fingerprints[start..end] {
            for group in &mut groups[run_group_start..] {
                if same_column_bits(a, rows, cols, col, group[0]) {
                    group.push(col);
                    continue 'col;
                }
            }
            groups.push(vec![col]);
        }

        start = end;
    }
    groups.sort_unstable_by_key(|group| group[0]);

    let duplicates = cols - groups.len();
    if duplicates == 0 || duplicates * 8 < cols {
        return None;
    }
    Some(groups)
}

fn complete_orthonormal_columns_monotonic(
    matrix: &mut [f64],
    rows: usize,
    cols: usize,
    first_missing: usize,
    tol: f64,
) -> bool {
    let mut seed = 0usize;
    for col_idx in first_missing..cols {
        let mut filled = false;
        while seed < rows {
            let mut col = vec![0.0f64; rows];
            col[seed] = 1.0;
            seed += 1;
            for _ in 0..2 {
                for prev in 0..col_idx {
                    let mut dot = 0.0f64;
                    for row in 0..rows {
                        dot += col[row] * matrix[row * cols + prev];
                    }
                    for row in 0..rows {
                        col[row] -= dot * matrix[row * cols + prev];
                    }
                }
            }
            let norm = col.iter().map(|value| value * value).sum::<f64>().sqrt();
            if norm > tol {
                let inv = 1.0 / norm;
                for row in 0..rows {
                    matrix[row * cols + col_idx] = col[row] * inv;
                }
                filled = true;
                break;
            }
        }
        if !filled {
            return false;
        }
    }
    true
}

fn fill_duplicate_nullspace_rows(
    matrix: &mut [f64],
    n: usize,
    first_missing: usize,
    groups: &[Vec<usize>],
) -> bool {
    let mut row = first_missing;
    for group in groups {
        for basis_idx in 1..group.len() {
            if row >= n {
                return false;
            }
            let scale = ((basis_idx * (basis_idx + 1)) as f64).sqrt();
            let positive = 1.0 / scale;
            let negative = -(basis_idx as f64) / scale;
            for &col in &group[..basis_idx] {
                matrix[row * n + col] = positive;
            }
            matrix[row * n + group[basis_idx]] = negative;
            row += 1;
        }
    }
    row == n
}

fn svd_columns_orthogonality_error(matrix: &[f64], rows: usize, cols: usize) -> f64 {
    let mut max_error = 0.0f64;
    for lhs in 0..cols {
        for rhs in 0..cols {
            let mut dot = 0.0f64;
            for row in 0..rows {
                dot += matrix[row * cols + lhs] * matrix[row * cols + rhs];
            }
            let expected = if lhs == rhs { 1.0 } else { 0.0 };
            max_error = max_error.max((dot - expected).abs());
        }
    }
    max_error
}

fn svd_rows_orthogonality_error(matrix: &[f64], rows: usize, cols: usize) -> f64 {
    let mut max_error = 0.0f64;
    for lhs in 0..rows {
        for rhs in 0..rows {
            let mut dot = 0.0f64;
            for col in 0..cols {
                dot += matrix[lhs * cols + col] * matrix[rhs * cols + col];
            }
            let expected = if lhs == rhs { 1.0 } else { 0.0 };
            max_error = max_error.max((dot - expected).abs());
        }
    }
    max_error
}

fn svd_reconstruction_error(a: &[f64], result: &SvdResult) -> (f64, f64) {
    let mut max_abs = 0.0f64;
    let mut frob = 0.0f64;
    for row in 0..result.m {
        for col in 0..result.n {
            let mut reconstructed = 0.0f64;
            for idx in 0..result.k {
                reconstructed += result.u[row * result.k + idx]
                    * result.s[idx]
                    * result.vh[idx * result.n + col];
            }
            let original = a[row * result.n + col];
            max_abs = max_abs.max((reconstructed - original).abs());
            frob += original * original;
        }
    }
    (max_abs, frob.sqrt())
}

fn validate_rank_deficient_svd(a: &[f64], result: &SvdResult) -> bool {
    let tol = 1e-8f64;
    if result.u.len() != result.m * result.k
        || result.s.len() != result.k
        || result.vh.len() != result.k * result.n
    {
        return false;
    }
    for idx in 0..result.k {
        if !result.s[idx].is_finite() || result.s[idx] < -tol {
            return false;
        }
        if idx > 0 && result.s[idx - 1] + tol < result.s[idx] {
            return false;
        }
    }
    if !result.u.iter().all(|value| value.is_finite())
        || !result.vh.iter().all(|value| value.is_finite())
    {
        return false;
    }
    let meta = TensorMeta::from_shape(vec![result.m, result.n], DType::F64, Device::Cpu);
    let Ok(values_only) = svdvals_contiguous_f64(a, &meta) else {
        return false;
    };
    if values_only.len() != result.s.len() {
        return false;
    }
    for (idx, (&fast, &reference)) in result.s.iter().zip(values_only.iter()).enumerate() {
        let scale = fast.abs().max(reference.abs()).max(1.0);
        let allowed = 1e-8 * scale;
        if idx == 0 && fast <= allowed {
            return false;
        }
        if (fast - reference).abs() > allowed {
            return false;
        }
    }
    let (reconstruction, frob) = svd_reconstruction_error(a, result);
    if reconstruction > 1e-7 * frob.max(1.0) {
        return false;
    }
    if svd_columns_orthogonality_error(&result.u, result.m, result.k) > 1e-8 {
        return false;
    }
    if svd_rows_orthogonality_error(&result.vh, result.k, result.n) > 1e-8 {
        return false;
    }
    true
}

fn svd_rank_deficient_square_fast_path(
    a: &[f64],
    m: usize,
    n: usize,
    full_matrices: bool,
) -> Result<Option<SvdResult>, KernelError> {
    if full_matrices || m != n || n < 64 {
        return Ok(None);
    }
    if !a.iter().all(|value| value.is_finite()) {
        return Ok(None);
    }
    let frob = a.iter().map(|value| value * value).sum::<f64>().sqrt();
    let rank_tol = f64::EPSILON.sqrt() * frob.max(1.0);
    let Some(groups) = duplicate_column_groups(a, m, n) else {
        return Ok(None);
    };
    let rank = groups.len();
    if rank * 8 > n * 7 {
        return Ok(None);
    }

    let mut weighted_unique = vec![0.0f64; m * rank];
    for (group_idx, group) in groups.iter().enumerate() {
        let scale = (group.len() as f64).sqrt();
        let source_col = group[0];
        for row in 0..m {
            weighted_unique[row * rank + group_idx] = a[row * n + source_col] * scale;
        }
    }
    let weighted_meta = TensorMeta::from_shape(vec![m, rank], DType::F64, Device::Cpu);
    let weighted_svd = match svd_contiguous_f64(&weighted_unique, &weighted_meta, false) {
        Ok(result) if result.k == rank => result,
        _ => return Ok(None),
    };
    if weighted_svd.s[rank - 1] <= rank_tol {
        return Ok(None);
    }

    let mut u = vec![0.0f64; m * n];
    for row in 0..m {
        for col in 0..rank {
            u[row * n + col] = weighted_svd.u[row * rank + col];
        }
    }
    if !complete_orthonormal_columns_monotonic(&mut u, m, n, rank, rank_tol) {
        return Ok(None);
    }

    let mut vh = vec![0.0f64; n * n];
    for row in 0..rank {
        let inv_s = 1.0 / weighted_svd.s[row];
        for col in 0..n {
            let mut dot = 0.0f64;
            for input_row in 0..m {
                dot += weighted_svd.u[input_row * rank + row] * a[input_row * n + col];
            }
            vh[row * n + col] = dot * inv_s;
        }
    }
    if !fill_duplicate_nullspace_rows(&mut vh, n, rank, &groups) {
        return Ok(None);
    }

    let mut s = vec![0.0f64; n];
    s[..rank].copy_from_slice(&weighted_svd.s[..rank]);
    let result = SvdResult {
        u,
        s,
        vh,
        m,
        n,
        k: n,
    };

    if validate_rank_deficient_svd(a, &result) {
        Ok(Some(result))
    } else {
        Ok(None)
    }
}

fn svd_full_rank_square_deferred_left_fast_path(
    a: &[f64],
    m: usize,
    n: usize,
    full_matrices: bool,
) -> Result<Option<SvdResult>, KernelError> {
    // For well-conditioned reduced square SVD, V and S determine U as A*V/S.
    // That avoids the expensive left-Givens accumulation in the QR sweep.
    if full_matrices || m != n || n < 64 {
        return Ok(None);
    }
    if !a.iter().all(|value| value.is_finite()) {
        return Ok(None);
    }

    let mut scratch = a.to_vec();
    let (w_bidiag, v) = golub_reinsch_svd_right_only(&mut scratch, m, n)?;
    if !w_bidiag.iter().all(|value| value.is_finite()) || !v.iter().all(|value| value.is_finite()) {
        return Ok(None);
    }
    let max_s = w_bidiag.iter().copied().fold(0.0f64, f64::max);
    let min_s = w_bidiag.iter().copied().fold(f64::INFINITY, f64::min);
    let rank_tol = f64::EPSILON.sqrt() * max_s.max(1.0);
    if min_s <= rank_tol {
        return Ok(None);
    }

    let mut order: Vec<usize> = (0..n).collect();
    order.sort_by(|&lhs, &rhs| w_bidiag[rhs].total_cmp(&w_bidiag[lhs]));

    let mut av = vec![0.0f64; m * n];
    gemm::dgemm(m, n, n, a, &v, &mut av);

    let mut s = Vec::with_capacity(n);
    let mut u = vec![0.0f64; m * n];
    let mut vh = vec![0.0f64; n * n];

    for (new_col, &old_col) in order.iter().enumerate() {
        s.push(w_bidiag[old_col]);
        let inv_s = 1.0 / w_bidiag[old_col];
        for row in 0..m {
            u[row * n + new_col] = av[row * n + old_col] * inv_s;
        }
        for col in 0..n {
            vh[new_col * n + col] = v[col * n + old_col];
        }
    }

    Ok(Some(SvdResult {
        u,
        s,
        vh,
        m,
        n,
        k: n,
    }))
}

/// SVD for tall/square matrices (m >= n) via Golub-Reinsch bidiagonalization.
fn svd_tall(a: &[f64], m: usize, n: usize, full_matrices: bool) -> Result<SvdResult, KernelError> {
    let k = n; // since m >= n, k = min(m,n) = n
    let tol = 1e-15;

    if let Some(result) = svd_rank_deficient_square_fast_path(a, m, n, full_matrices)? {
        return Ok(result);
    }
    if let Some(result) = svd_full_rank_square_deferred_left_fast_path(a, m, n, full_matrices)? {
        return Ok(result);
    }

    // Golub-Reinsch SVD: A = U_b diag(w) V^T with U_b the reduced (m x n) left
    // singular vectors. We rescale into `work[:,j] = w[j] * U_b[:,j]` so the
    // column norm of `work[:,j]` is exactly w[j] — matching the contract the
    // singular-value extraction, descending sort, U re-normalization,
    // orthonormal-basis completion, and V^T construction below already expect
    // (they were written for the prior one-sided-Jacobi `work = U diag(S)`).
    let mut u = a.to_vec();
    let (w_bidiag, v) = golub_reinsch_svd(&mut u, m, n)?;
    let mut work = vec![0.0f64; m * n];
    for j in 0..n {
        let wj = w_bidiag[j];
        for i in 0..m {
            work[i * n + j] = wj * u[i * n + j];
        }
    }

    // Singular values are the bidiagonal-QR diagonal `w_bidiag` directly (each
    // already non-negative). Using `w_bidiag` here — rather than re-deriving via
    // `work` column norms — makes the full SVD's `s` BIT-IDENTICAL to the
    // dedicated values-only path (`svdvals_contiguous_f64`), which runs the same
    // `w` recurrence without U/V accumulation. `col_norms` (the actual norms,
    // = w_bidiag up to U_b's unit-length rounding) is retained to re-normalize
    // the `work` columns into the orthonormal U.
    let mut singular_values = Vec::with_capacity(k);
    let mut col_norms = Vec::with_capacity(k);
    for j in 0..k {
        let mut norm = 0.0f64;
        for i in 0..m {
            norm += work[i * n + j] * work[i * n + j];
        }
        col_norms.push(norm.sqrt());
        singular_values.push(w_bidiag[j]);
    }

    // Sort singular values in descending order
    let mut order: Vec<usize> = (0..k).collect();
    order.sort_by(|&a, &b| singular_values[b].total_cmp(&singular_values[a]));

    let s: Vec<f64> = order.iter().map(|&i| singular_values[i]).collect();

    // Build U: normalize columns of `work` by singular values, reorder
    let u_cols = if full_matrices { m } else { k };
    let mut u = vec![0.0f64; m * u_cols];
    for (new_j, &old_j) in order.iter().enumerate() {
        if new_j >= u_cols {
            break;
        }
        let norm = col_norms[old_j];
        if norm > tol {
            for i in 0..m {
                u[i * u_cols + new_j] = work[i * n + old_j] / norm;
            }
        }
        // else: leave zero — completed in the unified pass below.
    }

    // Complete the orthonormal basis: any column of U that is still
    // zero (either because the corresponding singular value is below
    // tol — rank-deficient input — or because we are in full_matrices
    // mode and m > k so columns k..m start unfilled) gets a unit
    // vector orthogonal to all previously-set columns via
    // Gram-Schmidt. Required for U to satisfy U^T U = I_{u_cols},
    // which numpy / torch.linalg.svd / scipy all guarantee. Tracked
    // under frankentorch-zs8a — previously the rank-deficient path
    // left those columns as zeros and reduced-mode SVD failed
    // U^T U = I on rank-deficient matrices.
    for j in 0..u_cols {
        // Check if column j is currently zero (norm < tol).
        let mut existing_norm_sq = 0.0f64;
        for i in 0..m {
            let v = u[i * u_cols + j];
            existing_norm_sq += v * v;
        }
        if existing_norm_sq > tol * tol {
            continue;
        }

        // Try standard basis vectors e_0, e_1, ... e_{m-1} until one
        // produces a non-degenerate residual after Gram-Schmidt. In
        // a rank-r system with m-r missing columns, at most r of the
        // basis vectors can lie entirely in the existing column span,
        // so a fresh one is always available within m tries.
        for seed in 0..m {
            let mut col = vec![0.0f64; m];
            col[seed] = 1.0;
            // Orthogonalize against all previously-set columns of u
            // (this includes both already-normalized SVD columns and
            // any earlier basis-completion columns we just filled).
            for prev in 0..u_cols {
                if prev == j {
                    continue;
                }
                let mut dot = 0.0;
                for i in 0..m {
                    dot += col[i] * u[i * u_cols + prev];
                }
                for i in 0..m {
                    col[i] -= dot * u[i * u_cols + prev];
                }
            }
            let mut norm = 0.0f64;
            for item in col.iter().take(m) {
                norm += item * item;
            }
            let norm = norm.sqrt();
            if norm > tol {
                for i in 0..m {
                    u[i * u_cols + j] = col[i] / norm;
                }
                break;
            }
        }
    }

    // Build Vh: V^T with reordering
    let vh_rows = if full_matrices { n } else { k };
    let mut vh = vec![0.0f64; vh_rows * n];
    for (new_i, &old_i) in order.iter().enumerate() {
        if new_i >= vh_rows {
            break;
        }
        for j in 0..n {
            vh[new_i * n + j] = v[j * n + old_i]; // V^T[new_i][j] = V[j][old_i]
        }
    }

    Ok(SvdResult { u, s, vh, m, n, k })
}

/// Compute just the singular values of an (m x n) matrix, sorted descending.
///
/// Uses the dedicated values-only Golub-Reinsch path
/// ([`golub_reinsch_singular_values`]): bidiagonalize then run the implicit-shift
/// QR recurrence on the bidiagonal alone, skipping all U/V accumulation. The
/// `w` recurrence is identical to the full SVD's, so the values agree with
/// `svd_contiguous_f64(..).s` to working precision while avoiding the O(m n^2)
/// U accumulation and every per-rotation matrix update. Wide matrices reduce to
/// the tall case via transpose (the singular values of `A` and `A^T` are equal).
/// Batched singular values: input `[..., m, n]` -> singular values `[B*min(m,n)]` (row-major).
/// Parallelizes the verified 2-D [`svdvals_contiguous_f64`] over the batch. PyTorch loops LAPACK per
/// plane (per-call overhead dominates for small m,n). Bit-identical to looping the 2-D svdvals.
/// frankentorch-batched-eigh. (BlackThrush)
pub fn svdvals_batched_contiguous_f64(
    data: &[f64],
    meta: &TensorMeta,
) -> Result<Vec<f64>, KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    let nd = shape.len();
    if nd < 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![nd],
        });
    }
    let m = shape[nd - 2];
    let n = shape[nd - 1];
    let mn = m.min(n);
    let bb: usize = shape[..nd - 2].iter().product();
    let plane = m * n;
    let offset = meta.storage_offset();
    let data = &data[offset..offset + bb * plane];
    let pmeta = TensorMeta::from_shape(vec![m, n], DType::F64, Device::Cpu);
    let mut out = vec![0.0f64; bb * mn];
    let first_err = std::sync::Mutex::new(None);
    out.par_chunks_mut(mn)
        .zip(data.par_chunks(plane))
        .for_each(|(o, pl)| match svdvals_contiguous_f64(pl, &pmeta) {
            Ok(s) => o.copy_from_slice(&s),
            Err(e) => {
                let mut g = first_err.lock().unwrap();
                if g.is_none() {
                    *g = Some(e);
                }
            }
        });
    if let Some(e) = first_err.into_inner().unwrap() {
        return Err(e);
    }
    Ok(out)
}

pub fn svdvals_contiguous_f64(data: &[f64], meta: &TensorMeta) -> Result<Vec<f64>, KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![2],
        });
    }
    let m = shape[0];
    let n = shape[1];
    if m == 0 || n == 0 {
        return Ok(Vec::new());
    }
    let offset = meta.storage_offset();
    let mut a = vec![0.0f64; m * n];
    for i in 0..m {
        for j in 0..n {
            a[i * n + j] = data[offset + i * n + j];
        }
    }

    let mut s = if m >= n {
        golub_reinsch_singular_values(&mut a, m, n)?
    } else {
        // Transpose to (n x m) so it is tall; sv(A) == sv(A^T).
        let mut at = vec![0.0f64; n * m];
        for i in 0..m {
            for j in 0..n {
                at[j * m + i] = a[i * n + j];
            }
        }
        golub_reinsch_singular_values(&mut at, n, m)?
    };
    // Sort descending, matching svd_contiguous_f64's ordering.
    s.sort_by(|x, y| y.total_cmp(x));
    Ok(s)
}

/// One draw from a deterministic SplitMix64 stream, mapped to a uniform in (0,1).
fn splitmix_uniform(state: &mut u64) -> f64 {
    *state = state.wrapping_add(0x9E37_79B9_7F4A_7C15);
    let mut z = *state;
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
    z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
    z ^= z >> 31;
    // 53-bit mantissa -> (0, 1).
    ((z >> 11) as f64 + 0.5) / (1u64 << 53) as f64
}

/// `out` (= ca x cb) = `A^T · B`, where `A` is `ra x ca` and `B` is `ra x cb`
/// (both row-major). Materialises `A^T` then routes through the cache-blocked GEMM.
fn mat_at_b(a: &[f64], ra: usize, ca: usize, b: &[f64], cb: usize, out: &mut [f64]) {
    let mut at = vec![0.0f64; ca * ra];
    for i in 0..ra {
        for j in 0..ca {
            at[j * ra + i] = a[i * ca + j];
        }
    }
    gemm::dgemm(ca, ra, cb, &at, b, out);
}

/// Randomized truncated SVD (Halko-Martinsson-Tropp). Returns an approximate
/// rank-`q` factorisation `A ≈ U·diag(s)·Vh` in `O(m·n·l)` (l = q + oversampling)
/// instead of the full SVD's `O(m·n²)` — a large win when `q << min(m,n)`
/// (PCA / low-rank approximation). `niter` subspace power iterations sharpen the
/// estimate for slowly-decaying spectra. The Gaussian sketch is seeded
/// deterministically from the shape so results are reproducible. For a matrix of
/// exact rank ≤ q the factorisation is accurate to working precision.
pub fn svd_lowrank_contiguous_f64(
    data: &[f64],
    meta: &TensorMeta,
    q: usize,
    niter: usize,
) -> Result<SvdResult, KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![2],
        });
    }
    let m = shape[0];
    let n = shape[1];
    if m == 0 || n == 0 {
        return Ok(SvdResult {
            u: Vec::new(),
            s: Vec::new(),
            vh: Vec::new(),
            m,
            n,
            k: 0,
        });
    }
    let offset = meta.storage_offset();
    let a = data[offset..offset + m * n].to_vec();

    let max_rank = m.min(n);
    let q = q.clamp(1, max_rank);
    // Sketch width: target rank + oversampling, capped at the smaller dimension.
    let l = (q + 6).min(max_rank);

    // Gaussian sketch Omega (n x l) via SplitMix64 + Box-Muller.
    let mut rng =
        0x243F_6A88_85A3_08D3u64 ^ ((m as u64) << 32) ^ (n as u64).wrapping_mul(2_654_435_761);
    let mut omega = vec![0.0f64; n * l];
    let mut idx = 0;
    while idx < omega.len() {
        let u1 = splitmix_uniform(&mut rng);
        let u2 = splitmix_uniform(&mut rng);
        let r = (-2.0 * u1.ln()).sqrt();
        let ang = std::f64::consts::TAU * u2;
        omega[idx] = r * ang.cos();
        idx += 1;
        if idx < omega.len() {
            omega[idx] = r * ang.sin();
            idx += 1;
        }
    }

    // Y = A · Omega  (m x l).
    let mut y = vec![0.0f64; m * l];
    gemm::dgemm(m, n, l, &a, &omega, &mut y);

    // Subspace power iterations: Y <- A·(A^T·Y).
    for _ in 0..niter {
        let mut z = vec![0.0f64; n * l]; // z = A^T · Y
        mat_at_b(&a, m, n, &y, l, &mut z);
        gemm::dgemm(m, n, l, &a, &z, &mut y); // y = A · z
    }

    // Orthonormal basis Q (m x l) of range(Y) via reduced QR.
    let y_meta = TensorMeta::from_shape(vec![m, l], meta.dtype(), meta.device());
    let qr = qr_contiguous_f64(&y, &y_meta, true)?;
    let qmat = qr.q; // m x l
    let lq = qr.n;

    // B = Q^T · A  (lq x n), then its (small) full SVD.
    let mut b = vec![0.0f64; lq * n];
    mat_at_b(&qmat, m, lq, &a, n, &mut b);
    let b_meta = TensorMeta::from_shape(vec![lq, n], meta.dtype(), meta.device());
    let bsvd = svd_contiguous_f64(&b, &b_meta, false)?;
    let kb = bsvd.k;

    // U = Q · Ub  (m x kb).
    let mut u_full = vec![0.0f64; m * kb];
    gemm::dgemm(m, lq, kb, &qmat, &bsvd.u, &mut u_full);

    // Truncate to the top-q components.
    let out_k = q.min(kb);
    let mut u = vec![0.0f64; m * out_k];
    for i in 0..m {
        for j in 0..out_k {
            u[i * out_k + j] = u_full[i * kb + j];
        }
    }
    let s = bsvd.s[..out_k].to_vec();
    let vh = bsvd.vh[..out_k * n].to_vec();

    Ok(SvdResult {
        u,
        s,
        vh,
        m,
        n,
        k: out_k,
    })
}

/// Randomized PCA (`torch.pca_lowrank`). Optionally centers the columns
/// (subtract each column's mean, treating rows as samples / columns as
/// features), then runs the randomized truncated SVD. Returns the reduced
/// `(U, S, Vh)`; the caller transposes `Vh` to the `V` that `torch.pca_lowrank`
/// reports. O(m·n·q) via [`svd_lowrank_contiguous_f64`].
pub fn pca_lowrank_contiguous_f64(
    data: &[f64],
    meta: &TensorMeta,
    q: usize,
    center: bool,
    niter: usize,
) -> Result<SvdResult, KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![2],
        });
    }
    let m = shape[0];
    let n = shape[1];
    if m == 0 || n == 0 {
        return Ok(SvdResult {
            u: Vec::new(),
            s: Vec::new(),
            vh: Vec::new(),
            m,
            n,
            k: 0,
        });
    }
    let offset = meta.storage_offset();
    let mut a = data[offset..offset + m * n].to_vec();
    if center {
        for j in 0..n {
            let mut mean = 0.0;
            for i in 0..m {
                mean += a[i * n + j];
            }
            mean /= m as f64;
            for i in 0..m {
                a[i * n + j] -= mean;
            }
        }
    }
    let a_meta = TensorMeta::from_shape(vec![m, n], meta.dtype(), meta.device());
    svd_lowrank_contiguous_f64(&a, &a_meta, q, niter)
}

/// Modified Gram-Schmidt over the columns of `m` (n x c, row-major). The
/// orthonormal columns are packed into the first `rank` positions (returned);
/// columns whose residual norm falls below the threshold are dropped (rank
/// deficiency). Used by [`lobpcg_contiguous_f64`].
fn mgs_orthonormalize_cols(m: &mut [f64], n: usize, c: usize) -> usize {
    let mut rank = 0usize;
    for j in 0..c {
        let mut col = vec![0.0f64; n];
        for i in 0..n {
            col[i] = m[i * c + j];
        }
        for p in 0..rank {
            let mut dot = 0.0;
            for i in 0..n {
                dot += col[i] * m[i * c + p];
            }
            for i in 0..n {
                col[i] -= dot * m[i * c + p];
            }
        }
        let norm: f64 = col.iter().map(|v| v * v).sum::<f64>().sqrt();
        if norm > 1e-10 {
            let inv = 1.0 / norm;
            for i in 0..n {
                m[i * c + rank] = col[i] * inv;
            }
            rank += 1;
        }
    }
    rank
}

/// Top/bottom-`k` eigenpairs of a real-symmetric matrix via a block
/// steepest-descent Rayleigh-Ritz iteration (LOBPCG family, torch.lobpcg). Each
/// step expands the orthonormal subspace `[X | R]` (R = the X residuals,
/// orthonormalized against X), does a SMALL `eigh` of `S^T A S`, and keeps the k
/// extreme Ritz pairs — converging to the k largest (`largest=true`) or smallest
/// eigenpairs in `O(n^2 k)` per iteration vs the full eigh's `O(n^3)`. Returns
/// `(eigenvalues[k], eigenvectors[n*k]` row-major, columns = vectors`)`.
pub fn lobpcg_contiguous_f64(
    data: &[f64],
    meta: &TensorMeta,
    k: usize,
    largest: bool,
    niter: usize,
    tol: f64,
) -> Result<(Vec<f64>, Vec<f64>), KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 || shape[0] != shape[1] {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![2],
        });
    }
    let n = shape[0];
    let k = k.clamp(1, n);
    let offset = meta.storage_offset();
    let a = data[offset..offset + n * n].to_vec();

    let dev = meta.device();
    let dty = meta.dtype();
    // A @ M  for M: n x c  -> n x c.
    let amul = |x: &[f64], c: usize| -> Vec<f64> {
        let mut out = vec![0.0f64; n * c];
        gemm::dgemm(n, n, c, &a, x, &mut out);
        out
    };
    // Small dense eigh of an `s x s` symmetric matrix; selects the k extreme
    // Ritz pairs. Returns (theta[k], coeff[s*k] row-major) where coeff column t
    // is the eigenvector of the t-th selected Ritz value.
    let select_ritz = |sym: &[f64], s: usize| -> Result<(Vec<f64>, Vec<f64>), KernelError> {
        let m = TensorMeta::from_shape(vec![s, s], dty, dev);
        let e = eigh_contiguous_f64(sym, &m)?; // eigenvalues ascending, evecs s x s cols
        let mut theta = vec![0.0f64; k];
        let mut coeff = vec![0.0f64; s * k];
        for t in 0..k {
            let idx = if largest { s - 1 - t } else { t };
            theta[t] = e.eigenvalues[idx];
            for i in 0..s {
                coeff[i * k + t] = e.eigenvectors[i * s + idx];
            }
        }
        Ok((theta, coeff))
    };

    // Initial X: random n x k, orthonormalized.
    let mut rng =
        0x853C_49E6_748F_EA9Bu64 ^ ((n as u64) << 24) ^ (k as u64).wrapping_mul(0x2545F4914F6CDD1D);
    let mut x = vec![0.0f64; n * k];
    let mut idx = 0;
    while idx < x.len() {
        let u1 = splitmix_uniform(&mut rng);
        let u2 = splitmix_uniform(&mut rng);
        let r = (-2.0 * u1.ln()).sqrt();
        let ang = std::f64::consts::TAU * u2;
        x[idx] = r * ang.cos();
        idx += 1;
        if idx < x.len() {
            x[idx] = r * ang.sin();
            idx += 1;
        }
    }
    mgs_orthonormalize_cols(&mut x, n, k);

    let mut ax = amul(&x, k);
    // Initial Rayleigh-Ritz on X.
    let mut gram = vec![0.0f64; k * k];
    mat_at_b(&x, n, k, &ax, k, &mut gram); // X^T A X
    let (mut theta, c0) = select_ritz(&gram, k)?;
    {
        let mut nx = vec![0.0f64; n * k];
        gemm::dgemm(n, k, k, &x, &c0, &mut nx);
        x = nx;
        let mut nax = vec![0.0f64; n * k];
        gemm::dgemm(n, k, k, &ax, &c0, &mut nax);
        ax = nax;
    }

    for _ in 0..niter.max(1) {
        // Residuals R = AX - X diag(theta).
        let mut r = ax.clone();
        let mut maxres = 0.0f64;
        for i in 0..k {
            let mut nr = 0.0;
            for j in 0..n {
                let v = ax[j * k + i] - theta[i] * x[j * k + i];
                r[j * k + i] = v;
                nr += v * v;
            }
            maxres = maxres.max(nr.sqrt());
        }
        if maxres < tol {
            break;
        }
        // Orthogonalize R against X, then orthonormalize R's own columns.
        let mut xtr = vec![0.0f64; k * k];
        mat_at_b(&x, n, k, &r, k, &mut xtr); // X^T R  (k x k)
        let mut xxtr = vec![0.0f64; n * k];
        gemm::dgemm(n, k, k, &x, &xtr, &mut xxtr); // X (X^T R)
        for v in 0..n * k {
            r[v] -= xxtr[v];
        }
        let rr = mgs_orthonormalize_cols(&mut r, n, k);
        if rr == 0 {
            break;
        }
        // Subspace S = [X | R[:, :rr]]  (n x sc), orthonormal by construction.
        let sc = k + rr;
        let mut s = vec![0.0f64; n * sc];
        for i in 0..n {
            for j in 0..k {
                s[i * sc + j] = x[i * k + j];
            }
            for j in 0..rr {
                s[i * sc + (k + j)] = r[i * k + j];
            }
        }
        let as_ = amul(&s, sc);
        // M = S^T A S  (sc x sc, symmetric).
        let mut msym = vec![0.0f64; sc * sc];
        mat_at_b(&s, n, sc, &as_, sc, &mut msym);
        let (theta_new, coeff) = select_ritz(&msym, sc)?; // coeff: sc x k
        // X = S @ coeff ;  AX = AS @ coeff.
        let mut nx = vec![0.0f64; n * k];
        gemm::dgemm(n, sc, k, &s, &coeff, &mut nx);
        let mut nax = vec![0.0f64; n * k];
        gemm::dgemm(n, sc, k, &as_, &coeff, &mut nax);
        x = nx;
        ax = nax;
        theta = theta_new;
    }

    Ok((theta, x))
}

/// Result of QR decomposition.
#[derive(Debug, Clone)]
pub struct QrResult {
    /// Orthogonal matrix Q in row-major order.
    pub q: Vec<f64>,
    /// Upper triangular matrix R in row-major order.
    pub r: Vec<f64>,
    /// Number of rows (m).
    pub m: usize,
    /// Number of columns (n).
    pub n: usize,
}

/// Native f32 QR result (the f32 companion to [`QrResult`]). frankentorch-b3o90.
#[derive(Debug, Clone)]
pub struct QrResultF32 {
    /// Orthogonal matrix Q in row-major order, f32.
    pub q: Vec<f32>,
    /// Upper triangular matrix R in row-major order, f32.
    pub r: Vec<f32>,
    /// Number of rows (m).
    pub m: usize,
    /// Number of columns (n).
    pub n: usize,
}

/// Internal timing split for the compact-WY QR path.
#[doc(hidden)]
#[derive(Debug, Clone, Copy, Default)]
pub struct QrStageTimings {
    /// Input copy, final lower-triangle zeroing, and reduced-R copy time.
    pub copy_zeroing_ns: u128,
    /// Panel Householder factorization plus compact-WY T construction time.
    pub panel_and_t_ns: u128,
    /// Trailing R compact-WY update time.
    pub trailing_r_ns: u128,
    /// Reverse dorgqr Q construction time.
    pub reverse_q_ns: u128,
    /// Total profiled helper time.
    pub total_ns: u128,
}

impl QrStageTimings {
    /// Time not attributed to the four named stage buckets.
    #[must_use]
    pub fn unaccounted_ns(self) -> u128 {
        let accounted =
            self.copy_zeroing_ns + self.panel_and_t_ns + self.trailing_r_ns + self.reverse_q_ns;
        self.total_ns.saturating_sub(accounted)
    }
}

/// Internal QR profile result for stage-split probes.
#[doc(hidden)]
#[derive(Debug, Clone)]
pub struct QrStageProfile {
    /// QR output from the same algorithm being profiled.
    pub result: QrResult,
    /// Stage timings in nanoseconds.
    pub timings: QrStageTimings,
    /// Whether the compact-WY blocked QR path was exercised.
    pub used_blocked_path: bool,
}

/// Compute the QR decomposition of an (m x n) matrix via Householder reflections.
///
/// Returns `(Q, R)` such that `A = Q @ R`:
/// - Q: orthogonal matrix (m x m) for `reduced=false`, or (m x k) for `reduced=true` where k=min(m,n)
/// - R: upper triangular matrix (m x n) for `reduced=false`, or (k x n) for `reduced=true`
///
/// The matrix must be 2-D.
/// Compact-WY BLOCKED upper-Hessenberg reduction (LAPACK `dgehrd`/`dlahr2` shape)
/// of `h` (n×n, row-major), accumulating the orthogonal Q into `q` (starts as I).
/// Replaces the per-reflector BLAS-2 two-sided sweep — which dominates the
/// non-symmetric eigensolver (Hessenberg ~= 74% of eigvals) — with NB-wide panels
/// whose trailing two-sided update `H := PᵀH P` is four cache-blocked parallel
/// `gemm::dgemm` groups (BLAS-3). The key to a tractable two-sided block: keep the
/// pre-panel matrix `H0` FIXED during a panel and form each column on demand via
/// `Y = H0·V` matvecs against the fixed `H0`, sidestepping the trailing-state
/// circular dependency. Reassociates panel-by-panel, so it matches the unblocked
/// sweep only to TOLERANCE — validated by reconstruction (Q·H·Qᵀ = A) +
/// orthonormality, not bit-for-bit. frankentorch-9y5bi.
fn hessenberg_reduce_blocked(h: &mut [f64], q: &mut [f64], n: usize, accumulate_q: bool) {
    if n <= 2 {
        return;
    }
    const NB: usize = 32;
    let kmax = n - 2; // columns 0..kmax-1 get a reflector
    let mut ib = 0;
    while ib < kmax {
        let pe = (ib + NB).min(kmax);
        let nb = pe - ib; // panel width (active reflectors)
        // H0 = the current matrix, FIXED for the duration of this panel.
        let h0 = h.to_vec();
        let mut vmat = vec![0.0f64; n * nb]; // V[:, c] = reflector c (full length n)
        let mut ymat = vec![0.0f64; n * nb]; // Y[:, c] = H0 · V[:, c]
        let mut tmat = vec![0.0f64; nb * nb]; // compact-WY T (upper triangular)
        for c in 0..nb {
            let jcol = ib + c;
            // --- col_c = Pᵀ_c (H0[:,jcol] - Y_c·(T_c·r)),  r = row(jcol) of V_c.
            let mut s = vec![0.0f64; c]; // s = T_c · r  (c-vector)
            for i in 0..c {
                let mut acc = 0.0;
                for l in i..c {
                    // T upper-tri: T[i][l]==0 for l<i; r[l] = V[jcol][l]
                    acc += tmat[i * nb + l] * vmat[jcol * nb + l];
                }
                s[i] = acc;
            }
            let mut col = vec![0.0f64; n];
            for rr in 0..n {
                let mut acc = h0[rr * n + jcol];
                for l in 0..c {
                    acc -= ymat[rr * nb + l] * s[l];
                }
                col[rr] = acc; // col = w (before the left Pᵀ_c)
            }
            // p = V_cᵀ w  (c-vector); q_lin = T_cᵀ p; col -= V_c · q_lin.
            let mut pvec = vec![0.0f64; c];
            for l in 0..c {
                let mut acc = 0.0;
                for rr in 0..n {
                    acc += vmat[rr * nb + l] * col[rr];
                }
                pvec[l] = acc;
            }
            let mut qlin = vec![0.0f64; c];
            for i in 0..c {
                let mut acc = 0.0;
                for l in 0..=i {
                    // qlin = Tᵀ p; Tᵀ is LOWER-tri so (Tᵀ)[i][l] = T[l][i] ≠ 0 for l<=i
                    acc += tmat[l * nb + i] * pvec[l];
                }
                qlin[i] = acc;
            }
            for rr in 0..n {
                let mut acc = col[rr];
                for l in 0..c {
                    acc -= vmat[rr * nb + l] * qlin[l];
                }
                col[rr] = acc;
            }
            // --- Form the Householder reflector zeroing col[jcol+2:] (rows below
            //     subdiagonal), matching the existing eig convention exactly.
            let mut cn2 = 0.0;
            for &x in &col[jcol + 1..n] {
                cn2 += x * x;
            }
            if cn2 < 1e-30 {
                continue; // tau[c]=0 (T col stays 0, V col stays 0)
            }
            let col_norm = cn2.sqrt();
            let sign = if col[jcol + 1] >= 0.0 { 1.0 } else { -1.0 };
            vmat[(jcol + 1) * nb + c] = col[jcol + 1] + sign * col_norm;
            for rr in (jcol + 2)..n {
                vmat[rr * nb + c] = col[rr];
            }
            let mut vn2 = 0.0;
            for rr in (jcol + 1)..n {
                let x = vmat[rr * nb + c];
                vn2 += x * x;
            }
            if vn2 < 1e-30 {
                for rr in (jcol + 1)..n {
                    vmat[rr * nb + c] = 0.0;
                }
                continue;
            }
            let tau_c = 2.0 / vn2;
            // --- Y[:, c] = H0 · v_c  (one O(n^2) matvec against the FIXED H0).
            for rr in 0..n {
                let mut acc = 0.0;
                for jj in (jcol + 1)..n {
                    acc += h0[rr * n + jj] * vmat[jj * nb + c];
                }
                ymat[rr * nb + c] = acc;
            }
            // --- T column c (dlarft forward): T[c][c]=tau; T[0:c,c]=-tau (Vᵀ v_c);
            //     then T[0:c,c] = T_c · T[0:c,c].
            tmat[c * nb + c] = tau_c;
            let mut tcol = vec![0.0f64; c];
            for i in 0..c {
                let mut dot = 0.0;
                for rr in (jcol + 1)..n {
                    dot += vmat[rr * nb + i] * vmat[rr * nb + c];
                }
                tcol[i] = -tau_c * dot;
            }
            for i in 0..c {
                let mut acc = 0.0;
                for l in i..c {
                    acc += tmat[i * nb + l] * tcol[l];
                }
                tmat[i * nb + c] = acc;
            }
        }
        // --- Trailing two-sided update: H := PᵀH0 P = (I - V Tᵀ Vᵀ) H0 (I - V T Vᵀ).
        let mut vt = vec![0.0f64; nb * n];
        for rr in 0..n {
            for c in 0..nb {
                vt[c * n + rr] = vmat[rr * nb + c];
            }
        }
        let mut tt = vec![0.0f64; nb * nb];
        for i in 0..nb {
            for j in 0..nb {
                tt[i * nb + j] = tmat[j * nb + i];
            }
        }
        // H1 = H0 - V (Tᵀ (Vᵀ H0))
        let mut w = vec![0.0f64; nb * n];
        gemm::dgemm(nb, n, n, &vt, &h0, &mut w); // Vᵀ H0
        let mut ttw = vec![0.0f64; nb * n];
        gemm::dgemm(nb, nb, n, &tt, &w, &mut ttw); // Tᵀ (Vᵀ H0)
        let mut vttw = vec![0.0f64; n * n];
        gemm::dgemm(n, nb, n, &vmat, &ttw, &mut vttw); // V (...)
        for x in 0..n * n {
            h[x] = h0[x] - vttw[x];
        }
        // H = H1 - (H1 V) T Vᵀ
        let mut z = vec![0.0f64; n * nb];
        gemm::dgemm(n, n, nb, h, &vmat, &mut z); // H1 V
        let mut zt = vec![0.0f64; n * nb];
        gemm::dgemm(n, nb, nb, &z, &tmat, &mut zt); // (H1 V) T
        let mut ztvt = vec![0.0f64; n * n];
        gemm::dgemm_bt(n, nb, n, &zt, &vmat, &mut ztvt); // (...) Vᵀ
        for x in 0..n * n {
            h[x] -= ztvt[x];
        }
        // --- Q := Q · (I - V T Vᵀ) = Q - ((Q V) T) Vᵀ.  (eigenvector work only)
        if accumulate_q {
            let mut qv = vec![0.0f64; n * nb];
            gemm::dgemm(n, n, nb, q, &vmat, &mut qv);
            let mut qvt = vec![0.0f64; n * nb];
            gemm::dgemm(n, nb, nb, &qv, &tmat, &mut qvt);
            let mut qupd = vec![0.0f64; n * n];
            gemm::dgemm_bt(n, nb, n, &qvt, &vmat, &mut qupd);
            for x in 0..n * n {
                q[x] -= qupd[x];
            }
        }
        ib = pe;
    }
    // Clean the strict-below-subdiagonal of the reduced columns (the GEMM trailing
    // update leaves ~round-off there; the QR phase expects a clean Hessenberg band).
    for j in 0..kmax {
        for i in (j + 2)..n {
            h[i * n + j] = 0.0;
        }
    }
}

/// Compact-WY BLOCKED Householder QR (LAPACK `dgeqrf`+`dorgqr` shape). Replaces
/// the per-reflector BLAS-2 sweep — whose trailing R/Q updates are memory-bound
/// (~60x off LAPACK) — with NB-wide panels whose block reflector `I - V T Vᵀ` is
/// applied to the trailing R columns and to Q through the cache-blocked parallel
/// `gemm::dgemm` (BLAS-3). Reassociates the trailing sums panel-by-panel (like the
/// blocked LU/Cholesky), so it matches the unblocked sweep only to TOLERANCE —
/// validated by reconstruction (A = Q·R) + orthonormality, not bit-for-bit.
/// `r_mat` starts as A (m×n) and becomes R; `q_mat` starts as I (m×m) and becomes
/// Q. frankentorch-ct2yy.
fn qr_profile_stage_start(enabled: bool) -> Option<std::time::Instant> {
    enabled.then(std::time::Instant::now)
}

fn qr_profile_record_ns(slot: &mut u128, start: Option<std::time::Instant>) {
    if let Some(start) = start {
        *slot += start.elapsed().as_nanos();
    }
}

fn qr_build_compact_wy_t_f64(
    vmat: &[f64],
    tau: &[f64],
    m: usize,
    nb: usize,
    col_start: usize,
    col_end: usize,
) -> Vec<f64> {
    let width = col_end - col_start;
    let mut tmat = vec![0.0f64; width * width];
    for c in 0..width {
        let src_c = col_start + c;
        if tau[src_c] == 0.0 {
            continue;
        }
        tmat[c * width + c] = tau[src_c];
        for i in 0..c {
            let src_i = col_start + i;
            let mut dot = 0.0;
            for row in 0..m {
                dot += vmat[row * nb + src_i] * vmat[row * nb + src_c];
            }
            tmat[i * width + c] = -tau[src_c] * dot;
        }
        let mut newcol = vec![0.0f64; c];
        for i in 0..c {
            let mut s = 0.0;
            for l in i..c {
                s += tmat[i * width + l] * tmat[l * width + c];
            }
            newcol[i] = s;
        }
        for i in 0..c {
            tmat[i * width + c] = newcol[i];
        }
    }
    tmat
}

#[allow(clippy::too_many_arguments)]
fn qr_apply_panel_block_reflector_f64(
    r_mat: &mut [f64],
    m: usize,
    n: usize,
    panel_start: usize,
    nb: usize,
    vmat: &[f64],
    tau: &[f64],
    block_start: usize,
    block_end: usize,
    target_start: usize,
    target_end: usize,
) {
    let block_width = block_end - block_start;
    let target_width = target_end - target_start;
    if block_width == 0
        || target_width == 0
        || !tau[block_start..block_end]
            .iter()
            .any(|&value| value != 0.0)
    {
        return;
    }

    let first_row = panel_start + block_start;
    let active_rows = m - first_row;
    let tmat = qr_build_compact_wy_t_f64(vmat, tau, m, nb, block_start, block_end);
    let mut vblock = vec![0.0f64; active_rows * block_width];
    let mut vt = vec![0.0f64; block_width * active_rows];
    for local_row in 0..active_rows {
        let row = first_row + local_row;
        for c in 0..block_width {
            let value = vmat[row * nb + block_start + c];
            vblock[local_row * block_width + c] = value;
            vt[c * active_rows + local_row] = value;
        }
    }

    let target_col = panel_start + target_start;
    let mut panel_cols = vec![0.0f64; active_rows * target_width];
    for local_row in 0..active_rows {
        let row = first_row + local_row;
        let src = row * n + target_col;
        let dst = local_row * target_width;
        panel_cols[dst..dst + target_width].copy_from_slice(&r_mat[src..src + target_width]);
    }

    let mut work = vec![0.0f64; block_width * target_width];
    gemm::dgemm(
        block_width,
        active_rows,
        target_width,
        &vt,
        &panel_cols,
        &mut work,
    );
    let mut tt = vec![0.0f64; block_width * block_width];
    for i in 0..block_width {
        for j in 0..block_width {
            tt[i * block_width + j] = tmat[j * block_width + i];
        }
    }
    let mut reflected = vec![0.0f64; block_width * target_width];
    gemm::dgemm(
        block_width,
        block_width,
        target_width,
        &tt,
        &work,
        &mut reflected,
    );
    let mut update = vec![0.0f64; active_rows * target_width];
    gemm::dgemm(
        active_rows,
        block_width,
        target_width,
        &vblock,
        &reflected,
        &mut update,
    );
    for local_row in 0..active_rows {
        let row = first_row + local_row;
        let dst = row * n + target_col;
        let src = local_row * target_width;
        for c in 0..target_width {
            r_mat[dst + c] -= update[src + c];
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn qr_factor_panel_leaf_f64(
    r_mat: &mut [f64],
    m: usize,
    n: usize,
    panel_start: usize,
    leaf_start: usize,
    leaf_end: usize,
    nb: usize,
    vmat: &mut [f64],
    tau: &mut [f64],
    tiny: f64,
) {
    for c in leaf_start..leaf_end {
        let j = panel_start + c;
        let col_len = m - j;
        let mut nrm2 = 0.0;
        for t in 0..col_len {
            let x = r_mat[(j + t) * n + j];
            nrm2 += x * x;
        }
        let norm_v = nrm2.sqrt();
        if norm_v < tiny {
            continue;
        }
        let v0 = r_mat[j * n + j];
        let sign = if v0 >= 0.0 { 1.0 } else { -1.0 };
        vmat[j * nb + c] = v0 + sign * norm_v;
        for t in 1..col_len {
            vmat[(j + t) * nb + c] = r_mat[(j + t) * n + j];
        }
        let mut nv2 = 0.0;
        for t in 0..col_len {
            let x = vmat[(j + t) * nb + c];
            nv2 += x * x;
        }
        if nv2 < tiny {
            for t in 0..col_len {
                vmat[(j + t) * nb + c] = 0.0;
            }
            continue;
        }
        let tau_c = 2.0 / nv2;
        tau[c] = tau_c;
        // Reflected column j: diagonal = -sign*norm, below-diagonal = 0.
        r_mat[j * n + j] = -sign * norm_v;
        for t in 1..col_len {
            r_mat[(j + t) * n + j] = 0.0;
        }
        for col in (j + 1)..(panel_start + leaf_end) {
            let mut dot = 0.0;
            for t in 0..col_len {
                dot += vmat[(j + t) * nb + c] * r_mat[(j + t) * n + col];
            }
            let factor = tau_c * dot;
            for t in 0..col_len {
                r_mat[(j + t) * n + col] -= factor * vmat[(j + t) * nb + c];
            }
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn qr_factor_panel_recursive_f64(
    r_mat: &mut [f64],
    m: usize,
    n: usize,
    panel_start: usize,
    range_start: usize,
    range_end: usize,
    nb: usize,
    vmat: &mut [f64],
    tau: &mut [f64],
    tiny: f64,
) {
    const LEAF: usize = 8;
    if range_end - range_start <= LEAF {
        qr_factor_panel_leaf_f64(
            r_mat,
            m,
            n,
            panel_start,
            range_start,
            range_end,
            nb,
            vmat,
            tau,
            tiny,
        );
        return;
    }

    let mid = range_start + (range_end - range_start) / 2;
    qr_factor_panel_recursive_f64(
        r_mat,
        m,
        n,
        panel_start,
        range_start,
        mid,
        nb,
        vmat,
        tau,
        tiny,
    );
    qr_apply_panel_block_reflector_f64(
        r_mat,
        m,
        n,
        panel_start,
        nb,
        vmat,
        tau,
        range_start,
        mid,
        mid,
        range_end,
    );
    qr_factor_panel_recursive_f64(
        r_mat,
        m,
        n,
        panel_start,
        mid,
        range_end,
        nb,
        vmat,
        tau,
        tiny,
    );
}

fn qr_householder_panel_blocked_profiled(
    r_mat: &mut [f64],
    m: usize,
    n: usize,
    k: usize,
    qcols: usize,
    nb_block: usize,
    mut timings: Option<&mut QrStageTimings>,
) -> Vec<f64> {
    let nb_block = nb_block.max(1);
    let tiny = f64::EPSILON * 1e6;
    let profile_enabled = timings.is_some();
    // Forward pass reduces R and stores each panel's (V, T); Q is then built
    // (m×qcols) by a reverse dorgqr — so REDUCED tall matrices (qcols=k<m) cost
    // O(m·k²) instead of building the full m×m Q (O(m²·k)). frankentorch-ct2yy.
    let mut panels: Vec<(usize, Vec<f64>, Vec<f64>)> = Vec::new();
    let mut p = 0;
    while p < k {
        let pe = (p + nb_block).min(k);
        let nb = pe - p;

        // --- Panel factorization: build V (m×nb) and tau, applying each reflector
        //     only to the remaining PANEL columns (the trailing [pe,n) is deferred).
        let panel_start = qr_profile_stage_start(profile_enabled);
        let mut vmat = vec![0.0f64; m * nb];
        let mut tau = vec![0.0f64; nb];
        qr_factor_panel_recursive_f64(r_mat, m, n, p, 0, nb, nb, &mut vmat, &mut tau, tiny);

        // --- Compact-WY T (nb×nb upper triangular, LAPACK dlarft forward) so that
        //     H_p H_{p+1} ... H_{pe-1} = I - V T Vᵀ.
        let tmat = qr_build_compact_wy_t_f64(&vmat, &tau, m, nb, 0, nb);
        if let Some(timings) = timings.as_mut() {
            qr_profile_record_ns(&mut timings.panel_and_t_ns, panel_start);
        }

        // --- Apply block reflector to the trailing R[:, pe:n]: R -= V (Tᵀ (Vᵀ R)).
        let nt = n - pe;
        if nt > 0 {
            let trailing_start = qr_profile_stage_start(profile_enabled);
            let mut rt = vec![0.0f64; m * nt];
            for i in 0..m {
                let base = i * n + pe;
                let dst = i * nt;
                rt[dst..dst + nt].copy_from_slice(&r_mat[base..base + nt]);
            }
            let mut vt = vec![0.0f64; nb * m];
            for row in 0..m {
                for c in 0..nb {
                    vt[c * m + row] = vmat[row * nb + c];
                }
            }
            let mut w = vec![0.0f64; nb * nt];
            gemm::dgemm(nb, m, nt, &vt, &rt, &mut w); // Vᵀ R
            let mut tt = vec![0.0f64; nb * nb];
            for i in 0..nb {
                for jj in 0..nb {
                    tt[i * nb + jj] = tmat[jj * nb + i];
                }
            }
            let mut w2 = vec![0.0f64; nb * nt];
            gemm::dgemm(nb, nb, nt, &tt, &w, &mut w2); // Tᵀ (Vᵀ R)
            let mut upd = vec![0.0f64; m * nt];
            gemm::dgemm(m, nb, nt, &vmat, &w2, &mut upd); // V (...)
            for i in 0..m {
                let base = i * n + pe;
                let src = i * nt;
                for t in 0..nt {
                    r_mat[base + t] -= upd[src + t];
                }
            }
            if let Some(timings) = timings.as_mut() {
                qr_profile_record_ns(&mut timings.trailing_r_ns, trailing_start);
            }
        }

        panels.push((nb, vmat, tmat));
        p = pe;
    }

    // --- Reverse dorgqr: Q (m×qcols) = H_0 H_1 ... H_{k-1} · I[:, :qcols].
    // Start X = I[:, :qcols]; apply blocks innermost-first (reverse panel order),
    // each Q_block · X = X - V (T (Vᵀ X)).
    let reverse_start = qr_profile_stage_start(profile_enabled);
    let mut x = vec![0.0f64; m * qcols];
    for i in 0..m.min(qcols) {
        x[i * qcols + i] = 1.0;
    }
    for (nb, vmat, tmat) in panels.iter().rev() {
        let nb = *nb;
        let mut vt = vec![0.0f64; nb * m];
        for row in 0..m {
            for c in 0..nb {
                vt[c * m + row] = vmat[row * nb + c];
            }
        }
        let mut w1 = vec![0.0f64; nb * qcols];
        gemm::dgemm(nb, m, qcols, &vt, &x, &mut w1); // Vᵀ X
        let mut w2 = vec![0.0f64; nb * qcols];
        gemm::dgemm(nb, nb, qcols, tmat, &w1, &mut w2); // T (Vᵀ X)
        let mut upd = vec![0.0f64; m * qcols];
        gemm::dgemm(m, nb, qcols, vmat, &w2, &mut upd); // V (...)
        for t in 0..m * qcols {
            x[t] -= upd[t];
        }
    }
    if let Some(timings) = timings.as_mut() {
        qr_profile_record_ns(&mut timings.reverse_q_ns, reverse_start);
    }
    x
}

fn qr_householder_panel_blocked(
    r_mat: &mut [f64],
    m: usize,
    n: usize,
    k: usize,
    qcols: usize,
) -> Vec<f64> {
    qr_householder_panel_blocked_profiled(r_mat, m, n, k, qcols, 32, None)
}

/// A/B entry point (NOT production dispatch): runs the blocked compact-WY QR with
/// a caller-chosen panel width `nb_block`, so a same-worker A/B can find the NB
/// that best amortizes the skinny-K trailing/reverse GEMMs. frankentorch-ct2yy.
#[doc(hidden)]
pub fn qr_householder_panel_blocked_nb_ab(
    r_mat: &mut [f64],
    m: usize,
    n: usize,
    k: usize,
    qcols: usize,
    nb_block: usize,
) -> Vec<f64> {
    qr_householder_panel_blocked_profiled(r_mat, m, n, k, qcols, nb_block, None)
}

/// Native f32 compact-WY blocked QR panel factorization (the f32 companion to
/// `qr_householder_panel_blocked_profiled`, profiling stripped). Reduces `r_mat`
/// in place and returns Q (m×qcols) via a reverse dorgqr, with `gemm::sgemm`
/// trailing/Q updates. frankentorch-b3o90.
fn qr_householder_panel_blocked_f32(
    r_mat: &mut [f32],
    m: usize,
    n: usize,
    k: usize,
    qcols: usize,
) -> Vec<f32> {
    const NB: usize = 32;
    let tiny = f32::EPSILON * 1e6;
    let mut panels: Vec<(usize, Vec<f32>, Vec<f32>)> = Vec::new();
    let mut p = 0;
    while p < k {
        let pe = (p + NB).min(k);
        let nb = pe - p;

        let mut vmat = vec![0.0f32; m * nb];
        let mut tau = vec![0.0f32; nb];
        for c in 0..nb {
            let j = p + c;
            let col_len = m - j;
            let mut nrm2 = 0.0f32;
            for t in 0..col_len {
                let x = r_mat[(j + t) * n + j];
                nrm2 += x * x;
            }
            let norm_v = nrm2.sqrt();
            if norm_v < tiny {
                continue;
            }
            let v0 = r_mat[j * n + j];
            let sign = if v0 >= 0.0 { 1.0 } else { -1.0 };
            vmat[j * nb + c] = v0 + sign * norm_v;
            for t in 1..col_len {
                vmat[(j + t) * nb + c] = r_mat[(j + t) * n + j];
            }
            let mut nv2 = 0.0f32;
            for t in 0..col_len {
                let x = vmat[(j + t) * nb + c];
                nv2 += x * x;
            }
            if nv2 < tiny {
                for t in 0..col_len {
                    vmat[(j + t) * nb + c] = 0.0;
                }
                continue;
            }
            let tau_c = 2.0 / nv2;
            tau[c] = tau_c;
            r_mat[j * n + j] = -sign * norm_v;
            for t in 1..col_len {
                r_mat[(j + t) * n + j] = 0.0;
            }
            for col in (j + 1)..pe {
                let mut dot = 0.0f32;
                for t in 0..col_len {
                    dot += vmat[(j + t) * nb + c] * r_mat[(j + t) * n + col];
                }
                let factor = tau_c * dot;
                for t in 0..col_len {
                    r_mat[(j + t) * n + col] -= factor * vmat[(j + t) * nb + c];
                }
            }
        }

        let mut tmat = vec![0.0f32; nb * nb];
        for c in 0..nb {
            if tau[c] == 0.0 {
                continue;
            }
            tmat[c * nb + c] = tau[c];
            for i in 0..c {
                let mut dot = 0.0f32;
                for row in 0..m {
                    dot += vmat[row * nb + i] * vmat[row * nb + c];
                }
                tmat[i * nb + c] = -tau[c] * dot;
            }
            let mut newcol = vec![0.0f32; c];
            for i in 0..c {
                let mut s = 0.0f32;
                for l in i..c {
                    s += tmat[i * nb + l] * tmat[l * nb + c];
                }
                newcol[i] = s;
            }
            for i in 0..c {
                tmat[i * nb + c] = newcol[i];
            }
        }

        let nt = n - pe;
        if nt > 0 {
            let mut rt = vec![0.0f32; m * nt];
            for i in 0..m {
                let base = i * n + pe;
                let dst = i * nt;
                rt[dst..dst + nt].copy_from_slice(&r_mat[base..base + nt]);
            }
            let mut vt = vec![0.0f32; nb * m];
            for row in 0..m {
                for c in 0..nb {
                    vt[c * m + row] = vmat[row * nb + c];
                }
            }
            let mut w = vec![0.0f32; nb * nt];
            gemm::sgemm(nb, m, nt, &vt, &rt, &mut w); // Vᵀ R
            let mut tt = vec![0.0f32; nb * nb];
            for i in 0..nb {
                for jj in 0..nb {
                    tt[i * nb + jj] = tmat[jj * nb + i];
                }
            }
            let mut w2 = vec![0.0f32; nb * nt];
            gemm::sgemm(nb, nb, nt, &tt, &w, &mut w2); // Tᵀ (Vᵀ R)
            let mut upd = vec![0.0f32; m * nt];
            gemm::sgemm(m, nb, nt, &vmat, &w2, &mut upd); // V (...)
            for i in 0..m {
                let base = i * n + pe;
                let src = i * nt;
                for t in 0..nt {
                    r_mat[base + t] -= upd[src + t];
                }
            }
        }

        panels.push((nb, vmat, tmat));
        p = pe;
    }

    let mut x = vec![0.0f32; m * qcols];
    for i in 0..m.min(qcols) {
        x[i * qcols + i] = 1.0;
    }
    for (nb, vmat, tmat) in panels.iter().rev() {
        let nb = *nb;
        let mut vt = vec![0.0f32; nb * m];
        for row in 0..m {
            for c in 0..nb {
                vt[c * m + row] = vmat[row * nb + c];
            }
        }
        let mut w1 = vec![0.0f32; nb * qcols];
        gemm::sgemm(nb, m, qcols, &vt, &x, &mut w1); // Vᵀ X
        let mut w2 = vec![0.0f32; nb * qcols];
        gemm::sgemm(nb, nb, qcols, tmat, &w1, &mut w2); // T (Vᵀ X)
        let mut upd = vec![0.0f32; m * qcols];
        gemm::sgemm(m, nb, qcols, vmat, &w2, &mut upd); // V (...)
        for t in 0..m * qcols {
            x[t] -= upd[t];
        }
    }
    x
}

/// Native f32 QR factorization — the f32 companion to [`qr_contiguous_f64`].
/// Blocked compact-WY (BLAS-3 `gemm::sgemm`) for m>=128 && k>=16; scalar
/// Householder sweep below that. Computed entirely in f32 so the public f32 QR
/// avoids the f32->f64->f32 round trip and matches torch's f32 QR (tolerance
/// parity: blocked WY reassociates). frankentorch-b3o90.
/// f32 mirror of [`qr_batched_contiguous_f64`]: batched QR `[..., m, n]` -> `(Q [B*m*kq], R [B*kq*n])`
/// f32, native, parallel over the batch. Bit-identical to looping the 2-D f32 qr. (BlackThrush)
pub fn qr_batched_contiguous_f32(
    data: &[f32],
    meta: &TensorMeta,
    reduced: bool,
) -> Result<(Vec<f32>, Vec<f32>), KernelError> {
    ensure_unary_layout_and_storage_f32(data, meta)?;
    let shape = meta.shape();
    let nd = shape.len();
    if nd < 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![nd],
        });
    }
    let m = shape[nd - 2];
    let n = shape[nd - 1];
    let kq = if reduced { m.min(n) } else { m };
    let bb: usize = shape[..nd - 2].iter().product();
    let plane = m * n;
    let qp = m * kq;
    let rp = kq * n;
    let offset = meta.storage_offset();
    let data = &data[offset..offset + bb * plane];
    let pmeta = TensorMeta::from_shape(vec![m, n], DType::F32, Device::Cpu);
    let mut q_out = vec![0.0f32; bb * qp];
    let mut r_out = vec![0.0f32; bb * rp];
    let first_err = std::sync::Mutex::new(None);
    q_out
        .par_chunks_mut(qp)
        .zip(r_out.par_chunks_mut(rp))
        .zip(data.par_chunks(plane))
        .for_each(|((qc, rc), pl)| match qr_contiguous_f32(pl, &pmeta, reduced) {
            Ok(res) => {
                qc.copy_from_slice(&res.q);
                rc.copy_from_slice(&res.r);
            }
            Err(e) => {
                let mut g = first_err.lock().unwrap();
                if g.is_none() {
                    *g = Some(e);
                }
            }
        });
    if let Some(e) = first_err.into_inner().unwrap() {
        return Err(e);
    }
    Ok((q_out, r_out))
}

pub fn qr_contiguous_f32(
    data: &[f32],
    meta: &TensorMeta,
    reduced: bool,
) -> Result<QrResultF32, KernelError> {
    ensure_unary_layout_and_storage_f32(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![shape.len()],
        });
    }
    let m = shape[0];
    let n = shape[1];

    if m == 0 || n == 0 {
        let k = if reduced { m.min(n) } else { m };
        return Ok(QrResultF32 {
            q: vec![0.0; m * k],
            r: vec![0.0; k * n],
            m: k,
            n,
        });
    }

    let k = m.min(n);
    let offset = meta.storage_offset();
    let mut r_mat = data[offset..offset + m * n].to_vec();

    if m >= 128 && k >= 16 {
        let qcols = if reduced { k } else { m };
        let q = qr_householder_panel_blocked_f32(&mut r_mat, m, n, k, qcols);
        for i in 0..m {
            for jj in 0..i.min(n) {
                r_mat[i * n + jj] = 0.0;
            }
        }
        if reduced {
            let r_reduced = r_mat[..k * n].to_vec();
            return Ok(QrResultF32 {
                q,
                r: r_reduced,
                m: k,
                n,
            });
        }
        return Ok(QrResultF32 { q, r: r_mat, m, n });
    }

    let mut q_mat = vec![0.0f32; m * m];
    for i in 0..m {
        q_mat[i * m + i] = 1.0;
    }

    for j in 0..k {
        let col_len = m - j;
        let mut v = vec![0.0f32; col_len];
        for i in 0..col_len {
            v[i] = r_mat[(i + j) * n + j];
        }
        let norm_v: f32 = v.iter().map(|x| x * x).sum::<f32>().sqrt();
        if norm_v < f32::EPSILON * 1e6 {
            continue;
        }
        let sign = if v[0] >= 0.0 { 1.0 } else { -1.0 };
        v[0] += sign * norm_v;
        let norm_v2: f32 = v.iter().map(|x| x * x).sum();
        if norm_v2 < f32::EPSILON * 1e6 {
            continue;
        }
        let inv_norm = 1.0 / norm_v2;
        for col in 0..n {
            let mut dot = 0.0f32;
            for i in 0..col_len {
                dot += v[i] * r_mat[(i + j) * n + col];
            }
            let factor = 2.0 * dot * inv_norm;
            for i in 0..col_len {
                r_mat[(i + j) * n + col] -= factor * v[i];
            }
        }
        for row in 0..m {
            let mut dot = 0.0f32;
            for i in 0..col_len {
                dot += q_mat[row * m + (i + j)] * v[i];
            }
            let factor = 2.0 * dot * inv_norm;
            for i in 0..col_len {
                q_mat[row * m + (i + j)] -= factor * v[i];
            }
        }
    }

    for i in 0..m {
        for j in 0..i.min(n) {
            r_mat[i * n + j] = 0.0;
        }
    }

    if reduced {
        let mut q_reduced = vec![0.0f32; m * k];
        for i in 0..m {
            for j in 0..k {
                q_reduced[i * k + j] = q_mat[i * m + j];
            }
        }
        let r_reduced = r_mat[..k * n].to_vec();
        Ok(QrResultF32 {
            q: q_reduced,
            r: r_reduced,
            m: k,
            n,
        })
    } else {
        Ok(QrResultF32 {
            q: q_mat,
            r: r_mat,
            m,
            n,
        })
    }
}

/// Batched QR: input `[..., m, n]` -> `(Q [B*m*kq], R [B*kq*n])` row-major, kq = min(m,n) if reduced
/// else m. Parallelizes the verified 2-D [`qr_contiguous_f64`] over the batch. PyTorch loops LAPACK per
/// plane (per-call overhead dominates for small m,n). Bit-identical to looping the 2-D qr.
/// frankentorch-batched-eigh. (BlackThrush)
pub fn qr_batched_contiguous_f64(
    data: &[f64],
    meta: &TensorMeta,
    reduced: bool,
) -> Result<(Vec<f64>, Vec<f64>), KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    let nd = shape.len();
    if nd < 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![nd],
        });
    }
    let m = shape[nd - 2];
    let n = shape[nd - 1];
    let kq = if reduced { m.min(n) } else { m };
    let bb: usize = shape[..nd - 2].iter().product();
    let plane = m * n;
    let qp = m * kq;
    let rp = kq * n;
    let offset = meta.storage_offset();
    let data = &data[offset..offset + bb * plane];
    let pmeta = TensorMeta::from_shape(vec![m, n], DType::F64, Device::Cpu);
    let mut q_out = vec![0.0f64; bb * qp];
    let mut r_out = vec![0.0f64; bb * rp];
    let first_err = std::sync::Mutex::new(None);
    q_out
        .par_chunks_mut(qp)
        .zip(r_out.par_chunks_mut(rp))
        .zip(data.par_chunks(plane))
        .for_each(|((qc, rc), pl)| match qr_contiguous_f64(pl, &pmeta, reduced) {
            Ok(res) => {
                qc.copy_from_slice(&res.q);
                rc.copy_from_slice(&res.r);
            }
            Err(e) => {
                let mut g = first_err.lock().unwrap();
                if g.is_none() {
                    *g = Some(e);
                }
            }
        });
    if let Some(e) = first_err.into_inner().unwrap() {
        return Err(e);
    }
    Ok((q_out, r_out))
}

pub fn qr_contiguous_f64(
    data: &[f64],
    meta: &TensorMeta,
    reduced: bool,
) -> Result<QrResult, KernelError> {
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![shape.len()],
        });
    }
    let m = shape[0];
    let n = shape[1];

    if m == 0 || n == 0 {
        let k = if reduced { m.min(n) } else { m };
        return Ok(QrResult {
            q: vec![0.0; m * k],
            r: vec![0.0; k * n],
            m: k,
            n,
        });
    }

    let k = m.min(n);
    let offset = meta.storage_offset();

    // Copy A into working matrix R (m x n, row-major)
    let mut r_mat = data[offset..offset + m * n].to_vec();

    // Blocked compact-WY path (BLAS-3) for sizes where the GEMM trailing update
    // beats the per-reflector BLAS-2 sweep; small matrices stay on the scalar
    // sweep (no panel/GEMM overhead). The reverse dorgqr builds Q directly at the
    // output width (m×k for reduced, m×m for full), so reduced tall QR skips the
    // full m×m Q. frankentorch-ct2yy.
    if m >= 128 && k >= 16 {
        let qcols = if reduced { k } else { m };
        let q = qr_householder_panel_blocked(&mut r_mat, m, n, k, qcols);
        for i in 0..m {
            for jj in 0..i.min(n) {
                r_mat[i * n + jj] = 0.0;
            }
        }
        if reduced {
            let r_reduced = r_mat[..k * n].to_vec();
            return Ok(QrResult {
                q,
                r: r_reduced,
                m: k,
                n,
            });
        }
        return Ok(QrResult { q, r: r_mat, m, n });
    }

    // Build Q as product of Householder reflections, starting as identity (m x m)
    let mut q_mat = vec![0.0; m * m];
    for i in 0..m {
        q_mat[i * m + i] = 1.0;
    }

    for j in 0..k {
        // Extract the column vector below the diagonal: v = R[j:m, j]
        let col_len = m - j;
        let mut v = vec![0.0; col_len];
        for i in 0..col_len {
            v[i] = r_mat[(i + j) * n + j];
        }

        // Compute the Householder reflection: v[0] += sign(v[0]) * ||v||
        let norm_v: f64 = v.iter().map(|x| x * x).sum::<f64>().sqrt();
        if norm_v < f64::EPSILON * 1e6 {
            continue; // Skip near-zero column
        }
        let sign = if v[0] >= 0.0 { 1.0 } else { -1.0 };
        v[0] += sign * norm_v;

        // Normalize v
        let norm_v2: f64 = v.iter().map(|x| x * x).sum();
        if norm_v2 < f64::EPSILON * 1e6 {
            continue;
        }
        let inv_norm = 1.0 / norm_v2;

        // Apply Householder to R: R[j:m, :] -= 2 * v * (v^T @ R[j:m, :]). Each
        // output column's factor is an INDEPENDENT dot over the reflected rows,
        // and each reflected row's update is independent, so both fan out with
        // the SAME fp op order -> bit-for-bit identical to the serial sweep. The
        // factor `2*dot*inv_norm` is folded into `w` so the update keeps the exact
        // `factor * v[i]` association.
        const QR_PAR_WORK: u64 = 1 << 14;
        let r_work = (col_len as u64) * (n as u64);
        if r_work >= QR_PAR_WORK {
            let mut w = vec![0.0f64; n];
            {
                let r_ref: &[f64] = &r_mat;
                w.par_iter_mut().enumerate().for_each(|(col, wc)| {
                    let mut dot = 0.0;
                    for i in 0..col_len {
                        dot += v[i] * r_ref[(i + j) * n + col];
                    }
                    *wc = 2.0 * dot * inv_norm;
                });
            }
            let (_, tail) = r_mat.split_at_mut(j * n);
            tail.par_chunks_mut(n).enumerate().for_each(|(i, row)| {
                let vi = v[i];
                for col in 0..n {
                    row[col] -= w[col] * vi;
                }
            });
        } else {
            for col in 0..n {
                let mut dot = 0.0;
                for i in 0..col_len {
                    dot += v[i] * r_mat[(i + j) * n + col];
                }
                let factor = 2.0 * dot * inv_norm;
                for i in 0..col_len {
                    r_mat[(i + j) * n + col] -= factor * v[i];
                }
            }
        }

        // Apply Householder to Q: Q[:, j:m] -= 2 * Q[:, j:m] @ v * v^T. Each row of
        // Q is independent and contiguous -> clean bit-exact row fan-out.
        let q_work = (m as u64) * (col_len as u64);
        if q_work >= QR_PAR_WORK {
            q_mat.par_chunks_mut(m).for_each(|q_row| {
                let mut dot = 0.0;
                for i in 0..col_len {
                    dot += q_row[i + j] * v[i];
                }
                let factor = 2.0 * dot * inv_norm;
                for i in 0..col_len {
                    q_row[i + j] -= factor * v[i];
                }
            });
        } else {
            for row in 0..m {
                let mut dot = 0.0;
                for i in 0..col_len {
                    dot += q_mat[row * m + (i + j)] * v[i];
                }
                let factor = 2.0 * dot * inv_norm;
                for i in 0..col_len {
                    q_mat[row * m + (i + j)] -= factor * v[i];
                }
            }
        }
    }

    // Clean up R: zero out below-diagonal elements
    for i in 0..m {
        for j in 0..i.min(n) {
            r_mat[i * n + j] = 0.0;
        }
    }

    if reduced {
        // Q is m x k (first k columns of full Q)
        let mut q_reduced = vec![0.0; m * k];
        for i in 0..m {
            for j in 0..k {
                q_reduced[i * k + j] = q_mat[i * m + j];
            }
        }
        // R is k x n (first k rows of full R)
        let r_reduced = r_mat[..k * n].to_vec();
        Ok(QrResult {
            q: q_reduced,
            r: r_reduced,
            m: k,
            n,
        })
    } else {
        // Q is m x m, R is m x n
        Ok(QrResult {
            q: q_mat,
            r: r_mat,
            m,
            n,
        })
    }
}

/// Profile the existing QR implementation without changing public QR dispatch.
#[doc(hidden)]
pub fn qr_contiguous_f64_stage_profile(
    data: &[f64],
    meta: &TensorMeta,
    reduced: bool,
) -> Result<QrStageProfile, KernelError> {
    let total_start = std::time::Instant::now();
    ensure_unary_layout_and_storage(data, meta)?;
    let shape = meta.shape();
    if shape.len() != 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: shape.to_vec(),
            rhs: vec![shape.len()],
        });
    }
    let m = shape[0];
    let n = shape[1];

    if m == 0 || n == 0 {
        let k = if reduced { m.min(n) } else { m };
        let result = QrResult {
            q: vec![0.0; m * k],
            r: vec![0.0; k * n],
            m: k,
            n,
        };
        return Ok(QrStageProfile {
            result,
            timings: QrStageTimings {
                total_ns: total_start.elapsed().as_nanos(),
                ..QrStageTimings::default()
            },
            used_blocked_path: false,
        });
    }

    let k = m.min(n);
    if m < 128 || k < 16 {
        let result = qr_contiguous_f64(data, meta, reduced)?;
        return Ok(QrStageProfile {
            result,
            timings: QrStageTimings {
                total_ns: total_start.elapsed().as_nanos(),
                ..QrStageTimings::default()
            },
            used_blocked_path: false,
        });
    }

    let mut timings = QrStageTimings::default();
    let offset = meta.storage_offset();
    let copy_start = std::time::Instant::now();
    let mut r_mat = data[offset..offset + m * n].to_vec();
    qr_profile_record_ns(&mut timings.copy_zeroing_ns, Some(copy_start));

    let qcols = if reduced { k } else { m };
    let q = qr_householder_panel_blocked_profiled(&mut r_mat, m, n, k, qcols, 32, Some(&mut timings));

    let zero_start = std::time::Instant::now();
    for i in 0..m {
        for jj in 0..i.min(n) {
            r_mat[i * n + jj] = 0.0;
        }
    }
    let result = if reduced {
        let r_reduced = r_mat[..k * n].to_vec();
        QrResult {
            q,
            r: r_reduced,
            m: k,
            n,
        }
    } else {
        QrResult { q, r: r_mat, m, n }
    };
    qr_profile_record_ns(&mut timings.copy_zeroing_ns, Some(zero_start));
    timings.total_ns = total_start.elapsed().as_nanos();

    Ok(QrStageProfile {
        result,
        timings,
        used_blocked_path: true,
    })
}

// =========================================================================
// f32 kernel functions (bd-2do9.3)
// =========================================================================

fn ensure_storage_len_f32(
    buffer: &[f32],
    meta: &TensorMeta,
    side: &'static str,
) -> Result<(), KernelError> {
    let needed = contiguous_required_len(meta, side)?;
    if buffer.len() < needed {
        return Err(KernelError::InsufficientStorage {
            side,
            needed,
            available: buffer.len(),
        });
    }
    Ok(())
}

fn ensure_unary_layout_and_storage_f32(
    buffer: &[f32],
    meta: &TensorMeta,
) -> Result<(), KernelError> {
    if !meta.is_contiguous() {
        return Err(KernelError::UnsupportedLayout { side: "input" });
    }
    ensure_storage_len_f32(buffer, meta, "input")
}

const SIMD_WIDTH_F32: usize = 8;

fn simd_unary_f32<F, S>(window: &[f32], scalar_op: F, simd_op: S) -> Vec<f32>
where
    F: Fn(f32) -> f32,
    S: Fn(f32x8) -> f32x8,
{
    let numel = window.len();
    let simd_len = numel / SIMD_WIDTH_F32 * SIMD_WIDTH_F32;
    let mut output = Vec::with_capacity(numel);

    for i in (0..simd_len).step_by(SIMD_WIDTH_F32) {
        let a = f32x8::new([
            window[i],
            window[i + 1],
            window[i + 2],
            window[i + 3],
            window[i + 4],
            window[i + 5],
            window[i + 6],
            window[i + 7],
        ]);
        let result = simd_op(a);
        output.extend_from_slice(result.as_array_ref());
    }

    for &value in &window[simd_len..numel] {
        output.push(scalar_op(value));
    }

    output
}

fn simd_binary_f32<F, S>(
    lhs_window: &[f32],
    rhs_window: &[f32],
    scalar_op: F,
    simd_op: S,
) -> Vec<f32>
where
    F: Fn(f32, f32) -> f32,
    S: Fn(f32x8, f32x8) -> f32x8,
{
    let numel = lhs_window.len();
    let simd_len = numel / SIMD_WIDTH_F32 * SIMD_WIDTH_F32;
    let mut output = Vec::with_capacity(numel);

    for i in (0..simd_len).step_by(SIMD_WIDTH_F32) {
        let a = f32x8::new([
            lhs_window[i],
            lhs_window[i + 1],
            lhs_window[i + 2],
            lhs_window[i + 3],
            lhs_window[i + 4],
            lhs_window[i + 5],
            lhs_window[i + 6],
            lhs_window[i + 7],
        ]);
        let b = f32x8::new([
            rhs_window[i],
            rhs_window[i + 1],
            rhs_window[i + 2],
            rhs_window[i + 3],
            rhs_window[i + 4],
            rhs_window[i + 5],
            rhs_window[i + 6],
            rhs_window[i + 7],
        ]);
        let result = simd_op(a, b);
        output.extend_from_slice(result.as_array_ref());
    }

    for i in simd_len..numel {
        output.push(scalar_op(lhs_window[i], rhs_window[i]));
    }

    output
}

fn unary_contiguous_f32<F>(
    input: &[f32],
    meta: &TensorMeta,
    op: F,
    parallel_threshold: usize,
) -> Result<Vec<f32>, KernelError>
where
    F: Fn(f32) -> f32 + Sync,
{
    ensure_unary_layout_and_storage_f32(input, meta)?;
    let numel = meta.numel();
    if numel == 0 {
        return Ok(Vec::new());
    }
    let start = meta.storage_offset();
    let window = &input[start..start + numel];
    // f32 transcendental unary ops were entirely serial; spread the compute-bound
    // ones across the rayon pool above their (low) threshold. Pure per-element map,
    // so the parallel result is bit-identical to serial. frankentorch-kgs4.90.
    if numel >= parallel_threshold {
        Ok(window.par_iter().map(|value| op(*value)).collect())
    } else {
        Ok(window.iter().map(|value| op(*value)).collect())
    }
}

fn simd_unary_f32_kernel<F, S>(
    input: &[f32],
    meta: &TensorMeta,
    scalar_op: F,
    simd_op: S,
) -> Result<Vec<f32>, KernelError>
where
    F: Fn(f32) -> f32,
    S: Fn(f32x8) -> f32x8,
{
    ensure_unary_layout_and_storage_f32(input, meta)?;
    let numel = meta.numel();
    if numel == 0 {
        return Ok(Vec::new());
    }
    let start = meta.storage_offset();
    let window = &input[start..start + numel];
    Ok(simd_unary_f32(window, scalar_op, simd_op))
}

fn elementwise_contiguous_f32<F>(
    lhs: &[f32],
    rhs: &[f32],
    lhs_meta: &TensorMeta,
    rhs_meta: &TensorMeta,
    op: F,
    parallel_threshold: usize,
) -> Result<Vec<f32>, KernelError>
where
    F: Fn(f32, f32) -> f32 + Sync,
{
    ensure_meta_shape_and_dtype(lhs_meta, rhs_meta)?;
    ensure_storage_len_f32(lhs, lhs_meta, "lhs")?;
    ensure_storage_len_f32(rhs, rhs_meta, "rhs")?;
    let numel = lhs_meta.numel();
    if numel == 0 {
        return Ok(Vec::new());
    }
    let lhs_start = lhs_meta.storage_offset();
    let rhs_start = rhs_meta.storage_offset();
    let lhs_window = &lhs[lhs_start..lhs_start + numel];
    let rhs_window = &rhs[rhs_start..rhs_start + numel];
    // f32 macro binary kernels were entirely serial (mirrors the pre-kgs4.90 f32
    // unary gap). Compute-bound ones (atan2) parallelise cleanly above their low
    // threshold; pure per-element map, so par == serial bit-for-bit. The cheap
    // ops keep a high default threshold so rayon split/join only amortises at the
    // very large sizes where even a bandwidth-bound map benefits.
    if numel >= parallel_threshold {
        Ok(lhs_window
            .par_iter()
            .zip(rhs_window.par_iter())
            .map(|(left, right)| op(*left, *right))
            .collect())
    } else {
        Ok(lhs_window
            .iter()
            .zip(rhs_window.iter())
            .map(|(left, right)| op(*left, *right))
            .collect())
    }
}

fn simd_elementwise_f32<F, S>(
    lhs: &[f32],
    rhs: &[f32],
    lhs_meta: &TensorMeta,
    rhs_meta: &TensorMeta,
    scalar_op: F,
    simd_op: S,
) -> Result<Vec<f32>, KernelError>
where
    F: Fn(f32, f32) -> f32,
    S: Fn(f32x8, f32x8) -> f32x8,
{
    ensure_meta_shape_and_dtype(lhs_meta, rhs_meta)?;
    ensure_storage_len_f32(lhs, lhs_meta, "lhs")?;
    ensure_storage_len_f32(rhs, rhs_meta, "rhs")?;
    let numel = lhs_meta.numel();
    if numel == 0 {
        return Ok(Vec::new());
    }
    let lhs_start = lhs_meta.storage_offset();
    let rhs_start = rhs_meta.storage_offset();
    let lhs_window = &lhs[lhs_start..lhs_start + numel];
    let rhs_window = &rhs[rhs_start..rhs_start + numel];
    Ok(simd_binary_f32(lhs_window, rhs_window, scalar_op, simd_op))
}

/// Least-squares solve `min ||A·X - B||` for an overdetermined, full-rank
/// `A` (`m >= n`) via a reduced QR factorization: `A = Q·R`, then
/// `R·X = Qᵀ·B` by back-substitution. This is the unique least-squares
/// solution, identical (to tolerance) to the SVD pseudo-inverse path, but it
/// replaces the O(n³)-but-BLAS-1 Golub–Reinsch SVD with the parallel
/// Householder QR.
///
/// Returns `Ok(None)` when the QR fast path does not apply or is unsafe — `m <
/// n` (underdetermined) or a (near-)rank-deficient `R` (a tiny diagonal) — so
/// the caller falls back to the SVD pseudo-inverse, which yields the
/// minimum-norm solution PyTorch returns for those cases.
pub fn lstsq_qr_contiguous_f64(
    a_data: &[f64],
    a_meta: &TensorMeta,
    b_data: &[f64],
    b_meta: &TensorMeta,
) -> Result<Option<Vec<f64>>, KernelError> {
    ensure_unary_layout_and_storage(a_data, a_meta)?;
    ensure_unary_layout_and_storage(b_data, b_meta)?;
    let a_shape = a_meta.shape();
    let b_shape = b_meta.shape();
    if a_shape.len() != 2 || b_shape.len() != 2 {
        return Err(KernelError::ShapeMismatch {
            lhs: a_shape.to_vec(),
            rhs: b_shape.to_vec(),
        });
    }
    let m = a_shape[0];
    let n = a_shape[1];
    let k = b_shape[1];
    if b_shape[0] != m {
        return Err(KernelError::ShapeMismatch {
            lhs: a_shape.to_vec(),
            rhs: b_shape.to_vec(),
        });
    }
    // Only the overdetermined full-rank case is handled here; everything else
    // defers to the SVD pseudo-inverse.
    if m == 0 || n == 0 || k == 0 || m < n {
        return Ok(None);
    }

    // Least squares solves R·X = Qᵀ·B for A = Q·R (X = R⁻¹·Qᵀ·B, invariant to the
    // QR sign convention). Use the BLOCKED compact-WY QR (BLAS-3 + parallel —
    // qr_contiguous_f64) instead of an unblocked per-reflector scalar sweep, form
    // Qᵀ·B via the parallel cache-blocked GEMM, then a small back-substitution.
    // Reassociates → tolerance (lstsq is tolerance-parity; the rank guard still
    // defers near-rank-deficient inputs to the SVD minimum-norm path).
    // frankentorch-kgs4.85.
    let b_offset = b_meta.storage_offset();
    let b = &b_data[b_offset..b_offset + m * k];
    let qr = match qr_contiguous_f64(a_data, a_meta, true) {
        Ok(qr) => qr,
        Err(_) => return Ok(None),
    };
    let q = qr.q; // m×n (reduced)
    let r = qr.r; // n×n upper triangular
    // Full-rank guard on R's diagonal (defer near-rank-deficient to SVD).
    let mut max_diag = 0.0_f64;
    for i in 0..n {
        max_diag = max_diag.max(r[i * n + i].abs());
    }
    if max_diag == 0.0 {
        return Ok(None);
    }
    let rank_tol = max_diag * f64::EPSILON * (m.max(n) as f64);
    for i in 0..n {
        if r[i * n + i].abs() <= rank_tol {
            return Ok(None);
        }
    }
    // Qᵀ·B  [n×k].
    let mut qt = vec![0.0_f64; n * m];
    for t in 0..m {
        for i in 0..n {
            qt[i * m + t] = q[t * n + i];
        }
    }
    let mut qtb = vec![0.0_f64; n * k];
    gemm::dgemm(n, m, k, &qt, b, &mut qtb);
    // Back-substitute R·X = Qᵀ·B.
    let mut x = vec![0.0_f64; n * k];
    for c in 0..k {
        for i in (0..n).rev() {
            let mut acc = qtb[i * k + c];
            for jj in (i + 1)..n {
                acc -= r[i * n + jj] * x[jj * k + c];
            }
            x[i * k + c] = acc / r[i * n + i];
        }
    }
    Ok(Some(x))
}

fn pinv_qr_full_column_rank_f64(a: &[f64], m: usize, n: usize) -> Option<Vec<f64>> {
    if m == 0 || n == 0 || m < n {
        return None;
    }
    // For full column rank, A = Q·R ⇒ A⁺ = R⁻¹·Qᵀ (sign-convention invariant, since
    // Q/R sign flips cancel). Use the BLOCKED compact-WY QR (BLAS-3, parallel —
    // qr_contiguous_f64) instead of an unblocked per-reflector scalar sweep, then
    // form R⁻¹ (small triangular back-sub) and the final R⁻¹·Qᵀ via the parallel
    // cache-blocked GEMM. Reassociates → tolerance (pinv is tolerance-parity,
    // validated by reconstruction). frankentorch-kgs4.84.
    let a_meta = TensorMeta::from_shape(vec![m, n], DType::F64, Device::Cpu);
    let qr = qr_contiguous_f64(a, &a_meta, true).ok()?;
    let q = qr.q; // m×n (reduced)
    let r = qr.r; // n×n upper triangular
    // Near-rank-deficiency guard on R's diagonal (defer those to the SVD path).
    let mut max_diag = 0.0_f64;
    for i in 0..n {
        max_diag = max_diag.max(r[i * n + i].abs());
    }
    if max_diag == 0.0 {
        return None;
    }
    let rank_tol = max_diag * f64::EPSILON.sqrt() * (m.max(n) as f64);
    for i in 0..n {
        if r[i * n + i].abs() <= rank_tol {
            return None;
        }
    }
    // R⁻¹ (upper triangular) by back-substitution: solve R·Rinv = I.
    let mut rinv = vec![0.0_f64; n * n];
    for j in 0..n {
        rinv[j * n + j] = 1.0 / r[j * n + j];
        for i in (0..j).rev() {
            let mut acc = 0.0_f64;
            for l in (i + 1)..=j {
                acc += r[i * n + l] * rinv[l * n + j];
            }
            rinv[i * n + j] = -acc / r[i * n + i];
        }
    }
    // pinv = R⁻¹ · Qᵀ  [n×m].
    let mut pinv = vec![0.0_f64; n * m];
    gemm::dgemm_bt(n, n, m, &rinv, &q, &mut pinv);
    Some(pinv)
}

/// Pseudoinverse for full-rank matrices via Q-free Householder QR.
///
/// Returns `Ok(None)` for empty, rank-deficient, near-rank-deficient, or
/// unsupported cases so callers can preserve the SVD pseudo-inverse fallback.
pub fn pinv_qr_contiguous_f64(
    a_data: &[f64],
    a_meta: &TensorMeta,
) -> Result<Option<Vec<f64>>, KernelError> {
    ensure_unary_layout_and_storage(a_data, a_meta)?;
    let shape = a_meta.shape();
    if shape.len() != 2 {
        return Err(KernelError::InvalidDimension {
            dim: shape.len(),
            ndim: 2,
        });
    }
    let m = shape[0];
    let n = shape[1];
    if m == 0 || n == 0 {
        return Ok(None);
    }

    let offset = a_meta.storage_offset();
    let values = &a_data[offset..offset + m * n];
    if m >= n {
        return Ok(pinv_qr_full_column_rank_f64(values, m, n));
    }

    let mut transposed = vec![0.0_f64; n * m];
    for row in 0..m {
        for col in 0..n {
            transposed[col * m + row] = values[row * n + col];
        }
    }

    let Some(transposed_pinv) = pinv_qr_full_column_rank_f64(&transposed, n, m) else {
        return Ok(None);
    };
    let mut pinv = vec![0.0_f64; n * m];
    for row in 0..m {
        for col in 0..n {
            pinv[col * m + row] = transposed_pinv[row * n + col];
        }
    }
    Ok(Some(pinv))
}

pub fn add_tensor_contiguous_f32(
    lhs: &[f32],
    rhs: &[f32],
    lhs_meta: &TensorMeta,
    rhs_meta: &TensorMeta,
) -> Result<Vec<f32>, KernelError> {
    simd_elementwise_f32(lhs, rhs, lhs_meta, rhs_meta, |l, r| l + r, |a, b| a + b)
}

pub fn sub_tensor_contiguous_f32(
    lhs: &[f32],
    rhs: &[f32],
    lhs_meta: &TensorMeta,
    rhs_meta: &TensorMeta,
) -> Result<Vec<f32>, KernelError> {
    simd_elementwise_f32(lhs, rhs, lhs_meta, rhs_meta, |l, r| l - r, |a, b| a - b)
}

pub fn mul_tensor_contiguous_f32(
    lhs: &[f32],
    rhs: &[f32],
    lhs_meta: &TensorMeta,
    rhs_meta: &TensorMeta,
) -> Result<Vec<f32>, KernelError> {
    simd_elementwise_f32(lhs, rhs, lhs_meta, rhs_meta, |l, r| l * r, |a, b| a * b)
}

pub fn div_tensor_contiguous_f32(
    lhs: &[f32],
    rhs: &[f32],
    lhs_meta: &TensorMeta,
    rhs_meta: &TensorMeta,
) -> Result<Vec<f32>, KernelError> {
    simd_elementwise_f32(lhs, rhs, lhs_meta, rhs_meta, |l, r| l / r, |a, b| a / b)
}

pub fn neg_tensor_contiguous_f32(
    input: &[f32],
    meta: &TensorMeta,
) -> Result<Vec<f32>, KernelError> {
    simd_unary_f32_kernel(input, meta, |v| -v, |a| -a)
}

pub fn abs_tensor_contiguous_f32(
    input: &[f32],
    meta: &TensorMeta,
) -> Result<Vec<f32>, KernelError> {
    simd_unary_f32_kernel(input, meta, |v| v.abs(), |a| a.abs())
}

pub fn sqrt_tensor_contiguous_f32(
    input: &[f32],
    meta: &TensorMeta,
) -> Result<Vec<f32>, KernelError> {
    simd_unary_f32_kernel(input, meta, |v| v.sqrt(), |a| a.sqrt())
}

pub fn reciprocal_tensor_contiguous_f32(
    input: &[f32],
    meta: &TensorMeta,
) -> Result<Vec<f32>, KernelError> {
    let one = f32x8::splat(1.0);
    simd_unary_f32_kernel(input, meta, |v| 1.0 / v, move |a| one / a)
}

fn ensure_dtype_device_and_layout_f32(
    lhs: &TensorMeta,
    rhs: &TensorMeta,
) -> Result<(), KernelError> {
    if lhs.dtype() != rhs.dtype() {
        return Err(KernelError::Incompatible(
            TensorCompatError::DTypeMismatch {
                lhs: lhs.dtype(),
                rhs: rhs.dtype(),
            },
        ));
    }
    if lhs.device() != rhs.device() {
        return Err(KernelError::Incompatible(
            TensorCompatError::DeviceMismatch {
                lhs: lhs.device(),
                rhs: rhs.device(),
            },
        ));
    }
    if !lhs.is_contiguous() {
        return Err(KernelError::UnsupportedLayout { side: "lhs" });
    }
    if !rhs.is_contiguous() {
        return Err(KernelError::UnsupportedLayout { side: "rhs" });
    }
    Ok(())
}

// f32 activation helpers

fn gelu_value_f32(x: f32) -> f32 {
    // PyTorch default GELU (approximate="none"): exact erf form.
    0.5f32 * x * (1.0f32 + libm::erff(x * std::f32::consts::FRAC_1_SQRT_2))
}

fn silu_value_f32(x: f32) -> f32 {
    x / (1.0f32 + (-x).exp())
}

fn leaky_relu_value_f32(x: f32) -> f32 {
    if x >= 0.0f32 { x } else { 0.01f32 * x }
}

fn elu_value_f32(x: f32) -> f32 {
    // expm1 (not exp(x)-1.0): avoids cancellation near 0, matches torch. frankentorch-0f609.
    if x > 0.0f32 { x } else { x.exp_m1() }
}

fn erf_value_f32(x: f32) -> f32 {
    // F32 companion to `erf_value` — see that function for the reason
    // `libm` is preferred over the Abramowitz-Stegun approximation.
    libm::erff(x)
}

fn erfc_value_f32(x: f32) -> f32 {
    libm::erfcf(x)
}

fn hardswish_value_f32(x: f32) -> f32 {
    if x <= -3.0f32 {
        0.0f32
    } else if x >= 3.0f32 {
        x
    } else {
        x * (x + 3.0f32) / 6.0f32
    }
}

fn hardsigmoid_value_f32(x: f32) -> f32 {
    if x <= -3.0f32 {
        0.0f32
    } else if x >= 3.0f32 {
        1.0f32
    } else {
        (x + 3.0f32) / 6.0f32
    }
}

fn hardtanh_value_f32(x: f32) -> f32 {
    x.clamp(-1.0f32, 1.0f32)
}

fn softplus_value_f32(x: f32) -> f32 {
    // Mirrors softplus_value (f64): only the upper threshold is needed;
    // log1p(exp(x)) is precise for negative x and decays smoothly.
    if x > 20.0f32 { x } else { x.exp().ln_1p() }
}

fn mish_value_f32(x: f32) -> f32 {
    x * softplus_value_f32(x).tanh()
}

fn round_ties_even_f32(value: f32) -> f32 {
    value.round_ties_even()
}

/// F32 companion to `torch_sign_f64` — see that function for rationale.
fn torch_sign_f32(value: f32) -> f32 {
    // torch.sign(NaN) == 0.0; NaN and ±0 fall through to 0.0. frankentorch-z6bl1.
    if value > 0.0 {
        1.0
    } else if value < 0.0 {
        -1.0
    } else {
        0.0
    }
}

// ── Macro-generated simple f32 unary kernels ────────────────────────────

macro_rules! define_unary_f32 {
    // Cheap ops (sign/round/clamp/…): keep the high cheap-op gate so a small input
    // never eats rayon dispatch overhead.
    ($name:ident, $op:expr) => {
        define_unary_f32!($name, $op, SCALAR_UNARY_PARALLEL_THRESHOLD);
    };
    // Compute-bound ops pass the low PARALLEL_THRESHOLD (8192) explicitly.
    ($name:ident, $op:expr, $thresh:expr) => {
        pub fn $name(input: &[f32], meta: &TensorMeta) -> Result<Vec<f32>, KernelError> {
            unary_contiguous_f32(input, meta, $op, $thresh)
        }
    };
}

define_unary_f32!(exp_tensor_contiguous_f32, f32::exp, PARALLEL_THRESHOLD);
define_unary_f32!(log_tensor_contiguous_f32, f32::ln, PARALLEL_THRESHOLD);
pub fn relu_tensor_contiguous_f32(
    input: &[f32],
    meta: &TensorMeta,
) -> Result<Vec<f32>, KernelError> {
    let zero = f32x8::splat(0.0f32);
    simd_unary_f32_kernel(input, meta, |v| v.max(0.0f32), move |a| a.max(zero))
}
define_unary_f32!(
    sigmoid_tensor_contiguous_f32,
    |v: f32| 1.0f32 / (1.0f32 + (-v).exp()),
    PARALLEL_THRESHOLD
);
define_unary_f32!(tanh_tensor_contiguous_f32, f32::tanh, PARALLEL_THRESHOLD);
define_unary_f32!(sin_tensor_contiguous_f32, f32::sin, PARALLEL_THRESHOLD);
define_unary_f32!(cos_tensor_contiguous_f32, f32::cos, PARALLEL_THRESHOLD);
define_unary_f32!(tan_tensor_contiguous_f32, f32::tan, PARALLEL_THRESHOLD);
define_unary_f32!(floor_tensor_contiguous_f32, f32::floor);
define_unary_f32!(ceil_tensor_contiguous_f32, f32::ceil);
