    #[test]
    fn symmetric_to_banded_reconstructs_and_is_banded() {
        // Stage-1 of the two-stage symmetric eigensolver (frankentorch-5oqum):
        // the unblocked full -> banded Householder reduction must (1) produce an
        // exactly banded, symmetric `band`, (2) accumulate an orthogonal `q`,
        // and (3) reconstruct the input via `q @ band @ q^T`. Exercise several
        // half-bandwidths including `b == 1` (the tridiagonal case the QL step
        // ultimately consumes).
        let n = 13usize;
        // Deterministic symmetric input (no RNG), reasonably general.
        let mut a = vec![0.0f64; n * n];
        for i in 0..n {
            for j in 0..=i {
                let val = ((i * 7 + j * 3 + 1) % 17) as f64 * 0.37 - 2.1
                    + (i as f64) * (j as f64) * 0.013;
                a[i * n + j] = val;
                a[j * n + i] = val;
            }
        }

        for &b in &[1usize, 2, 4, 7] {
            let (band, q) = super::symmetric_to_banded_f64(&a, n, b).unwrap();

            // (1a) exactly banded.
            for i in 0..n {
                for j in 0..n {
                    if i.abs_diff(j) > b {
                        assert_eq!(
                            band[i * n + j],
                            0.0,
                            "b={b}: out-of-band entry ({i},{j}) not zeroed"
                        );
                    }
                }
            }
            // (1b) symmetric.
            for i in 0..n {
                for j in 0..n {
                    assert!(
                        (band[i * n + j] - band[j * n + i]).abs() < 1e-12,
                        "b={b}: band not symmetric at ({i},{j})"
                    );
                }
            }
            // (2) q orthogonal: q^T q == I.
            for i in 0..n {
                for j in 0..n {
                    let mut s = 0.0;
                    for r in 0..n {
                        s += q[r * n + i] * q[r * n + j];
                    }
                    let expect = if i == j { 1.0 } else { 0.0 };
                    assert!(
                        (s - expect).abs() < 1e-9,
                        "b={b}: q not orthogonal at ({i},{j}): {s}"
                    );
                }
            }
            // (3) reconstruction: q @ band @ q^T == a.
            // bt = band @ q^T : bt[p,j] = sum_k band[p,k] q[j,k]
            let mut bt = vec![0.0f64; n * n];
            for p in 0..n {
                for j in 0..n {
                    let mut s = 0.0;
                    for k in 0..n {
                        s += band[p * n + k] * q[j * n + k];
                    }
                    bt[p * n + j] = s;
                }
            }
            for i in 0..n {
                for j in 0..n {
                    let mut s = 0.0;
                    for p in 0..n {
                        s += q[i * n + p] * bt[p * n + j];
                    }
                    assert!(
                        (s - a[i * n + j]).abs() < 1e-9,
                        "b={b}: reconstruction mismatch at ({i},{j}): {s} vs {}",
                        a[i * n + j]
                    );
                }
            }
        }
    }

    #[test]
    fn symmetric_to_banded_rejects_short_input() {
        let err = super::symmetric_to_banded_f64(&[1.0, 2.0, 3.0], 3, 1);
        assert!(matches!(err, Err(super::KernelError::ShapeMismatch { .. })));
    }

    #[test]
    fn symmetric_to_banded_values_matches_unblocked() {
        // The BLAS-3 blocked values-only stage-1 must agree with the unblocked
        // reference band (a) elementwise to reduction tolerance, (b) be exactly
        // banded + symmetric, and (c) preserve the spectrum. frankentorch-5oqum.
        for &(n, b) in &[
            (32usize, 2usize),
            (32, 4),
            (40, 5),
            (48, 8),
            (64, 8),
            (64, 16),
            (96, 12),
            (128, 16),
        ] {
            let mut a = vec![0.0f64; n * n];
            for i in 0..n {
                for j in 0..=i {
                    let val = ((i * 13 + j * 7 + 2) % 31) as f64 * 0.29 - 4.7 + (i as f64) * 0.011
                        - (j as f64) * 0.017;
                    a[i * n + j] = val;
                    a[j * n + i] = val;
                }
            }
            let reference = super::symmetric_to_banded_f64(&a, n, b).unwrap().0;
            let blocked = super::symmetric_to_banded_values_f64(&a, n, b).unwrap();

            // Build a tolerance from the band magnitude (the reduction is a
            // similarity transform; absolute entry error scales with ||A||).
            let scale = reference
                .iter()
                .fold(0.0f64, |m, &x| m.max(x.abs()))
                .max(1.0);
            let tol = 1e-9 * scale;
            for i in 0..n {
                for j in 0..n {
                    // (b) exactly banded + symmetric.
                    if i.abs_diff(j) > b {
                        assert_eq!(blocked[i * n + j], 0.0, "n={n} b={b}: ({i},{j}) not zeroed");
                    }
                    assert!(
                        (blocked[i * n + j] - blocked[j * n + i]).abs() < 1e-12,
                        "n={n} b={b}: blocked band not symmetric at ({i},{j})"
                    );
                    // (a) elementwise agreement with the unblocked reference.
                    assert!(
                        (blocked[i * n + j] - reference[i * n + j]).abs() <= tol,
                        "n={n} b={b}: band entry ({i},{j}) blocked={} reference={} (tol {tol})",
                        blocked[i * n + j],
                        reference[i * n + j]
                    );
                }
            }

            // (c) spectrum preserved (the strongest invariant).
            let meta = TensorMeta::from_shape(vec![n, n], DType::F64, Device::Cpu);
            let spec_ref = super::eigvalsh_contiguous_f64(&a, &meta).unwrap();
            let spec_blk = super::eigvalsh_contiguous_f64(&blocked, &meta).unwrap();
            for (idx, (&lr, &lb)) in spec_ref.iter().zip(spec_blk.iter()).enumerate() {
                let etol = 1e-7 + 1e-8 * lr.abs();
                assert!(
                    (lr - lb).abs() <= etol,
                    "n={n} b={b}: eigenvalue[{idx}] ref={lr} blocked={lb} (tol {etol})"
                );
            }
        }
    }

    #[test]
    fn qr_batched_matches_looping_2d_bit_exact() {
        // general batched [B,m,n]; Q and R bit-identical to looping the 2-D qr (reduced).
        let (bb, m, n) = (8usize, 6usize, 4usize);
        let data: Vec<f64> = (0..bb * m * n)
            .map(|x| (((x * 2246822519usize) % 9941) as f64) * 0.002 - 9.0)
            .collect();
        let meta = TensorMeta::from_shape(vec![bb, m, n], DType::F64, Device::Cpu);
        let pmeta = TensorMeta::from_shape(vec![m, n], DType::F64, Device::Cpu);
        let kq = m.min(n);
        let (q, r) = super::qr_batched_contiguous_f64(&data, &meta, true).unwrap();
        assert_eq!(q.len(), bb * m * kq);
        assert_eq!(r.len(), bb * kq * n);
        for b in 0..bb {
            let res =
                super::qr_contiguous_f64(&data[b * m * n..(b + 1) * m * n], &pmeta, true).unwrap();
            for t in 0..m * kq {
                assert_eq!(q[b * m * kq + t].to_bits(), res.q[t].to_bits());
            }
            for t in 0..kq * n {
                assert_eq!(r[b * kq * n + t].to_bits(), res.r[t].to_bits());
            }
        }
    }

