    #[test]
    fn reduce_sum_for_broadcast_parallel_matches_serial_scatter_bit_exact() {
        // Reference = the original serial row-major scatter-add. The production fn
        // takes its parallel-over-outputs path once expanded_numel >= the threshold;
        // the sizes below cross it. Results must be BIT-FOR-BIT identical (kgs4.95).
        fn serial_ref(grad: &[f64], expanded: &[usize], original: &[usize]) -> Vec<f64> {
            let ndim = expanded.len();
            let ostrides =
                super::broadcast_strides(original, expanded, "ref").expect("ref strides");
            let onumel: usize = original.iter().product();
            let mut reduced = vec![0.0_f64; onumel];
            let mut coords = vec![0usize; ndim];
            for g in grad {
                let mut idx = 0usize;
                for d in 0..ndim {
                    idx += coords[d] * ostrides[d];
                }
                reduced[idx] += *g;
                for d in (0..ndim).rev() {
                    coords[d] += 1;
                    if coords[d] < expanded[d] {
                        break;
                    }
                    coords[d] = 0;
                }
            }
            reduced
        }
        let cases: &[(&[usize], &[usize])] = &[
            (&[256, 64], &[1, 64]),       // reduce leading dim
            (&[64, 256], &[64, 1]),       // reduce trailing dim
            (&[16, 32, 24], &[1, 32, 1]), // reduce both ends
            (&[100, 100], &[1, 1]),       // reduce to scalar
            (&[8, 8, 8, 32], &[8, 1, 8, 1]),
            (&[4096, 5], &[1, 5]),
        ];
        for (expanded, original) in cases {
            let numel: usize = expanded.iter().product();
            // deterministic pseudo-random grads with a wide dynamic range so any
            // accumulation-order difference would surface in the low bits.
            let grad: Vec<f64> = (0..numel)
                .map(|i| {
                    let x = ((i.wrapping_mul(2654435761)) % 7919) as f64;
                    (x - 3959.0) * 1.000_000_000_173
                })
                .collect();
            let got = super::reduce_sum_for_broadcast(&grad, expanded, original).expect("reduce");
            let want = serial_ref(&grad, expanded, original);
            assert_eq!(got.len(), want.len(), "shape {expanded:?}->{original:?}");
            for (i, (g, w)) in got.iter().zip(want.iter()).enumerate() {
                assert_eq!(
                    g.to_bits(),
                    w.to_bits(),
                    "bit mismatch at {i} for {expanded:?}->{original:?}: {g} vs {w}"
                );
            }
        }
    }

    #[test]
    fn reduce_sum_for_broadcast_f32_parallel_matches_serial_scatter_bit_exact() {
        fn serial_ref(grad: &[f32], expanded: &[usize], original: &[usize]) -> Vec<f32> {
            let ndim = expanded.len();
            let ostrides =
                super::broadcast_strides(original, expanded, "ref").expect("ref strides");
            let onumel: usize = original.iter().product();
            let mut reduced = vec![0.0_f32; onumel];
            let mut coords = vec![0usize; ndim];
            for g in grad {
                let mut idx = 0usize;
                for d in 0..ndim {
                    idx += coords[d] * ostrides[d];
                }
                reduced[idx] += *g;
                for d in (0..ndim).rev() {
                    coords[d] += 1;
                    if coords[d] < expanded[d] {
                        break;
                    }
                    coords[d] = 0;
                }
            }
            reduced
        }
        let cases: &[(&[usize], &[usize])] = &[
            (&[256, 64], &[1, 64]),
            (&[64, 256], &[64, 1]),
            (&[16, 32, 24], &[1, 32, 1]),
            (&[100, 100], &[1, 1]),
            (&[8, 8, 8, 32], &[8, 1, 8, 1]),
        ];
        for (expanded, original) in cases {
            let numel: usize = expanded.iter().product();
            let grad: Vec<f32> = (0..numel)
                .map(|i| (((i.wrapping_mul(2654435761)) % 7919) as f32 - 3959.0) * 1.000_03)
                .collect();
            let got =
                super::reduce_sum_for_broadcast_f32(&grad, expanded, original).expect("reduce");
            let want = serial_ref(&grad, expanded, original);
            for (i, (g, w)) in got.iter().zip(want.iter()).enumerate() {
                assert_eq!(g.to_bits(), w.to_bits(), "f32 bit mismatch at {i}");
            }
        }
    }

    #[test]
    fn scatter_add_parallel_matches_serial_with_collisions_bit_exact() {
        // Original serial sweep as the reference. The case below crosses the
        // parallel threshold (src_numel >= PARALLEL_THRESHOLD, total_cols = m >= 2),
        // and has heavy index COLLISIONS (200 rows -> 50 outputs) so any change in
        // accumulation order would surface in the low bits. (kgs4.97)
        fn serial(
            input: &[f64],
            shape: &[usize],
            dim: usize,
            index: &[f64],
            idx_shape: &[usize],
            src: &[f64],
        ) -> Vec<f64> {
            let dim_size = shape[dim];
            let idx_dim_size = idx_shape[dim];
            let inner_size: usize = idx_shape[dim + 1..].iter().product();
            let outer_size: usize = idx_shape[..dim].iter().product();
            let numel: usize = shape.iter().product();
            let mut output = input[..numel].to_vec();
            for outer in 0..outer_size {
                for r in 0..idx_dim_size {
                    for inner in 0..inner_size {
                        let idx_pos = outer * idx_dim_size * inner_size + r * inner_size + inner;
                        let selected = index[idx_pos] as usize;
                        let dst = outer * dim_size * inner_size + selected * inner_size + inner;
                        output[dst] += src[idx_pos];
                    }
                }
            }
            output
        }
        let (num_emb, m, n) = (50usize, 256usize, 200usize); // embedding-backward shape
        let out_shape = [num_emb, m];
        let idx_shape = [n, m];
        let input: Vec<f64> = (0..num_emb * m).map(|i| (i % 97) as f64 * 0.1).collect();
        let src: Vec<f64> = (0..n * m)
            .map(|i| ((i * 31) % 101) as f64 * 0.01 - 0.5)
            .collect();
        let index: Vec<f64> = (0..n * m)
            .map(|i| (i.wrapping_mul(2654435761) % num_emb) as f64)
            .collect();
        assert!(n * m >= super::PARALLEL_THRESHOLD, "must hit parallel path");
        let meta = TensorMeta::from_shape(out_shape.to_vec(), DType::F64, Device::Cpu);
        let idx_meta = TensorMeta::from_shape(idx_shape.to_vec(), DType::F64, Device::Cpu);
        let got =
            super::scatter_add_tensor_contiguous_f64(&input, &meta, 0, &index, &idx_meta, &src)
                .expect("scatter_add");
        let want = serial(&input, &out_shape, 0, &index, &idx_shape, &src);
        for (i, (g, w)) in got.iter().zip(want.iter()).enumerate() {
            assert_eq!(g.to_bits(), w.to_bits(), "scatter_add bit mismatch at {i}");
        }
    }

    #[test]
    fn scatter_add_f32_parallel_matches_serial_with_collisions_bit_exact() {
        fn serial(
            input: &[f32],
            shape: &[usize],
            dim: usize,
            index: &[f64],
            idx_shape: &[usize],
            src: &[f32],
        ) -> Vec<f32> {
            let dim_size = shape[dim];
            let idx_dim_size = idx_shape[dim];
            let inner_size: usize = idx_shape[dim + 1..].iter().product();
            let outer_size: usize = idx_shape[..dim].iter().product();
            let numel: usize = shape.iter().product();
            let mut output = input[..numel].to_vec();
            for outer in 0..outer_size {
                for r in 0..idx_dim_size {
                    for inner in 0..inner_size {
                        let idx_pos = outer * idx_dim_size * inner_size + r * inner_size + inner;
                        let selected = index[idx_pos] as usize;
                        let dst = outer * dim_size * inner_size + selected * inner_size + inner;
                        output[dst] += src[idx_pos];
                    }
                }
            }
            output
        }
        let (num_emb, m, n) = (50usize, 256usize, 200usize);
        let out_shape = [num_emb, m];
        let idx_shape = [n, m];
        let input: Vec<f32> = (0..num_emb * m).map(|i| (i % 97) as f32 * 0.1).collect();
        let src: Vec<f32> = (0..n * m)
            .map(|i| ((i * 31) % 101) as f32 * 0.01 - 0.5)
            .collect();
        let index: Vec<f64> = (0..n * m)
            .map(|i| (i.wrapping_mul(2654435761) % num_emb) as f64)
            .collect();
        assert!(n * m >= super::PARALLEL_THRESHOLD);
        let meta = TensorMeta::from_shape(out_shape.to_vec(), DType::F32, Device::Cpu);
        let idx_meta = TensorMeta::from_shape(idx_shape.to_vec(), DType::F64, Device::Cpu);
        let got =
            super::scatter_add_tensor_contiguous_f32(&input, &meta, 0, &index, &idx_meta, &src)
                .expect("scatter_add_f32");
        let want = serial(&input, &out_shape, 0, &index, &idx_shape, &src);
        for (i, (g, w)) in got.iter().zip(want.iter()).enumerate() {
            assert_eq!(
                g.to_bits(),
                w.to_bits(),
                "scatter_add_f32 bit mismatch at {i}"
            );
        }
    }

