    // ---- cumsum ----

    #[test]
    fn cumsum_parallel_matches_serial_bit_exact() {
        // Sizes above PARALLEL_THRESHOLD (>=8192) with outer_size>=2 exercise the
        // Rayon outer-block path; the result must equal a serial scan BIT-FOR-BIT
        // (per-lane accumulation order is unchanged). Cover dim=last (inner=1) and
        // a middle dim (inner>1, strided lanes).
        for (shape, dim) in [
            (vec![256usize, 256usize], 1usize), // 65536, inner=1
            (vec![64, 32, 48], 1),              // 98304, inner=48
            (vec![512, 200], 1),                // 102400, inner=1
        ] {
            let numel: usize = shape.iter().product();
            let input: Vec<f64> = (0..numel)
                .map(|i| ((i % 97) as f64) * 0.013 - 0.6)
                .collect();
            let meta = TensorMeta::from_shape(shape.clone(), DType::F64, Device::Cpu);
            let got = super::cumsum_tensor_contiguous_f64(&input, &meta, dim).expect("cumsum");

            // Serial reference.
            let dim_size = shape[dim];
            let inner: usize = shape[dim + 1..].iter().product();
            let outer: usize = shape[..dim].iter().product();
            let mut want = vec![0.0f64; numel];
            for o in 0..outer {
                for inn in 0..inner {
                    let mut acc = 0.0;
                    for d in 0..dim_size {
                        let idx = o * dim_size * inner + d * inner + inn;
                        acc += input[idx];
                        want[idx] = acc;
                    }
                }
            }
            assert_eq!(got.len(), want.len());
            for (i, (&g, &w)) in got.iter().zip(want.iter()).enumerate() {
                assert_eq!(
                    g.to_bits(),
                    w.to_bits(),
                    "shape={shape:?} dim={dim} idx={i}"
                );
            }

            // f32 path too.
            let input32: Vec<f32> = input.iter().map(|&v| v as f32).collect();
            let meta32 = TensorMeta::from_shape(shape.clone(), DType::F32, Device::Cpu);
            let got32 =
                super::cumsum_tensor_contiguous_f32(&input32, &meta32, dim).expect("cumsum f32");
            let mut want32 = vec![0.0f32; numel];
            for o in 0..outer {
                for inn in 0..inner {
                    let mut acc = 0.0f32;
                    for d in 0..dim_size {
                        let idx = o * dim_size * inner + d * inner + inn;
                        acc += input32[idx];
                        want32[idx] = acc;
                    }
                }
            }
            for (i, (&g, &w)) in got32.iter().zip(want32.iter()).enumerate() {
                assert_eq!(
                    g.to_bits(),
                    w.to_bits(),
                    "f32 shape={shape:?} dim={dim} idx={i}"
                );
            }
        }
    }

    #[test]
    fn elementwise_strided_parallel_matches_serial_bit_exact() {
        // The non-contiguous same-shape binary path (elementwise_strided_f64) only
        // parallelizes above PARALLEL_THRESHOLD (>=8192), so small tests exercise
        // the serial fallback. Drive a LARGE transposed (non-contiguous) view of a
        // row-major buffer through atan2 and compare against an independent serial
        // strided reference BIT-FOR-BIT (the unravel must reproduce the old
        // coords-increment order exactly).
        let rows = 200usize;
        let cols = 173usize; // numel = 34600 > 8192, non-square + odd to stress the unravel
        let n = rows * cols;
        let lhs: Vec<f64> = (0..n).map(|i| ((i % 617) as f64) * 0.01 - 3.0).collect();
        let rhs: Vec<f64> = (0..n).map(|i| ((i % 953) as f64) * 0.01 + 0.5).collect();
        // Transposed view: logical [cols, rows], strides [1, cols] => non-contiguous.
        let meta = TensorMeta::from_shape_and_strides(
            vec![cols, rows],
            vec![1, cols],
            0,
            DType::F64,
            Device::Cpu,
        )
        .unwrap();
        let got = super::atan2_tensor_contiguous_f64(&lhs, &rhs, &meta, &meta).expect("atan2");

        // Serial reference: row-major over [cols, rows], strided index decode.
        let mut want = Vec::with_capacity(n);
        for c in 0..cols {
            for r in 0..rows {
                let idx = c * 1 + r * cols; // strides [1, cols]
                want.push(lhs[idx].atan2(rhs[idx]));
            }
        }
        assert_eq!(got.len(), want.len());
        for (i, (&g, &w)) in got.iter().zip(want.iter()).enumerate() {
            assert_eq!(g.to_bits(), w.to_bits(), "strided atan2 idx={i}");
        }
    }

    #[test]
    fn unary_strided_parallel_matches_serial_bit_exact() {
        // Same as the binary strided test but for the non-contiguous UNARY path
        // (unary_strided_f64), reached by e.g. `x.t().erf()`. Large transposed
        // view (> PARALLEL_THRESHOLD) so the parallel branch runs; compare against
        // an independent serial strided reference BIT-FOR-BIT.
        let rows = 200usize;
        let cols = 173usize; // numel 34600 > 8192
        let n = rows * cols;
        let x: Vec<f64> = (0..n).map(|i| ((i % 617) as f64) * 0.006 - 1.8).collect();
        let meta = TensorMeta::from_shape_and_strides(
            vec![cols, rows],
            vec![1, cols],
            0,
            DType::F64,
            Device::Cpu,
        )
        .unwrap();
        let got = super::erf_tensor_contiguous_f64(&x, &meta).expect("erf");

        let mut want = Vec::with_capacity(n);
        for c in 0..cols {
            for r in 0..rows {
                let idx = c + r * cols; // strides [1, cols]
                want.push(super::erf_value(x[idx]));
            }
        }
        assert_eq!(got.len(), want.len());
        for (i, (&g, &w)) in got.iter().zip(want.iter()).enumerate() {
            assert_eq!(g.to_bits(), w.to_bits(), "strided erf idx={i}");
        }
    }

    #[test]
    fn norm_dim_general_p_parallel_matches_serial_bit_exact() {
        // The general fractional-p branch of norm_dim now parallelises over
        // output rows above the work gate. Drive it past the threshold and
        // compare against an independent serial reference BIT-FOR-BIT (each
        // output's r-ascending powf sum is order-fixed; rows are independent).
        let serial_norm = |data: &[f64], shape: &[usize], p: f64, dim: usize| -> Vec<f64> {
            let reduce = shape[dim];
            let inner: usize = shape[dim + 1..].iter().product();
            let outer: usize = shape[..dim].iter().product();
            let mut out = Vec::with_capacity(outer * inner);
            for o in 0..outer {
                for i in 0..inner {
                    let mut s = 0.0;
                    for r in 0..reduce {
                        s += data[o * reduce * inner + r * inner + i].abs().powf(p);
                    }
                    out.push(s.powf(1.0 / p));
                }
            }
            out
        };
        // [512, 64, 8] reduce over dim=1: out_numel=4096, work=262144 > gate.
        let shape = vec![512usize, 64, 8];
        let n: usize = shape.iter().product();
        let data: Vec<f64> = (0..n).map(|i| ((i % 9973) as f64) * 0.0007 - 3.0).collect();
        let meta = TensorMeta::from_shape(shape.clone(), DType::F64, Device::Cpu);
        for &p in &[3.0f64, 0.5, 1.5] {
            let got = super::norm_dim_tensor_contiguous_f64(&data, &meta, p, 1).unwrap();
            let want = serial_norm(&data, &shape, p, 1);
            assert_eq!(got.len(), want.len());
            for i in 0..got.len() {
                assert_eq!(got[i].to_bits(), want[i].to_bits(), "norm_dim p={p} idx={i}");
            }
        }
        // f32 twin, same shape/p.
        let dataf: Vec<f32> = (0..n).map(|i| ((i % 9973) as f32) * 0.0007 - 3.0).collect();
        let metaf = TensorMeta::from_shape(shape.clone(), DType::F32, Device::Cpu);
        let pf = 3.0f32;
        let gotf = super::norm_dim_tensor_contiguous_f32(&dataf, &metaf, pf, 1).unwrap();
        let reduce = shape[1];
        let inner = shape[2];
        let outer = shape[0];
        let mut wantf = Vec::with_capacity(outer * inner);
        for o in 0..outer {
            for i in 0..inner {
                let mut s = 0.0f32;
                for r in 0..reduce {
                    s += dataf[o * reduce * inner + r * inner + i].abs().powf(pf);
                }
                wantf.push(s.powf(1.0f32 / pf));
            }
        }
        for i in 0..gotf.len() {
            assert_eq!(gotf[i].to_bits(), wantf[i].to_bits(), "norm_dim_f32 idx={i}");
        }
    }

    #[test]
    fn softmax_f32_parallel_matches_serial_bit_exact() {
        // softmax_dim_tensor_contiguous_f32 was fully serial; now parallel over
        // independent rows above the gate. Drive both the inner_size==1 (last-dim)
        // and the general strided (dim=1 of a 3D tensor) branches at sizes past
        // the threshold, comparing the production kernel against an independent
        // serial reference BIT-FOR-BIT (rows are independent → order-invariant).
        let serial_softmax = |data: &[f32], shape: &[usize], dim: usize| -> Vec<f32> {
            let reduce = shape[dim];
            let inner: usize = shape[dim + 1..].iter().product();
            let outer: usize = shape[..dim].iter().product();
            let mut out = vec![0.0f32; data.len()];
            let mut scratch = vec![0.0f32; reduce];
            for o in 0..outer {
                for i in 0..inner {
                    for r in 0..reduce {
                        scratch[r] = data[o * reduce * inner + r * inner + i];
                    }
                    let m = scratch.iter().copied().fold(f32::NEG_INFINITY, f32::max);
                    for v in scratch.iter_mut() {
                        *v = (*v - m).exp();
                    }
                    let s = super::pairwise_sum_f32(&scratch);
                    for (r, &e) in scratch.iter().enumerate() {
                        out[o * reduce * inner + r * inner + i] = e / s;
                    }
                }
            }
            out
        };
        // (a) last-dim path: [40000, 16] → numel 640000 > gates, inner_size==1.
        let shape_a = vec![40_000usize, 16];
        let na: usize = shape_a.iter().product();
        let da: Vec<f32> = (0..na).map(|i| ((i % 9001) as f32) * 0.001 - 4.0).collect();
        let meta_a = TensorMeta::from_shape(shape_a.clone(), DType::F32, Device::Cpu);
        let got_a = super::softmax_dim_tensor_contiguous_f32(&da, &meta_a, 1).unwrap();
        let want_a = serial_softmax(&da, &shape_a, 1);
        for i in 0..na {
            assert_eq!(
                got_a[i].to_bits(),
                want_a[i].to_bits(),
                "softmax f32 lastdim idx={i}"
            );
        }
        // (b) general strided path: [64, 32, 64], dim=1 (inner_size==64 > 1).
        let shape_b = vec![64usize, 32, 64];
        let nb: usize = shape_b.iter().product(); // 131072 > PARALLEL_THRESHOLD
        let db: Vec<f32> = (0..nb).map(|i| ((i % 7001) as f32) * 0.0013 - 3.0).collect();
        let meta_b = TensorMeta::from_shape(shape_b.clone(), DType::F32, Device::Cpu);
        let got_b = super::softmax_dim_tensor_contiguous_f32(&db, &meta_b, 1).unwrap();
        let want_b = serial_softmax(&db, &shape_b, 1);
        for i in 0..nb {
            assert_eq!(
                got_b[i].to_bits(),
                want_b[i].to_bits(),
                "softmax f32 strided idx={i}"
            );
        }
    }

    #[test]
    fn atan2_f32_parallel_matches_serial_bit_exact() {
        // The macro f32 binary kernels were fully serial; atan2 now parallelises
        // above PARALLEL_THRESHOLD. Drive a contiguous input > the gate so the
        // par_iter branch runs, and compare against an independent serial map
        // BIT-FOR-BIT (pure per-element map → order-independent).
        let n = 40_000usize; // > PARALLEL_THRESHOLD (8192)
        let y: Vec<f32> = (0..n).map(|i| ((i % 4001) as f32) * 0.001 - 2.0).collect();
        let x: Vec<f32> = (0..n).map(|i| ((i % 3001) as f32) * 0.001 - 1.5).collect();
        let meta = TensorMeta::from_shape(vec![n], DType::F32, Device::Cpu);
        let got = super::atan2_tensor_contiguous_f32(&y, &x, &meta, &meta).expect("atan2 f32");
        assert_eq!(got.len(), n);
        for i in 0..n {
            let want = y[i].atan2(x[i]);
            assert_eq!(got[i].to_bits(), want.to_bits(), "atan2 f32 idx={i}");
        }
    }

