    #[test]
    fn eigh_f32_native_reconstructs_and_matches_torch() {
        // Native f32 eigh (frankentorch-b6pem follow-up): eigenvectors are
        // non-unique (sign), so verify the convention-independent invariants —
        // A = V·diag(λ)·Vᵀ and VᵀV = I (f32 tol) — plus eigenvalues vs torch f32.
        let n = 4usize;
        #[rustfmt::skip]
        let a = vec![
            4.0f32, 1.0, 2.0, 0.5,
            1.0, 5.0, 1.5, 1.0,
            2.0, 1.5, 6.0, 2.0,
            0.5, 1.0, 2.0, 7.0,
        ];
        let meta = TensorMeta::from_shape(vec![n, n], DType::F32, Device::Cpu);
        let r = super::eigh_contiguous_f32(&a, &meta).expect("eigh_f32");
        let want = [2.64587f32, 3.99457, 5.43426, 9.9253];
        for (i, &expected) in want.iter().enumerate() {
            assert!((r.eigenvalues[i] - expected).abs() < 1e-3, "λ[{i}]");
        }
        // V·diag(λ)·Vᵀ == A  (V columns are eigenvectors: V[r*n+c]).
        for i in 0..n {
            for j in 0..n {
                let mut acc = 0.0f32;
                for k in 0..n {
                    acc += r.eigenvectors[i * n + k] * r.eigenvalues[k] * r.eigenvectors[j * n + k];
                }
                assert!((acc - a[i * n + j]).abs() < 5e-3, "recon ({i},{j}): {acc}");
            }
        }
        // VᵀV == I (columns orthonormal).
        for i in 0..n {
            for j in 0..n {
                let mut acc = 0.0f32;
                for k in 0..n {
                    acc += r.eigenvectors[k * n + i] * r.eigenvectors[k * n + j];
                }
                let w = if i == j { 1.0 } else { 0.0 };
                assert!((acc - w).abs() < 5e-3, "VtV ({i},{j}): {acc}");
            }
        }
    }

    #[test]
    fn eigvalsh_f32_native_matches_torch_and_f64() {
        // Native f32 eigvalsh (frankentorch-b6pem): (1) fixed 4x4 vs torch 2.12 f32
        // goldens; (2) larger n=80 vs the f64 reference within f32 tolerance (the
        // reduction runs in f32 — eigenvalues are ~f32-accurate, the f32 contract).
        let meta4 = TensorMeta::from_shape(vec![4, 4], DType::F32, Device::Cpu);
        #[rustfmt::skip]
        let a4 = vec![
            4.0f32, 1.0, 2.0, 0.5,
            1.0, 5.0, 1.5, 1.0,
            2.0, 1.5, 6.0, 2.0,
            0.5, 1.0, 2.0, 7.0,
        ];
        let ev = super::eigvalsh_contiguous_f32(&a4, &meta4).expect("eigvalsh_f32");
        let want = [2.64587f32, 3.99457, 5.43426, 9.9253];
        for i in 0..4 {
            assert!(
                (ev[i] - want[i]).abs() < 1e-3,
                "ev[{i}]={} want {}",
                ev[i],
                want[i]
            );
        }

        // n=80 symmetric: compare f32 eigvalsh to the f64 reference.
        let n = 80usize;
        let mut a = vec![0.0f32; n * n];
        for i in 0..n {
            for j in 0..=i {
                let v = (((i * 13 + j * 7) % 17) as f32) * 0.1 - 0.8;
                a[i * n + j] = v;
                a[j * n + i] = v;
            }
            a[i * n + i] += n as f32;
        }
        let meta = TensorMeta::from_shape(vec![n, n], DType::F32, Device::Cpu);
        let ev_f32 = super::eigvalsh_contiguous_f32(&a, &meta).expect("eigvalsh_f32 n");
        let a64: Vec<f64> = a.iter().map(|&x| x as f64).collect();
        let meta64 = TensorMeta::from_shape(vec![n, n], DType::F64, Device::Cpu);
        let ev_f64 = super::eigvalsh_contiguous_f64(&a64, &meta64).expect("eigvalsh_f64 n");
        for i in 0..n {
            let diff = (ev_f32[i] as f64 - ev_f64[i]).abs();
            // f32 reduction backward error ~eps_f32 * ||A|| (||A|| ~ n+ here).
            assert!(
                diff < 1e-2 * (1.0 + ev_f64[i].abs()),
                "n=80 ev[{i}] diff {diff}"
            );
        }
    }

    #[test]
    fn qr_f32_native_reconstructs_and_orthonormal() {
        // Native f32 QR (frankentorch-b3o90): test BOTH regimes — n=8 (scalar
        // Householder sweep) and n=160 (blocked compact-WY sgemm path). QR is
        // non-unique (sign conventions vary vs LAPACK), so verify the
        // convention-independent invariants: Q·R == A and Qᵀ·Q == I (f32 tol).
        for &n in &[8usize, 160] {
            let meta = TensorMeta::from_shape(vec![n, n], DType::F32, Device::Cpu);
            let mut a = vec![0.0f32; n * n];
            for i in 0..n {
                for j in 0..n {
                    a[i * n + j] = (((i * 29 + j * 7) % 11) as f32) * 0.1 - 0.5;
                }
                a[i * n + i] += 1.5;
            }
            let qr = super::qr_contiguous_f32(&a, &meta, true).expect("qr_f32");
            assert_eq!(qr.m, n);
            assert_eq!(qr.n, n);
            // Q·R == A
            for i in 0..n {
                for j in 0..n {
                    let mut acc = 0.0f32;
                    for t in 0..n {
                        acc += qr.q[i * n + t] * qr.r[t * n + j];
                    }
                    let diff = (acc - a[i * n + j]).abs();
                    assert!(diff < 5e-3, "n={n} Q·R != A at ({i},{j}): {diff}");
                }
            }
            // Qᵀ·Q == I
            for i in 0..n {
                for j in 0..n {
                    let mut acc = 0.0f32;
                    for t in 0..n {
                        acc += qr.q[t * n + i] * qr.q[t * n + j];
                    }
                    let want = if i == j { 1.0 } else { 0.0 };
                    assert!(
                        (acc - want).abs() < 5e-3,
                        "n={n} QᵀQ != I at ({i},{j}): {acc}"
                    );
                }
            }
        }
    }

    #[test]
    fn lu_factor_f32_native_solves_and_reconstructs() {
        // Native f32 LU (frankentorch-b3o90): factor a 64x64+ matrix (exercises the
        // blocked sgemm trailing update), confirm P·L·U == A within f32 tolerance
        // and that lu_solve_contiguous_f32 recovers x for A·x=b.
        let n = 96usize;
        let meta_a = TensorMeta::from_shape(vec![n, n], DType::F32, Device::Cpu);
        // Deterministic, diagonally-dominant (well-conditioned) f32 matrix.
        let mut a = vec![0.0f32; n * n];
        for i in 0..n {
            for j in 0..n {
                a[i * n + j] = (((i * 31 + j * 17) % 13) as f32) * 0.1 - 0.6;
            }
            a[i * n + i] += n as f32;
        }
        let f = super::lu_factor_contiguous_f32(&a, &meta_a).expect("lu_factor_f32");
        assert_eq!(f.n, n);

        // Reconstruct P·A == L·U from the packed factor and direct permutation.
        // (P·A)[i] = A[pivots[i]]; L unit-lower, U upper, both from `lu`.
        let mut recon = vec![0.0f32; n * n];
        for i in 0..n {
            for j in 0..n {
                let mut acc = 0.0f32;
                for k in 0..=i.min(j) {
                    let l_ik = if k == i { 1.0 } else { f.lu[i * n + k] };
                    let u_kj = f.lu[k * n + j];
                    acc += l_ik * u_kj;
                }
                recon[i * n + j] = acc;
            }
        }
        for i in 0..n {
            let orig = f.pivots[i] * n;
            for j in 0..n {
                let diff = (recon[i * n + j] - a[orig + j]).abs();
                assert!(diff < 5e-3, "P·A != L·U at ({i},{j}): {diff}");
            }
        }

        // Solve A·x = b and verify the residual.
        let b: Vec<f32> = (0..n).map(|i| (i % 7) as f32 + 1.0).collect();
        let meta_b = TensorMeta::from_shape(vec![n], DType::F32, Device::Cpu);
        let x = super::lu_solve_contiguous_f32(&f.lu, &f.pivots, n, &b, &meta_b).expect("lu_solve");
        for i in 0..n {
            let mut ax = 0.0f32;
            for j in 0..n {
                ax += a[i * n + j] * x[j];
            }
            assert!(
                (ax - b[i]).abs() < 5e-3,
                "A·x != b at {i}: {} vs {}",
                ax,
                b[i]
            );
        }
    }

    #[test]
    fn lu_solve_f32_blocked_path_inverse_n256() {
        // Exercises the BLAS-3 blocked f32 lu_solve path (gated num_rhs>=64 && n>=256):
        // the n-RHS f32 inverse with n=256 hits it. A·inv(A) must reconstruct I.
        let n = 256usize;
        let meta = TensorMeta::from_shape(vec![n, n], DType::F32, Device::Cpu);
        let mut a = vec![0.0f32; n * n];
        for r in 0..n {
            for c in 0..n {
                a[r * n + c] = (((r * 131 + c * 17 + 7) % 1000) as f32) * 0.001 - 0.5;
            }
            a[r * n + r] += n as f32;
        }
        let f = super::lu_factor_contiguous_f32(&a, &meta).expect("lu_factor_f32");
        let mut id = vec![0.0f32; n * n];
        for i in 0..n {
            id[i * n + i] = 1.0;
        }
        let inv = super::lu_solve_contiguous_f32(&f.lu, &f.pivots, n, &id, &meta).expect("solve");
        let mut max_off = 0.0f32;
        for r in 0..n {
            for c in 0..n {
                let mut s = 0.0f32;
                for k in 0..n {
                    s += a[r * n + k] * inv[k * n + c];
                }
                let want = if r == c { 1.0 } else { 0.0 };
                max_off = max_off.max((s - want).abs());
            }
        }
        assert!(
            max_off < 1e-3,
            "A @ inv(A) deviates from I by {max_off:e} (f32 blocked solve path)"
        );
    }

    #[test]
    fn lu_solve_multiple_rhs() {
        let meta_a = TensorMeta::from_shape(vec![2, 2], DType::F64, Device::Cpu);
        let a = vec![2.0, 1.0, 5.0, 3.0];
        let factor = super::lu_factor_contiguous_f64(&a, &meta_a).expect("lu_factor");

        // B is [2, 2]: two right-hand sides
        let meta_b = TensorMeta::from_shape(vec![2, 2], DType::F64, Device::Cpu);
        let b = vec![4.0, 3.0, 7.0, 8.0]; // columns: [4,7] and [3,8]
        let x = super::lu_solve_contiguous_f64(&factor, &b, &meta_b).expect("lu_solve multi-rhs");

        // Verify A * X ≈ B (column by column)
        for rhs in 0..2 {
            for i in 0..2 {
                let mut val = 0.0;
                for j in 0..2 {
                    val += a[i * 2 + j] * x[j * 2 + rhs];
                }
                assert!(
                    (val - b[i * 2 + rhs]).abs() < 1e-10,
                    "A*X[{i},{rhs}] = {val}, expected {}",
                    b[i * 2 + rhs]
                );
            }
        }
    }

    #[test]
    fn lu_solve_mixed_refine_matches_f64_reference_and_residual() {
        let (n, rhs) = (128usize, 4usize);
        let mut a = vec![0.0_f64; n * n];
        for i in 0..n {
            for j in 0..n {
                a[i * n + j] = ((i * 31 + j * 17) % 97) as f64 * 0.013 - 0.5;
            }
            a[i * n + i] += n as f64;
        }
        let b: Vec<f64> = (0..n * rhs)
            .map(|idx| ((idx * 19 + 11) % 101) as f64 * 0.007 - 0.33)
            .collect();
        let meta_a = TensorMeta::from_shape(vec![n, n], DType::F64, Device::Cpu);
        let meta_b = TensorMeta::from_shape(vec![n, rhs], DType::F64, Device::Cpu);
        let factor = super::lu_factor_contiguous_f64(&a, &meta_a).expect("lu_factor");
        let reference = super::lu_solve_contiguous_f64(&factor, &b, &meta_b).expect("f64 solve");
        let mixed = super::lu_solve_mixed_refine_contiguous_f64(&a, &meta_a, &b, &meta_b)
            .expect("mixed refine solve");

        let max_diff = reference
            .iter()
            .zip(&mixed)
            .map(|(r, m)| (r - m).abs())
            .fold(0.0_f64, f64::max);
        assert!(max_diff < 1.0e-8, "mixed vs f64 max diff {max_diff:e}");

        let mut max_residual = 0.0_f64;
        for i in 0..n {
            for rhs_idx in 0..rhs {
                let mut ax = 0.0_f64;
                for j in 0..n {
                    ax += a[i * n + j] * mixed[j * rhs + rhs_idx];
                }
                max_residual = max_residual.max((b[i * rhs + rhs_idx] - ax).abs());
            }
        }
        assert!(max_residual < 1.0e-9, "mixed residual max {max_residual:e}");
    }

