    #[test]
    fn eigh_tred2_tql2_orthonormal_and_reconstructs_24x24() {
        // Exercises the Householder/QL eigensolver at a size where the
        // tridiagonalization + shifted-QL machinery is fully engaged (small
        // cases can finish in a single step). Builds a non-trivial symmetric
        // matrix and verifies the three defining properties of a symmetric
        // eigendecomposition.
        let n = 24;
        let mut a = vec![0.0f64; n * n];
        for i in 0..n {
            for j in 0..n {
                let v = (((i * 37 + j * 101 + 7) % 53) as f64) * 0.11 - 2.5
                    + ((i as f64) - (j as f64)).abs().sin();
                a[i * n + j] = v;
            }
        }
        // Symmetrize.
        for i in 0..n {
            for j in (i + 1)..n {
                let s = 0.5 * (a[i * n + j] + a[j * n + i]);
                a[i * n + j] = s;
                a[j * n + i] = s;
            }
        }
        let meta = TensorMeta::from_shape(vec![n, n], DType::F64, Device::Cpu);
        let r = super::eigh_contiguous_f64(&a, &meta).unwrap();

        // (1) Eigenvalues sorted ascending.
        for i in 1..n {
            assert!(
                r.eigenvalues[i] >= r.eigenvalues[i - 1] - 1e-12,
                "eigenvalues not ascending at {i}"
            );
        }
        // (2) Eigenvectors orthonormal: V^T V = I.
        for c1 in 0..n {
            for c2 in 0..n {
                let mut dot = 0.0;
                for row in 0..n {
                    dot += r.eigenvectors[row * n + c1] * r.eigenvectors[row * n + c2];
                }
                let expected = if c1 == c2 { 1.0 } else { 0.0 };
                assert!(
                    (dot - expected).abs() < 1e-9,
                    "V^T V[{c1},{c2}] = {dot}, expected {expected}"
                );
            }
        }
        // (3) Reconstruction: V diag(λ) V^T = A.
        for i in 0..n {
            for j in 0..n {
                let mut val = 0.0;
                for k in 0..n {
                    val += r.eigenvectors[i * n + k] * r.eigenvalues[k] * r.eigenvectors[j * n + k];
                }
                assert!(
                    (val - a[i * n + j]).abs() < 1e-9,
                    "reconstructed[{i},{j}] = {val}, expected {}",
                    a[i * n + j]
                );
            }
        }
    }

    #[test]
    fn eigh_tql2_deferred_parallel_reconstructs_n288() {
        // n=288 drives many QL sweeps, exercising the deferred whole-stream
        // eigenvector replay (kgs4.73, par_chunks over Z rows). Verifies V·diag(λ)·Vᵀ
        // reconstructs A and the eigenvectors are orthonormal.
        let n = 288usize;
        let mut a = vec![0.0f64; n * n];
        for r in 0..n {
            for c in 0..=r {
                let v = (((r * 131 + c * 17 + 7) % 1000) as f64) * 0.001 - 0.5;
                a[r * n + c] = v;
                a[c * n + r] = v;
            }
        }
        let meta = TensorMeta::from_shape(vec![n, n], DType::F64, Device::Cpu);
        let res = super::eigh_contiguous_f64(&a, &meta).unwrap();
        let mut max_recon = 0.0f64;
        for i in 0..n {
            for j in 0..n {
                let mut val = 0.0;
                for k in 0..n {
                    val += res.eigenvectors[i * n + k]
                        * res.eigenvalues[k]
                        * res.eigenvectors[j * n + k];
                }
                max_recon = max_recon.max((val - a[i * n + j]).abs());
            }
        }
        assert!(max_recon < 1e-9, "eigh reconstruction error {max_recon:e}");
        let mut max_orth = 0.0f64;
        for c1 in 0..n {
            for c2 in c1..n {
                let mut dot = 0.0;
                for row in 0..n {
                    dot += res.eigenvectors[row * n + c1] * res.eigenvectors[row * n + c2];
                }
                let expected = if c1 == c2 { 1.0 } else { 0.0 };
                max_orth = max_orth.max((dot - expected).abs());
            }
        }
        assert!(max_orth < 1e-9, "eigh orthonormality error {max_orth:e}");
    }

    #[test]
    fn eigh_f32_tql2_deferred_parallel_reconstructs_n288() {
        // f32 companion: n=288 drives many QL sweeps, exercising the f32 deferred
        // parallel eigenvector replay (kgs4.74). Verifies V·diag(λ)·Vᵀ ≈ A.
        let n = 288usize;
        let mut a = vec![0.0f32; n * n];
        for r in 0..n {
            for c in 0..=r {
                let v = (((r * 131 + c * 17 + 7) % 1000) as f32) * 0.001 - 0.5;
                a[r * n + c] = v;
                a[c * n + r] = v;
            }
        }
        let meta = TensorMeta::from_shape(vec![n, n], DType::F32, Device::Cpu);
        let res = super::eigh_contiguous_f32(&a, &meta).unwrap();
        let mut max_recon = 0.0f32;
        for i in 0..n {
            for j in 0..n {
                let mut val = 0.0f32;
                for k in 0..n {
                    val += res.eigenvectors[i * n + k]
                        * res.eigenvalues[k]
                        * res.eigenvectors[j * n + k];
                }
                max_recon = max_recon.max((val - a[i * n + j]).abs());
            }
        }
        assert!(
            max_recon < 1e-3,
            "f32 eigh reconstruction error {max_recon:e}"
        );
    }

