    #[test]
    fn cholesky_blocked_matches_serial_and_reconstructs() {
        // n = 768 > NB exercises the blocked panel/TRSM/SYRK path. The blocked
        // right-looking algorithm REASSOCIATES the trailing sums (panel-by-panel
        // through GEMM) vs the serial left-looking long dot, so it matches the
        // serial reference only to TOLERANCE — assert that, plus the strict
        // proof obligation that L is lower-triangular and reconstructs A.
        let n = 768usize;
        // Cheap symmetric, strictly diagonally dominant (hence SPD) matrix.
        let mut a = vec![0.0f64; n * n];
        for i in 0..n {
            for j in 0..i {
                let v = (((i * 131 + j * 17) % 19) as f64 - 9.0) * 0.01;
                a[i * n + j] = v;
                a[j * n + i] = v;
            }
            a[i * n + i] = n as f64;
        }

        // Serial left-looking reference factor.
        let mut l_ref = vec![0.0f64; n * n];
        for j in 0..n {
            let mut sum_sq = 0.0;
            for k in 0..j {
                sum_sq += l_ref[j * n + k] * l_ref[j * n + k];
            }
            let l_jj = (a[j * n + j] - sum_sq).sqrt();
            l_ref[j * n + j] = l_jj;
            for i in (j + 1)..n {
                let mut dot = 0.0;
                for k in 0..j {
                    dot += l_ref[i * n + k] * l_ref[j * n + k];
                }
                l_ref[i * n + j] = (a[i * n + j] - dot) / l_jj;
            }
        }

        let meta = TensorMeta::from_shape(vec![n, n], DType::F64, Device::Cpu);
        let got = super::cholesky_contiguous_f64(&a, &meta, false).expect("cholesky");
        assert_eq!(got.factor.len(), n * n);
        for i in 0..n {
            for j in 0..n {
                let v = got.factor[i * n + j];
                if j > i {
                    // strictly upper triangle must be exactly zero
                    assert_eq!(v, 0.0, "factor not lower-triangular at ({i},{j})");
                } else {
                    let rel = (v - l_ref[i * n + j]).abs() / (l_ref[i * n + j].abs() + 1.0);
                    assert!(
                        rel < 1e-9,
                        "blocked factor[{i},{j}]={v} vs serial {} (rel {rel:e})",
                        l_ref[i * n + j]
                    );
                }
            }
        }
        // Reconstruction L·L^T ≈ A on a sample of entries (full check is O(n^3)).
        for &(i, j) in &[(0usize, 0usize), (5, 2), (700, 699), (767, 0), (400, 400)] {
            let mut dot = 0.0;
            for k in 0..=j.min(i) {
                dot += got.factor[i * n + k] * got.factor[j * n + k];
            }
            assert!(
                (dot - a[i * n + j]).abs() < 1e-7,
                "(L·L^T)[{i},{j}]={dot} expected {}",
                a[i * n + j]
            );
        }
    }

    #[test]
    fn cholesky_f32_blocked_reconstructs_and_lower_triangular() {
        // Native f32 blocked Cholesky (frankentorch-b3o90): n=384 > NB exercises
        // the panel/TRSM/SYRK path. Proof obligations: lower-triangular and
        // L·L^T ≈ A at f32 tolerance (the f32 SYRK reassociates, like the f64).
        let n = 384usize;
        let mut a = vec![0.0f32; n * n];
        for i in 0..n {
            for j in 0..i {
                let v = (((i * 131 + j * 17) % 19) as f32 - 9.0) * 0.01;
                a[i * n + j] = v;
                a[j * n + i] = v;
            }
            a[i * n + i] = n as f32;
        }
        let meta = TensorMeta::from_shape(vec![n, n], DType::F32, Device::Cpu);
        let l = super::cholesky_contiguous_f32(&a, &meta, false).expect("cholesky f32");
        assert_eq!(l.len(), n * n);
        for i in 0..n {
            for j in (i + 1)..n {
                assert_eq!(
                    l[i * n + j],
                    0.0,
                    "factor not lower-triangular at ({i},{j})"
                );
            }
        }
        // Reconstruction on a sample. f32 SPD with diagonal n gives entries ~O(n);
        // tolerance scales with sqrt(n)*eps_f32*magnitude.
        for &(i, j) in &[(0usize, 0usize), (5, 2), (300, 299), (383, 0), (200, 200)] {
            let mut dot = 0.0f32;
            for k in 0..=j.min(i) {
                dot += l[i * n + k] * l[j * n + k];
            }
            let tol = 1e-3 * (a[i * n + j].abs() + 1.0);
            assert!(
                (dot - a[i * n + j]).abs() < tol,
                "(L·L^T)[{i},{j}]={dot} expected {} (tol {tol})",
                a[i * n + j]
            );
        }
    }

    #[test]
    fn cholesky_solve_f32_solves_spd_system() {
        // Native f32 Cholesky solve (b3o90): factor an SPD A in f32, solve A X = I,
        // and verify A·X ≈ I at f32 tolerance (X = A^-1).
        let n = 96usize;
        // A = B^T B + n*I (well-conditioned SPD), in f32.
        let mut b = vec![0.0f32; n * n];
        for i in 0..n {
            for j in 0..n {
                b[i * n + j] = ((i * 31 + j * 17) % 97) as f32 * 0.013 - 0.5;
            }
        }
        let mut a = vec![0.0f32; n * n];
        for i in 0..n {
            for j in 0..n {
                let mut s = 0.0f32;
                for k in 0..n {
                    s += b[k * n + i] * b[k * n + j];
                }
                a[i * n + j] = s;
            }
            a[i * n + i] += n as f32;
        }
        let meta = TensorMeta::from_shape(vec![n, n], DType::F32, Device::Cpu);
        let factor = super::cholesky_contiguous_f32(&a, &meta, false).expect("chol f32");
        let mut id = vec![0.0f32; n * n];
        for i in 0..n {
            id[i * n + i] = 1.0;
        }
        let x = super::cholesky_solve_contiguous_f32(&factor, n, &id, &meta, false).expect("solve");
        // A·X should reconstruct I.
        for &(i, j) in &[(0usize, 0usize), (10, 10), (3, 50), (95, 95), (40, 7)] {
            let mut dot = 0.0f32;
            for k in 0..n {
                dot += a[i * n + k] * x[k * n + j];
            }
            let want = if i == j { 1.0 } else { 0.0 };
            assert!(
                (dot - want).abs() < 1e-3,
                "(A·A^-1)[{i},{j}]={dot} expected {want}"
            );
        }
    }

    #[test]
    fn lu_solve_f32_inverts_general_matrix() {
        // Native f32 LU solve (b3o90): factor a general well-conditioned A in f64,
        // convert the factor to f32, solve A X = I in f32, verify A·X ≈ I at f32 tol.
        let n = 96usize;
        let mut a = vec![0.0f32; n * n];
        for i in 0..n {
            for j in 0..n {
                a[i * n + j] = ((i * 31 + j * 17) % 97) as f32 * 0.013 - 0.5;
            }
            a[i * n + i] += n as f32;
        }
        let a64: Vec<f64> = a.iter().map(|&v| v as f64).collect();
        let meta = TensorMeta::from_shape(vec![n, n], DType::F64, Device::Cpu);
        let factor = super::lu_factor_contiguous_f64(&a64, &meta).expect("lu");
        let lu32: Vec<f32> = factor.lu.iter().map(|&v| v as f32).collect();
        let mut id = vec![0.0f32; n * n];
        for i in 0..n {
            id[i * n + i] = 1.0;
        }
        let meta32 = TensorMeta::from_shape(vec![n, n], DType::F32, Device::Cpu);
        let x = super::lu_solve_contiguous_f32(&lu32, &factor.pivots, n, &id, &meta32)
            .expect("lu solve f32");
        for &(i, j) in &[(0usize, 0usize), (10, 10), (3, 50), (95, 95), (40, 7)] {
            let mut dot = 0.0f32;
            for k in 0..n {
                dot += a[i * n + k] * x[k * n + j];
            }
            let want = if i == j { 1.0 } else { 0.0 };
            assert!(
                (dot - want).abs() < 2e-3,
                "(A·A^-1)[{i},{j}]={dot} expected {want}"
            );
        }
    }

    #[test]
    fn winograd_conv2d_matches_direct_within_tolerance() {
        // Isomorphism proof for the Winograd F(2,3) path: it must match a direct
        // 3x3 stride-1 convolution to tolerance (it reassociates, not bit-exact).
        // Use odd out dims (7) to exercise the edge-tile trimming.
        let (batch, in_ch, out_ch) = (2usize, 3usize, 4usize);
        let (padded_h, padded_w) = (9usize, 9usize); // out = 7x7
        let out_h = padded_h - 2;
        let out_w = padded_w - 2;
        let input: Vec<f64> = (0..batch * in_ch * padded_h * padded_w)
            .map(|i| (((i * 2654435761usize) % 211) as f64 - 105.0) * 0.013)
            .collect();
        let weight: Vec<f64> = (0..out_ch * in_ch * 9)
            .map(|i| (((i * 40503usize) % 97) as f64 - 48.0) * 0.021)
            .collect();

        let got = super::winograd_conv2d_3x3_s1_f64(
            &input, &weight, batch, in_ch, out_ch, padded_h, padded_w,
        );

        // Direct reference.
        let mut want = vec![0.0f64; batch * out_ch * out_h * out_w];
        for b in 0..batch {
            for oc in 0..out_ch {
                for oh in 0..out_h {
                    for ow in 0..out_w {
                        let mut acc = 0.0;
                        for ic in 0..in_ch {
                            let ibase = (b * in_ch + ic) * padded_h * padded_w;
                            let wbase = (oc * in_ch + ic) * 9;
                            for kh in 0..3 {
                                for kw in 0..3 {
                                    acc += input[ibase + (oh + kh) * padded_w + (ow + kw)]
                                        * weight[wbase + kh * 3 + kw];
                                }
                            }
                        }
                        want[((b * out_ch + oc) * out_h + oh) * out_w + ow] = acc;
                    }
                }
            }
        }
        assert_eq!(got.len(), want.len());
        for (idx, (&g, &w)) in got.iter().zip(want.iter()).enumerate() {
            assert!(
                (g - w).abs() < 1e-9,
                "winograd[{idx}]={g} vs direct {w} (diff {:e})",
                (g - w).abs()
            );
        }
    }

    #[test]
    fn winograd_conv2d_f32_matches_direct_within_tolerance() {
        // Isomorphism proof for the f32 Winograd F(2,3) path: matches a direct
        // 3x3 stride-1 conv to f32 tolerance (it reassociates, not bit-exact).
        let (batch, in_ch, out_ch) = (2usize, 3usize, 4usize);
        let (padded_h, padded_w) = (9usize, 9usize); // out = 7x7
        let out_h = padded_h - 2;
        let out_w = padded_w - 2;
        let input: Vec<f32> = (0..batch * in_ch * padded_h * padded_w)
            .map(|i| (((i * 2654435761usize) % 211) as f32 - 105.0) * 0.013)
            .collect();
        let weight: Vec<f32> = (0..out_ch * in_ch * 9)
            .map(|i| (((i * 40503usize) % 97) as f32 - 48.0) * 0.021)
            .collect();

        let got = super::winograd_conv2d_3x3_s1_f32(
            &input, &weight, batch, in_ch, out_ch, padded_h, padded_w,
        );

        let mut want = vec![0.0f32; batch * out_ch * out_h * out_w];
        for b in 0..batch {
            for oc in 0..out_ch {
                for oh in 0..out_h {
                    for ow in 0..out_w {
                        let mut acc = 0.0f32;
                        for ic in 0..in_ch {
                            let ibase = (b * in_ch + ic) * padded_h * padded_w;
                            let wbase = (oc * in_ch + ic) * 9;
                            for kh in 0..3 {
                                for kw in 0..3 {
                                    acc += input[ibase + (oh + kh) * padded_w + (ow + kw)]
                                        * weight[wbase + kh * 3 + kw];
                                }
                            }
                        }
                        want[((b * out_ch + oc) * out_h + oh) * out_w + ow] = acc;
                    }
                }
            }
        }
        assert_eq!(got.len(), want.len());
        for (idx, (&g, &w)) in got.iter().zip(want.iter()).enumerate() {
            let tol = 1e-4 + 1e-4 * w.abs();
            assert!(
                (g - w).abs() < tol,
                "winograd_f32[{idx}]={g} vs direct {w} (diff {:e})",
                (g - w).abs()
            );
        }
    }

