    #[test]
    fn group_norm_f64_unit_dy_matches_general_reference_bits() {
        let (batch, num_groups, cpg, spatial) = (3usize, 2usize, 3usize, 5usize);
        let eps = 1e-5;
        let group_numel = cpg * spatial;
        let channels = num_groups * cpg;
        let x: Vec<f64> = (0..batch * channels * spatial)
            .map(|i| ((i % 41) as f64 - 20.0) * 0.02734375 + (i as f64) * 0.00019)
            .collect();
        let dy = vec![1.0f64; x.len()];
        let weight: Vec<f64> = (0..channels)
            .map(|c| 0.65 + (c % 7) as f64 * 0.046875)
            .collect();
        let inv_m = 1.0 / group_numel as f64;

        let mut ref_dx = vec![0.0f64; x.len()];
        for grp in 0..batch * num_groups {
            let g = grp % num_groups;
            let base = grp * group_numel;
            let xb = &x[base..base + group_numel];
            let dyb = &dy[base..base + group_numel];
            let dxrow = &mut ref_dx[base..base + group_numel];
            let mut sum = 0.0f64;
            for &v in xb {
                sum += v;
            }
            let mean = sum * inv_m;
            let mut vsum = 0.0f64;
            for &v in xb {
                let d = v - mean;
                vsum += d * d;
            }
            let rstd = 1.0 / (vsum * inv_m + eps).sqrt();
            let mut c1 = 0.0f64;
            let mut c2 = 0.0f64;
            for i in 0..group_numel {
                let c = g * cpg + i / spatial;
                let xhat = (xb[i] - mean) * rstd;
                let dxhat = dyb[i] * weight[c];
                c1 += dxhat;
                c2 += dxhat * xhat;
            }
            for i in 0..group_numel {
                let c = g * cpg + i / spatial;
                let xhat = (xb[i] - mean) * rstd;
                let dxhat = dyb[i] * weight[c];
                dxrow[i] = rstd * (dxhat - (c1 + xhat * c2) * inv_m);
            }
        }

        let mut ref_dw = vec![0.0f64; channels];
        let mut ref_db = vec![0.0f64; channels];
        for grp in 0..batch * num_groups {
            let g = grp % num_groups;
            let base = grp * group_numel;
            let xb = &x[base..base + group_numel];
            let dyb = &dy[base..base + group_numel];
            let mut sum = 0.0f64;
            for &v in xb {
                sum += v;
            }
            let mean = sum * inv_m;
            let mut vsum = 0.0f64;
            for &v in xb {
                let d = v - mean;
                vsum += d * d;
            }
            let rstd = 1.0 / (vsum * inv_m + eps).sqrt();
            for i in 0..group_numel {
                let c = g * cpg + i / spatial;
                ref_dw[c] += dyb[i] * (xb[i] - mean) * rstd;
                ref_db[c] += dyb[i];
            }
        }

        let (dx, dw, db) = crate::group_norm_backward_f64(
            &dy,
            &x,
            Some(&weight),
            batch,
            num_groups,
            cpg,
            spatial,
            eps,
        );
        let dw = dw.expect("weight gradient");
        let db = db.expect("bias gradient");
        for (got, expected) in dx.iter().zip(ref_dx.iter()) {
            assert_eq!(got.to_bits(), expected.to_bits(), "dx mismatch");
        }
        for (got, expected) in dw.iter().zip(ref_dw.iter()) {
            assert_eq!(got.to_bits(), expected.to_bits(), "dweight mismatch");
        }
        for (got, expected) in db.iter().zip(ref_db.iter()) {
            assert_eq!(got.to_bits(), expected.to_bits(), "dbias mismatch");
        }

        let mut digest = 0xcbf29ce484222325u64;
        for values in [&dx[..], &dw[..], &db[..]] {
            for value in values {
                digest ^= value.to_bits();
                digest = digest.wrapping_mul(0x100000001b3);
            }
        }
        assert_eq!(digest, 0x533d76b2bc4e86e3);
    }

